CREATE OR REPLACE FUNCTION public.platform_acknowledge_agm_reward(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context jsonb := public.platform_agm_resolve_context(p_params);
  v_schema_name text;
  v_actor_user_id uuid := coalesce(public.platform_try_uuid(p_params->>'actor_user_id'), public.platform_try_uuid(v_context->'details'->>'actor_user_id'));
  v_reward_kind text := lower(nullif(btrim(coalesce(p_params->>'reward_kind', '')), ''));
  v_reward_id uuid := coalesce(public.platform_try_uuid(p_params->>'reward_id'), public.platform_try_uuid(p_params->>'award_id'), public.platform_try_uuid(p_params->>'recognition_event_id'));
  v_employee_id uuid := public.platform_try_uuid(p_params->>'employee_id');
  v_result record;
begin
  if coalesce((v_context->>'success')::boolean, false) is not true then return v_context; end if;
  v_schema_name := v_context->'details'->>'tenant_schema';
  if v_employee_id is null then
    v_employee_id := public.platform_agm_resolve_actor_employee_id(v_schema_name, v_actor_user_id);
  end if;
  if v_reward_kind not in ('badge', 'recognition') or v_reward_id is null then
    return public.platform_json_response(false,'INVALID_INPUT','reward_kind and reward_id are required.',jsonb_build_object('reward_kind', v_reward_kind));
  end if;

  if v_reward_kind = 'badge' then
    execute format(
      'update %I.agm_badge_award
       set acknowledged_at = timezone(''utc'', now()),
           updated_at = timezone(''utc'', now())
       where award_id = $1
         and ($2 is null or employee_id = $2)
       returning award_id as reward_id, employee_id',
      v_schema_name
    ) into v_result
    using v_reward_id, v_employee_id;
  else
    execute format(
      'update %I.agm_recognition_event
       set acknowledged_at = timezone(''utc'', now()),
           updated_at = timezone(''utc'', now())
       where recognition_event_id = $1
         and ($2 is null or recipient_employee_id = $2)
       returning recognition_event_id as reward_id, recipient_employee_id as employee_id',
      v_schema_name
    ) into v_result
    using v_reward_id, v_employee_id;
  end if;

  if v_result.reward_id is null then
    return public.platform_json_response(false,'REWARD_NOT_FOUND','The requested reward could not be acknowledged.',jsonb_build_object('reward_kind', v_reward_kind, 'reward_id', v_reward_id));
  end if;

  perform public.platform_agm_write_audit_log(v_schema_name, 'agm.reward.acknowledged', jsonb_build_object('reward_kind', v_reward_kind, 'reward_id', v_result.reward_id), v_actor_user_id, null, v_result.employee_id);

  return public.platform_json_response(true,'OK','AGM reward acknowledged.',jsonb_build_object('reward_kind', v_reward_kind,'reward_id', v_result.reward_id,'employee_id', v_result.employee_id));
exception when others then
  return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_acknowledge_agm_reward.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_admin_edit_ams_attendance(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context_result jsonb;
  v_schema_name text;
  v_actor_user_id uuid := coalesce(public.platform_try_uuid(p_params->>'actor_user_id'), public.platform_current_actor_user_id());
  v_record record;
  v_attendance_record_id uuid := public.platform_try_uuid(p_params->>'attendance_record_id');
  v_reason text := nullif(btrim(coalesce(p_params->>'manual_edit_reason', '')), '');
begin
  v_context_result := public.platform_ams_resolve_context(p_params);
  if coalesce((v_context_result->>'success')::boolean, false) is not true then return v_context_result; end if;
  v_schema_name := nullif(coalesce(v_context_result->'details'->>'tenant_schema', ''), '');

  if v_attendance_record_id is null then
    return public.platform_json_response(false,'ATTENDANCE_RECORD_ID_REQUIRED','attendance_record_id is required.','{}'::jsonb);
  end if;

  if v_reason is null then
    return public.platform_json_response(false,'MANUAL_EDIT_REASON_REQUIRED','manual_edit_reason is required for admin attendance edits.','{}'::jsonb);
  end if;

  execute format('select * from %I.ams_attendance_record where attendance_record_id = $1', v_schema_name)
  into v_record
  using v_attendance_record_id;

  if v_record.attendance_record_id is null then
    return public.platform_json_response(false,'ATTENDANCE_RECORD_NOT_FOUND','Attendance record not found.',jsonb_build_object('attendance_record_id', v_attendance_record_id));
  end if;

  execute format(
    'update %I.ams_attendance_record set clock_in_time = coalesce($2, clock_in_time), clock_out_time = coalesce($3, clock_out_time), mood_score = coalesce($4, mood_score), is_manually_edited = true, manual_edit_reason = $5, clock_in_source = case when $2 is null then clock_in_source else ''ADMIN_MANUAL_ENTRY'' end, clock_out_source = case when $3 is null then clock_out_source else ''ADMIN_MANUAL_ENTRY'' end, updated_at = timezone(''utc'', now()) where attendance_record_id = $1',
    v_schema_name
  )
  using v_attendance_record_id, public.platform_ams_try_timestamptz(p_params->>'clock_in_time'), public.platform_ams_try_timestamptz(p_params->>'clock_out_time'), public.platform_ams_try_bigint(p_params->>'mood_score'), v_reason;

  perform public.platform_ams_recalculate_attendance_record(v_schema_name, v_attendance_record_id);
  perform public.platform_ams_log_audit_event(v_schema_name,'ATTENDANCE_ADMIN_EDITED','AMS_CORE',jsonb_build_object('manual_edit_reason', v_reason),v_record.employee_id,v_attendance_record_id,null,v_actor_user_id);

  return public.platform_json_response(true,'OK','AMS attendance record edited by administrator.',jsonb_build_object('attendance_record_id', v_attendance_record_id));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_agm_admin_observability_overview_rows()
 RETURNS TABLE(active_rule_set_count bigint, badge_catalog_count bigint, active_badge_award_count bigint, active_recognition_count bigint, participant_count bigint, latest_snapshot_date date, queued_refresh_count bigint, running_refresh_count bigint)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context jsonb := public.platform_agm_resolve_context('{}'::jsonb);
