CREATE OR REPLACE FUNCTION public.platform_agm_compute_attendance_score(p_scoring_rules jsonb, p_status_final text, p_late_minutes integer, p_overtime_minutes integer, p_clock_in_within_geofence boolean, p_clock_out_within_geofence boolean, p_mood_score smallint)
 RETURNS numeric
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_status text := upper(coalesce(nullif(btrim(p_status_final), ''), 'UNKNOWN'));
  v_base_present_bonus numeric := coalesce((p_scoring_rules->>'base_present_bonus')::numeric, 5);
  v_punctuality_bonus numeric := coalesce((p_scoring_rules->>'punctuality_bonus')::numeric, 2);
  v_late_penalty numeric := coalesce((p_scoring_rules->>'late_penalty_per_minute')::numeric, 0.10);
  v_overtime_bonus numeric := coalesce((p_scoring_rules->>'overtime_bonus_per_minute')::numeric, 0.10);
  v_geofence_bonus numeric := coalesce((p_scoring_rules->>'perfect_geofence_bonus')::numeric, 1);
  v_positive_mood_bonus numeric := coalesce((p_scoring_rules->>'positive_mood_bonus')::numeric, 1);
  v_positive_mood_threshold integer := coalesce((p_scoring_rules->>'positive_mood_threshold')::integer, 4);
  v_total numeric := 0;
begin
  if v_status in ('ABSENT', 'ON_LEAVE', 'HOLIDAY', 'WEEKEND_OFF') then
    return 0;
  end if;

  if v_status in ('PRESENT', 'LATE_IN', 'EARLY_OUT', 'MISSED_PUNCH_OUT', 'HALF_DAY_PRESENT', 'HOLIDAY_WORKED', 'ON_DUTY') then
    v_total := v_total + v_base_present_bonus;
  end if;

  if coalesce(p_late_minutes, 0) = 0 then
    v_total := v_total + v_punctuality_bonus;
  else
    v_total := v_total - (greatest(coalesce(p_late_minutes, 0), 0) * v_late_penalty);
  end if;

  if coalesce(p_overtime_minutes, 0) > 0 then
    v_total := v_total + (p_overtime_minutes * v_overtime_bonus);
  end if;

  if coalesce(p_clock_in_within_geofence, false) and coalesce(p_clock_out_within_geofence, false) then
    v_total := v_total + v_geofence_bonus;
  end if;

  if coalesce(p_mood_score, 0) >= v_positive_mood_threshold then
    v_total := v_total + v_positive_mood_bonus;
  end if;

  return round(v_total, 2);
end;
$function$
;

