CREATE OR REPLACE FUNCTION public.platform_agm_resolve_actor_employee_id(p_schema_name text, p_actor_user_id uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_employee_id uuid;
begin
  if p_actor_user_id is null or nullif(btrim(coalesce(p_schema_name, '')), '') is null then
