;

CREATE OR REPLACE FUNCTION public.platform_agm_resolve_context(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_params jsonb := coalesce(p_params, '{}'::jsonb);
  v_requested_tenant_id uuid := public.platform_resolve_tenant_id(v_params);
  v_current_tenant_id uuid := public.platform_current_tenant_id();
  v_current_schema text := public.platform_current_tenant_schema();
  v_context_result jsonb;
  v_details jsonb;
begin
  if v_current_tenant_id is not null and v_current_schema is not null then
    if v_requested_tenant_id is not null and v_requested_tenant_id <> v_current_tenant_id then
      return public.platform_json_response(false,'CONTEXT_TENANT_MISMATCH','The requested tenant does not match the current execution context.',jsonb_build_object('requested_tenant_id', v_requested_tenant_id,'current_tenant_id', v_current_tenant_id));
    end if;

    if not public.platform_table_exists(v_current_schema, 'wcm_employee')
      or not public.platform_table_exists(v_current_schema, 'ams_attendance_record')
      or not public.platform_table_exists(v_current_schema, 'agm_rule_set')
      or not public.platform_table_exists(v_current_schema, 'agm_badge_catalog')
      or not public.platform_table_exists(v_current_schema, 'agm_score_event')
      or not public.platform_table_exists(v_current_schema, 'agm_badge_award')
      or not public.platform_table_exists(v_current_schema, 'agm_recognition_event')
      or not public.platform_table_exists(v_current_schema, 'agm_user_preference')
      or not public.platform_table_exists(v_current_schema, 'agm_user_score_summary')
      or not public.platform_table_exists(v_current_schema, 'agm_leaderboard_snapshot')
      or not public.platform_table_exists(v_current_schema, 'agm_audit_log')
    then
      return public.platform_json_response(false,'AGM_TEMPLATE_NOT_APPLIED','AGM is not applied to the current tenant schema.',jsonb_build_object('tenant_id', v_current_tenant_id,'tenant_schema', v_current_schema));
    end if;

    return public.platform_json_response(true,'OK','AGM execution context resolved.',jsonb_build_object('tenant_id', v_current_tenant_id,'tenant_schema', v_current_schema,'actor_user_id', public.platform_current_actor_user_id()));
  end if;

  if not public.platform_is_internal_caller() then
    return public.platform_json_response(false,'TENANT_CONTEXT_REQUIRED','An applied tenant execution context is required.','{}'::jsonb);
  end if;

  if v_requested_tenant_id is null then
    return public.platform_json_response(false,'TENANT_ID_REQUIRED','tenant_id or tenant_code is required when no execution context is active.','{}'::jsonb);
  end if;

  v_context_result := public.platform_apply_execution_context(jsonb_build_object(
    'execution_mode', 'internal_platform',
    'tenant_id', v_requested_tenant_id,
    'source', coalesce(nullif(btrim(v_params->>'source'), ''), 'platform_agm_resolve_context')
  ));
  if coalesce((v_context_result->>'success')::boolean, false) is not true then
    return v_context_result;
  end if;

  v_details := coalesce(v_context_result->'details', '{}'::jsonb);
  if not public.platform_table_exists(v_details->>'tenant_schema', 'agm_rule_set') then
    return public.platform_json_response(false,'AGM_TEMPLATE_NOT_APPLIED','AGM is not applied to the requested tenant schema.',jsonb_build_object('tenant_id', public.platform_try_uuid(v_details->>'tenant_id'),'tenant_schema', v_details->>'tenant_schema'));
  end if;

  return public.platform_json_response(true,'OK','AGM execution context resolved.',jsonb_build_object('tenant_id', public.platform_try_uuid(v_details->>'tenant_id'),'tenant_schema', v_details->>'tenant_schema','actor_user_id', public.platform_current_actor_user_id()));
exception when others then
  return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_agm_resolve_context.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_agm_tenant_leaderboard_rows()
 RETURNS TABLE(scope_code text, scope_key text, window_code text, snapshot_date date, rank_position integer, employee_id uuid, total_score numeric, badge_count integer, rank_payload jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context jsonb := public.platform_agm_resolve_context('{}'::jsonb);
  v_schema_name text;
begin
  if coalesce((v_context->>'success')::boolean, false) is not true then return; end if;
  v_schema_name := v_context->'details'->>'tenant_schema';

  return query execute format(
    'with latest as (
       select distinct on (scope_code, scope_key, window_code)
         scope_code,
         scope_key,
         window_code,
         snapshot_date,
         ranks_payload
       from %I.agm_leaderboard_snapshot
       order by scope_code, scope_key, window_code, snapshot_date desc, generated_at desc
     )
     select l.scope_code,
            l.scope_key,
            l.window_code,
            l.snapshot_date,
            elem.ordinality::integer,
            public.platform_try_uuid(elem.value->>''employee_id''),
            coalesce((elem.value->>''total_score'')::numeric, 0),
            coalesce((elem.value->>''badge_count'')::integer, 0),
            elem.value
     from latest l
     cross join lateral jsonb_array_elements(l.ranks_payload) with ordinality as elem(value, ordinality)
     order by l.snapshot_date desc, l.window_code, elem.ordinality',
    v_schema_name
  );
end;
$function$
;

