 RETURNS date
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
begin
  if nullif(btrim(coalesce(p_value, '')), '') is null then
    return null;
  end if;
  return p_value::date;
exception when others then
  return null;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_agm_window_bounds(p_anchor_date date, p_window_code text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_anchor date := coalesce(p_anchor_date, current_date);
  v_code text := lower(coalesce(nullif(btrim(p_window_code), ''), 'monthly'));
  v_start date;
  v_end date;
begin
  if v_code = 'daily' then
    v_start := v_anchor;
    v_end := v_anchor;
  elsif v_code = 'weekly' then
    v_start := date_trunc('week', v_anchor::timestamp)::date;
    v_end := (date_trunc('week', v_anchor::timestamp)::date + 6);
  else
    v_code := 'monthly';
    v_start := date_trunc('month', v_anchor::timestamp)::date;
    v_end := ((date_trunc('month', v_anchor::timestamp) + interval '1 month - 1 day'))::date;
  end if;

  return jsonb_build_object(
    'window_code', v_code,
    'window_start', v_start,
    'window_end', v_end,
    'snapshot_date', v_end
  );
end;
$function$
;

