 RETURNS TABLE(tenant_id uuid, attendance_record_id uuid, employee_id uuid, employee_code text, employee_name text, employee_actor_user_id uuid, attendance_date date, shift_id bigint, shift_code text, shift_name text, scheduled_clock_in timestamp with time zone, scheduled_clock_out timestamp with time zone, clock_in_time timestamp with time zone, clock_out_time timestamp with time zone, duration_minutes integer, overtime_minutes integer, late_minutes integer, early_leaving_minutes integer, status_raw text, status_final text, on_leave_request_id uuid, leave_session_scope text, leave_fraction numeric, is_holiday boolean, holiday_name text, regularization_request_id uuid, is_manually_edited boolean, manual_edit_reason text, mood_score smallint, created_at timestamp with time zone, updated_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context_result jsonb;
  v_schema_name text;
  v_tenant_id uuid;
begin
  v_context_result := public.platform_ams_resolve_context('{}'::jsonb);
  if coalesce((v_context_result->>'success')::boolean, false) is not true then return; end if;
