  v_tenant_id := public.platform_try_uuid(v_context_result->'details'->>'tenant_id');

  return query execute format(
    'select $1::uuid, r.attendance_record_id, r.employee_id, e.employee_code, trim(concat_ws('' '', e.first_name, e.last_name)), e.actor_user_id, r.attendance_date, r.shift_id, s.shift_code, s.shift_name, r.scheduled_clock_in, r.scheduled_clock_out, r.clock_in_time, r.clock_out_time, r.duration_minutes, r.overtime_minutes, r.late_minutes, r.early_leaving_minutes, r.status_raw, r.status_final, r.on_leave_request_id, r.leave_session_scope, r.leave_fraction, r.is_holiday, r.holiday_name, r.regularization_request_id, r.is_manually_edited, r.manual_edit_reason, r.mood_score, r.created_at, r.updated_at from %I.ams_attendance_record r join %I.wcm_employee e on e.employee_id = r.employee_id left join %I.ams_shift s on s.shift_id = r.shift_id order by r.attendance_date desc, r.employee_id asc',
    v_schema_name,
    v_schema_name,
    v_schema_name
  ) using v_tenant_id;
