CREATE OR REPLACE FUNCTION public.platform_ams_bio_active_employee_anchor_exists(p_schema_name text, p_employee_id uuid, p_attendance_date date DEFAULT CURRENT_DATE)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_exists boolean;
begin
  execute format(
    'select exists (
       select 1
       from %I.wcm_employee_service_state s
       where s.employee_id = $1
         and s.service_state in (''pending_join'', ''active'')
         and coalesce(s.joining_date, $2) <= $2
         and (s.leaving_date is null or s.leaving_date >= $2)
     )',
    p_schema_name
  ) into v_exists using p_employee_id, p_attendance_date;

  return coalesce(v_exists, false);
end;
$function$
;

