CREATE OR REPLACE FUNCTION public.platform_ams_bio_extract_canonical_value(p_raw_row jsonb, p_source_field_name text, p_transform_strategy text, p_transform_config jsonb DEFAULT '{}'::jsonb, p_default_value jsonb DEFAULT NULL::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_value jsonb;
  v_lookup_key text;
begin
  if p_transform_strategy = 'default' then
    return coalesce(p_default_value, 'null'::jsonb);
  end if;

  v_value := coalesce(p_raw_row -> p_source_field_name, to_jsonb(p_raw_row ->> p_source_field_name));

  if p_transform_strategy = 'trim' then
    return case when v_value is null or v_value = 'null'::jsonb then 'null'::jsonb else to_jsonb(btrim(v_value #>> '{}')) end;
  elsif p_transform_strategy = 'case_normalize' then
    return case when v_value is null or v_value = 'null'::jsonb then 'null'::jsonb else to_jsonb(lower(btrim(v_value #>> '{}'))) end;
  elsif p_transform_strategy = 'parse_timestamp' then
    return to_jsonb(public.platform_ams_bio_try_timestamptz(v_value #>> '{}', p_transform_config));
  elsif p_transform_strategy = 'map_direction' then
    return to_jsonb(public.platform_ams_bio_map_direction(v_value #>> '{}'));
  elsif p_transform_strategy = 'lookup' then
    v_lookup_key := lower(btrim(coalesce(v_value #>> '{}', '')));
    return coalesce(p_transform_config -> 'map' -> v_lookup_key, p_default_value, 'null'::jsonb);
  end if;

  return coalesce(v_value, p_default_value, 'null'::jsonb);
end;
$function$
;

