CREATE OR REPLACE FUNCTION public.platform_ams_bio_map_direction(p_value text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_value text := lower(nullif(btrim(coalesce(p_value, '')), ''));
begin
  if v_value is null then
    return 'UNKNOWN';
  end if;

  if v_value in ('in', 'clock_in', 'clockin', 'checkin', 'punchin', 'entry') then
    return 'CLOCK_IN';
  end if;

  if v_value in ('out', 'clock_out', 'clockout', 'checkout', 'punchout', 'exit') then
    return 'CLOCK_OUT';
  end if;

  return 'UNKNOWN';
end;
$function$
;

