CREATE OR REPLACE FUNCTION public.platform_ams_bio_resolve_context(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_params jsonb := coalesce(p_params, '{}'::jsonb);
  v_requested_tenant_id uuid := public.platform_resolve_tenant_id(v_params);
  v_current_tenant_id uuid := public.platform_current_tenant_id();
  v_current_schema text := public.platform_current_tenant_schema();
  v_context_result jsonb;
  v_details jsonb;
begin
  if v_current_tenant_id is not null and v_current_schema is not null then
    if v_requested_tenant_id is not null and v_requested_tenant_id <> v_current_tenant_id then
      return public.platform_json_response(false,'CONTEXT_TENANT_MISMATCH','The requested tenant does not match the current execution context.',jsonb_build_object('requested_tenant_id', v_requested_tenant_id,'current_tenant_id', v_current_tenant_id));
    end if;

    if not public.platform_table_exists(v_current_schema, 'wcm_employee')
      or not public.platform_table_exists(v_current_schema, 'wcm_employee_service_state')
      or not public.platform_table_exists(v_current_schema, 'ams_attendance_record')
      or not public.platform_table_exists(v_current_schema, 'ams_punch_event')
      or not public.platform_table_exists(v_current_schema, 'lms_leave_request')
      or not public.platform_table_exists(v_current_schema, 'ams_bio_source_profile')
      or not public.platform_table_exists(v_current_schema, 'ams_bio_source_onboarding_state')
      or not public.platform_table_exists(v_current_schema, 'ams_bio_connector')
      or not public.platform_table_exists(v_current_schema, 'ams_bio_device')
      or not public.platform_table_exists(v_current_schema, 'ams_bio_employee_mapping')
      or not public.platform_table_exists(v_current_schema, 'ams_bio_field_mapping_profile')
      or not public.platform_table_exists(v_current_schema, 'ams_bio_field_mapping_rule')
      or not public.platform_table_exists(v_current_schema, 'ams_bio_import_session')
      or not public.platform_table_exists(v_current_schema, 'ams_bio_import_run')
      or not public.platform_table_exists(v_current_schema, 'ams_bio_import_staging_row')
      or not public.platform_table_exists(v_current_schema, 'ams_bio_import_validation_summary')
      or not public.platform_table_exists(v_current_schema, 'ams_bio_raw_punch_log')
      or not public.platform_table_exists(v_current_schema, 'ams_bio_normalized_punch')
      or not public.platform_table_exists(v_current_schema, 'ams_bio_publish_log')
      or not public.platform_table_exists(v_current_schema, 'ams_bio_reconciliation_case')
    then
      return public.platform_json_response(false,'AMS_BIO_TEMPLATE_NOT_APPLIED','AMS_BIO is not applied to the current tenant schema.',jsonb_build_object('tenant_id', v_current_tenant_id,'tenant_schema', v_current_schema));
    end if;

    return public.platform_json_response(true,'OK','AMS_BIO execution context resolved.',jsonb_build_object('tenant_id', v_current_tenant_id,'tenant_schema', v_current_schema,'actor_user_id', public.platform_current_actor_user_id()));
  end if;

  if not public.platform_is_internal_caller() then
    return public.platform_json_response(false,'TENANT_CONTEXT_REQUIRED','An applied tenant execution context is required.','{}'::jsonb);
  end if;

  if v_requested_tenant_id is null then
    return public.platform_json_response(false,'TENANT_ID_REQUIRED','tenant_id or tenant_code is required when no execution context is active.','{}'::jsonb);
  end if;

  v_context_result := public.platform_apply_execution_context(jsonb_build_object('execution_mode', 'internal_platform','tenant_id', v_requested_tenant_id,'source', coalesce(nullif(btrim(v_params->>'source'), ''), 'platform_ams_bio_resolve_context')));
  if coalesce((v_context_result->>'success')::boolean, false) is not true then
    return v_context_result;
  end if;

  v_details := coalesce(v_context_result->'details', '{}'::jsonb);
  if not public.platform_table_exists(v_details->>'tenant_schema', 'ams_bio_source_profile') then
    return public.platform_json_response(false,'AMS_BIO_TEMPLATE_NOT_APPLIED','AMS_BIO is not applied to the requested tenant schema.',jsonb_build_object('tenant_id', public.platform_try_uuid(v_details->>'tenant_id'),'tenant_schema', v_details->>'tenant_schema'));
  end if;

  return public.platform_json_response(true,'OK','AMS_BIO execution context resolved.',jsonb_build_object('tenant_id', public.platform_try_uuid(v_details->>'tenant_id'),'tenant_schema', v_details->>'tenant_schema','actor_user_id', public.platform_current_actor_user_id()));
exception when others then
  return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_ams_bio_resolve_context.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm));
end;
$function$
;

