CREATE OR REPLACE FUNCTION public.platform_ams_bio_try_timestamptz(p_value text, p_options jsonb DEFAULT '{}'::jsonb)
 RETURNS timestamp with time zone
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_value text := nullif(btrim(coalesce(p_value, '')), '');
  v_timezone text := nullif(btrim(coalesce(p_options->>'timezone', '')), '');
begin
  if v_value is null then
    return null;
  end if;

  begin
    return v_value::timestamptz;
  exception when others then
    null;
  end;

  begin
    if v_timezone is not null then
      return timezone(v_timezone, v_value::timestamp);
    end if;
  exception when others then
    null;
  end;

  begin
    return timezone('UTC', v_value::timestamp);
  exception when others then
    return null;
  end;
end;
$function$
;

