CREATE OR REPLACE FUNCTION public.platform_ams_geofence_match(p_schema_name text, p_latitude numeric, p_longitude numeric, p_allowed_geofences jsonb DEFAULT '[]'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_geofence record;
begin
  if p_latitude is null or p_longitude is null then
    return jsonb_build_object('within_geofence', null, 'geofence_name', null, 'error_code', null);
  end if;

  if public.platform_ams_has_postgis() is not true then
    return jsonb_build_object('within_geofence', null, 'geofence_name', null, 'error_code', 'POSTGIS_REQUIRED');
  end if;

  execute format(
    'select geofence_id, geofence_name from %I.ams_geofence where geofence_status = ''active'' and (coalesce(jsonb_array_length($3), 0) = 0 or $3 @> to_jsonb(geofence_id::text)) and extensions.ST_DWithin(extensions.ST_SetSRID(extensions.ST_MakePoint($1, $2), 4326)::extensions.geography, extensions.ST_SetSRID(extensions.ST_MakePoint(longitude, latitude), 4326)::extensions.geography, radius_meters) order by radius_meters asc limit 1',
    p_schema_name
  ) into v_geofence using p_longitude, p_latitude, coalesce(p_allowed_geofences, '[]'::jsonb);

  if v_geofence.geofence_name is null then
    return jsonb_build_object('within_geofence', false, 'geofence_name', null, 'error_code', null);
  end if;

  return jsonb_build_object('within_geofence', true, 'geofence_name', v_geofence.geofence_name, 'error_code', null);
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_ams_has_postgis()
 RETURNS boolean
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
  select exists (select 1 from pg_extension where extname = 'postgis');
$function$
;

CREATE OR REPLACE FUNCTION public.platform_ams_ip_allowed(p_allowed_ips jsonb, p_ip_address text)
 RETURNS boolean
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_value text;
begin
  if nullif(btrim(coalesce(p_ip_address, '')), '') is null then return null; end if;
  if p_allowed_ips is null or jsonb_typeof(p_allowed_ips) <> 'array' or jsonb_array_length(p_allowed_ips) = 0 then return true; end if;

  for v_value in select value from jsonb_array_elements_text(p_allowed_ips)
  loop
    begin
      if position('/' in v_value) > 0 then
        if inet(p_ip_address) <<= cidr(v_value) then return true; end if;
      elsif btrim(v_value) = p_ip_address then
        return true;
      end if;
    exception when others then
      null;
    end;
  end loop;

  return false;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_ams_leave_fraction(p_session_scope text)
 RETURNS numeric
 LANGUAGE sql
 IMMUTABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
  select case lower(coalesce(p_session_scope, ''))
    when 'first_half' then 0.5
    when 'second_half' then 0.5
    when 'full_day' then 1.0
    else null
  end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_ams_log_audit_event(p_schema_name text, p_event_type text, p_event_source text, p_event_details jsonb, p_employee_id uuid DEFAULT NULL::uuid, p_attendance_record_id uuid DEFAULT NULL::uuid, p_regularization_request_id uuid DEFAULT NULL::uuid, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
begin
  execute format(
    'insert into %I.ams_audit_event (employee_id, attendance_record_id, regularization_request_id, event_type, event_source, event_details, actor_user_id) values ($1,$2,$3,$4,$5,coalesce($6,''{}''::jsonb),$7)',
    p_schema_name
  )
  using p_employee_id, p_attendance_record_id, p_regularization_request_id, p_event_type, p_event_source, p_event_details, p_actor_user_id;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_ams_pending_approval_rows()
 RETURNS TABLE(tenant_id uuid, manager_actor_user_id uuid, manager_employee_id uuid, regularization_request_id uuid, attendance_record_id uuid, employee_id uuid, employee_code text, employee_name text, request_type text, request_status text, requested_clock_in timestamp with time zone, requested_clock_out timestamp with time zone, supporting_document_id uuid, created_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context_result jsonb;
  v_schema_name text;
  v_tenant_id uuid;
begin
  v_context_result := public.platform_ams_resolve_context('{}'::jsonb);
  if coalesce((v_context_result->>'success')::boolean, false) is not true then return; end if;
  v_schema_name := nullif(coalesce(v_context_result->'details'->>'tenant_schema', ''), '');
  v_tenant_id := public.platform_try_uuid(v_context_result->'details'->>'tenant_id');

  return query execute format(
    'select $1::uuid, s.manager_actor_user_id, s.manager_employee_id, rr.regularization_request_id, rr.attendance_record_id, rr.employee_id, e.employee_code, trim(concat_ws('' '', e.first_name, e.last_name)), rr.request_type, rr.request_status, rr.requested_clock_in, rr.requested_clock_out, rr.supporting_document_id, rr.created_at from %I.ams_regularization_request rr join %I.wcm_employee e on e.employee_id = rr.employee_id left join public.platform_rm_hierarchy_team_scope s on s.team_member_employee_id = rr.employee_id where rr.request_status = ''PENDING'' order by rr.created_at desc, rr.regularization_request_id desc',
    v_schema_name,
    v_schema_name
  ) using v_tenant_id;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_ams_recalculate_attendance_record(p_schema_name text, p_attendance_record_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_record record;
  v_schedule jsonb;
  v_leave jsonb;
  v_effective_clock_in timestamptz;
  v_effective_clock_out timestamptz;
  v_status_raw text;
  v_status_final text;
  v_regularization_status text;
  v_duration integer := 0;
  v_late integer := 0;
  v_early integer := 0;
  v_overtime integer := 0;
begin
  execute format('select * from %I.ams_attendance_record where attendance_record_id = $1', p_schema_name) into v_record using p_attendance_record_id;
  if v_record.attendance_record_id is null then return public.platform_json_response(false,'ATTENDANCE_RECORD_NOT_FOUND','Attendance record not found.','{}'::jsonb); end if;

  v_schedule := public.platform_ams_resolve_schedule_for_day(p_schema_name, v_record.employee_id, v_record.attendance_date);
  v_leave := public.platform_ams_resolve_leave_for_day(p_schema_name, v_record.employee_id, v_record.attendance_date);

  if v_record.regularization_request_id is not null then
    execute format('select request_status from %I.ams_regularization_request where regularization_request_id = $1', p_schema_name)
    into v_regularization_status
    using v_record.regularization_request_id;
  end if;

  v_effective_clock_in := v_record.clock_in_time;
  v_effective_clock_out := v_record.clock_out_time;

  if coalesce(v_leave->>'leave_session_scope', '') <> '' and v_effective_clock_in is null and v_effective_clock_out is null then
    v_status_raw := 'ON_LEAVE';
  elsif coalesce((v_schedule->>'holiday_name') is not null, false) and v_effective_clock_in is null and v_effective_clock_out is null then
    v_status_raw := 'HOLIDAY';
  elsif coalesce((v_schedule->>'is_work_day')::boolean, false) is false and v_effective_clock_in is null and v_effective_clock_out is null then
    v_status_raw := 'WEEKEND';
  elsif v_effective_clock_in is null and v_effective_clock_out is null then
    v_status_raw := 'ABSENT';
  elsif v_effective_clock_in is not null and v_effective_clock_out is null then
    v_status_raw := 'MISSED_PUNCH_OUT';
  else
    v_duration := greatest(0, floor(extract(epoch from (v_effective_clock_out - v_effective_clock_in)) / 60)::integer);
    if v_schedule->>'scheduled_clock_in' is not null and v_effective_clock_in > ((v_schedule->>'scheduled_clock_in')::timestamptz + make_interval(mins => coalesce((v_schedule->>'grace_period_late_minutes')::int, 0))) then
      v_late := greatest(0, floor(extract(epoch from (v_effective_clock_in - (v_schedule->>'scheduled_clock_in')::timestamptz)) / 60)::integer);
    end if;
    if v_schedule->>'scheduled_clock_out' is not null and v_effective_clock_out < ((v_schedule->>'scheduled_clock_out')::timestamptz - make_interval(mins => coalesce((v_schedule->>'grace_period_early_minutes')::int, 0))) then
      v_early := greatest(0, floor(extract(epoch from (((v_schedule->>'scheduled_clock_out')::timestamptz) - v_effective_clock_out)) / 60)::integer);
    end if;
    if v_schedule->>'scheduled_work_minutes' is not null and v_duration > (v_schedule->>'scheduled_work_minutes')::int then
      v_overtime := v_duration - (v_schedule->>'scheduled_work_minutes')::int;
    end if;
    if v_late > coalesce((v_schedule->>'late_mark_threshold_minutes')::int, 0) then
      v_status_raw := 'LATE_IN';
    elsif v_early > coalesce((v_schedule->>'early_leaving_threshold_minutes')::int, 0) then
      v_status_raw := 'EARLY_OUT';
    else
      v_status_raw := 'PRESENT';
    end if;
  end if;

  v_status_final := v_status_raw;
  if v_regularization_status = 'APPROVED' then
    if v_status_raw = 'LATE_IN' then
      v_status_final := 'LATE_IN_APPROVED';
    elsif v_status_raw = 'EARLY_OUT' then
      v_status_final := 'EARLY_OUT_APPROVED';
    elsif v_status_raw in ('ABSENT', 'MISSED_PUNCH_IN', 'MISSED_PUNCH_OUT', 'PRESENT') then
      v_status_final := 'PRESENT_REGULARIZED';
    end if;
  end if;

  execute format(
    'update %I.ams_attendance_record set shift_id = coalesce($2, shift_id), scheduled_clock_in = coalesce($3, scheduled_clock_in), scheduled_clock_out = coalesce($4, scheduled_clock_out), scheduled_work_minutes = coalesce($5, scheduled_work_minutes), status_raw = $6, status_final = $7, duration_minutes = $8, overtime_minutes = $9, late_minutes = $10, early_leaving_minutes = $11, on_leave_request_id = $12, leave_session_scope = $13, leave_fraction = $14, is_holiday = $15, holiday_name = $16, updated_at = timezone(''utc'', now()) where attendance_record_id = $1',
    p_schema_name
  ) using p_attendance_record_id, public.platform_ams_try_bigint(v_schedule->>'shift_id'), public.platform_ams_try_timestamptz(v_schedule->>'scheduled_clock_in'), public.platform_ams_try_timestamptz(v_schedule->>'scheduled_clock_out'), (v_schedule->>'scheduled_work_minutes')::int, v_status_raw, v_status_final, v_duration, v_overtime, v_late, v_early, public.platform_try_uuid(v_leave->>'on_leave_request_id'), nullif(v_leave->>'leave_session_scope',''), public.platform_ams_try_numeric(v_leave->>'leave_fraction'), coalesce(v_schedule->>'holiday_name','') <> '', nullif(v_schedule->>'holiday_name','');

  return public.platform_json_response(true,'OK','AMS attendance record recalculated.',jsonb_build_object('attendance_record_id', p_attendance_record_id,'status_final', v_status_final));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_ams_resolve_context(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_params jsonb := coalesce(p_params, '{}'::jsonb);
  v_requested_tenant_id uuid := public.platform_resolve_tenant_id(v_params);
  v_current_tenant_id uuid := public.platform_current_tenant_id();
  v_current_schema text := public.platform_current_tenant_schema();
  v_context_result jsonb;
  v_details jsonb;
begin
  if v_current_tenant_id is not null and v_current_schema is not null then
    if v_requested_tenant_id is not null and v_requested_tenant_id <> v_current_tenant_id then
      return public.platform_json_response(false,'CONTEXT_TENANT_MISMATCH','The requested tenant does not match the current execution context.',jsonb_build_object('requested_tenant_id', v_requested_tenant_id,'current_tenant_id', v_current_tenant_id));
    end if;

    if not public.platform_table_exists(v_current_schema, 'wcm_employee')
      or not public.platform_table_exists(v_current_schema, 'wcm_employee_service_state')
      or not public.platform_table_exists(v_current_schema, 'hierarchy_position')
      or not public.platform_table_exists(v_current_schema, 'lms_leave_request')
      or not public.platform_table_exists(v_current_schema, 'ams_attendance_configuration')
      or not public.platform_table_exists(v_current_schema, 'ams_shift')
      or not public.platform_table_exists(v_current_schema, 'ams_employee_schedule')
      or not public.platform_table_exists(v_current_schema, 'ams_holiday')
      or not public.platform_table_exists(v_current_schema, 'ams_geofence')
      or not public.platform_table_exists(v_current_schema, 'ams_punch_event')
      or not public.platform_table_exists(v_current_schema, 'ams_attendance_record')
      or not public.platform_table_exists(v_current_schema, 'ams_regularization_request')
      or not public.platform_table_exists(v_current_schema, 'ams_audit_event')
    then
      return public.platform_json_response(false,'AMS_CORE_TEMPLATE_NOT_APPLIED','AMS_CORE is not applied to the current tenant schema.',jsonb_build_object('tenant_id', v_current_tenant_id,'tenant_schema', v_current_schema));
    end if;

    return public.platform_json_response(true,'OK','AMS_CORE execution context resolved.',jsonb_build_object('tenant_id', v_current_tenant_id,'tenant_schema', v_current_schema,'actor_user_id', public.platform_current_actor_user_id()));
  end if;

  if not public.platform_is_internal_caller() then
    return public.platform_json_response(false,'TENANT_CONTEXT_REQUIRED','An applied tenant execution context is required.','{}'::jsonb);
  end if;

  if v_requested_tenant_id is null then
    return public.platform_json_response(false,'TENANT_ID_REQUIRED','tenant_id or tenant_code is required when no execution context is active.','{}'::jsonb);
  end if;

  v_context_result := public.platform_apply_execution_context(jsonb_build_object('execution_mode', 'internal_platform','tenant_id', v_requested_tenant_id,'source', coalesce(nullif(btrim(v_params->>'source'), ''), 'platform_ams_resolve_context')));
  if coalesce((v_context_result->>'success')::boolean, false) is not true then return v_context_result; end if;

  v_details := coalesce(v_context_result->'details', '{}'::jsonb);
  if not public.platform_table_exists(v_details->>'tenant_schema', 'ams_attendance_configuration') then
    return public.platform_json_response(false,'AMS_CORE_TEMPLATE_NOT_APPLIED','AMS_CORE is not applied to the requested tenant schema.',jsonb_build_object('tenant_id', public.platform_try_uuid(v_details->>'tenant_id'),'tenant_schema', v_details->>'tenant_schema'));
  end if;

  return public.platform_json_response(true,'OK','AMS_CORE execution context resolved.',jsonb_build_object('tenant_id', public.platform_try_uuid(v_details->>'tenant_id'),'tenant_schema', v_details->>'tenant_schema','actor_user_id', public.platform_current_actor_user_id()));
exception when others then
  return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_ams_resolve_context.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_ams_resolve_leave_for_day(p_schema_name text, p_employee_id uuid, p_attendance_date date)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_leave record;
  v_scope text;
begin
  execute format(
    'select leave_request_id, request_session from %I.lms_leave_request where employee_id = $1 and request_status in (''APPROVED'', ''AUTO_APPROVED'') and request_start_date <= $2 and request_end_date >= $2 order by created_at desc limit 1',
    p_schema_name
  ) into v_leave using p_employee_id, p_attendance_date;

  if v_leave.leave_request_id is null then
    return jsonb_build_object('on_leave_request_id', null, 'leave_session_scope', null, 'leave_fraction', null);
  end if;

  v_scope := lower(coalesce(v_leave.request_session, 'full_day'));
  return jsonb_build_object('on_leave_request_id', v_leave.leave_request_id, 'leave_session_scope', v_scope, 'leave_fraction', public.platform_ams_leave_fraction(v_scope));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_ams_resolve_schedule_for_day(p_schema_name text, p_employee_id uuid, p_attendance_date date)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_config record;
  v_schedule record;
  v_holiday record;
  v_work_days jsonb;
  v_day_of_week integer;
  v_is_work_day boolean;
  v_start_time time;
  v_end_time time;
  v_break_minutes integer;
  v_crosses_midnight boolean;
  v_scheduled_clock_in timestamptz;
  v_scheduled_clock_out timestamptz;
  v_work_minutes integer;
  v_shift_start_time time;
  v_shift_end_time time;
  v_shift_break_minutes integer;
  v_shift_work_days jsonb;
  v_shift_crosses_midnight boolean;
begin
  execute format(
    'select * from %I.ams_attendance_configuration where configuration_status = ''active'' and effective_from <= $1 and (effective_to is null or effective_to >= $1) order by effective_from desc, created_at desc limit 1',
    p_schema_name
  ) into v_config using p_attendance_date;

  if v_config.ams_configuration_id is null then
    return jsonb_build_object('success', false, 'error_code', 'AMS_CONFIGURATION_REQUIRED');
  end if;

  execute format(
    'select * from %I.ams_employee_schedule where employee_id = $1 and schedule_status = ''active'' and effective_start_date <= $2 and (effective_end_date is null or effective_end_date >= $2) order by effective_start_date desc, created_at desc limit 1',
    p_schema_name
  ) into v_schedule using p_employee_id, p_attendance_date;

  if v_schedule.shift_id is not null then
    execute format(
      'select start_time, end_time, break_duration_minutes, work_days, crosses_midnight from %I.ams_shift where shift_id = $1 and shift_status = ''active''',
      p_schema_name
    )
    into v_shift_start_time, v_shift_end_time, v_shift_break_minutes, v_shift_work_days, v_shift_crosses_midnight
    using v_schedule.shift_id;
  end if;

  v_start_time := coalesce(v_schedule.custom_start_time, v_shift_start_time, v_config.default_start_time);
  v_end_time := coalesce(v_schedule.custom_end_time, v_shift_end_time, v_config.default_end_time);
  v_break_minutes := coalesce(v_schedule.custom_break_duration_minutes, v_shift_break_minutes, v_config.default_break_minutes);
  v_work_days := coalesce(v_schedule.custom_work_days, v_shift_work_days, v_config.default_working_days);
  v_crosses_midnight := coalesce(v_shift_crosses_midnight, false) or (v_end_time < v_start_time);
  v_day_of_week := extract(dow from p_attendance_date)::integer;
  v_is_work_day := coalesce(v_work_days @> to_jsonb(v_day_of_week), false);

  execute format(
    'select holiday_name, applies_to_shift_ids from %I.ams_holiday where holiday_status = ''active'' and holiday_date = $1 order by created_at desc limit 1',
    p_schema_name
  ) into v_holiday using p_attendance_date;

  if v_holiday.holiday_name is not null then
    if jsonb_array_length(coalesce(v_holiday.applies_to_shift_ids, '[]'::jsonb)) = 0 or v_schedule.shift_id is null or v_holiday.applies_to_shift_ids @> to_jsonb(v_schedule.shift_id) then
      return jsonb_build_object('success', true, 'shift_id', v_schedule.shift_id, 'is_work_day', false, 'work_day_reason', 'HOLIDAY', 'holiday_name', v_holiday.holiday_name, 'scheduled_clock_in', null, 'scheduled_clock_out', null, 'scheduled_work_minutes', 0, 'timezone', v_config.timezone, 'ip_restrictions_enabled', v_config.ip_restrictions_enabled, 'allowed_ips', v_config.allowed_ips, 'geo_fencing_enabled', v_config.geo_fencing_enabled, 'allowed_geofences', v_config.allowed_geofences, 'late_mark_threshold_minutes', v_config.late_mark_threshold_minutes, 'early_leaving_threshold_minutes', v_config.early_leaving_threshold_minutes, 'grace_period_late_minutes', v_config.grace_period_late_minutes, 'grace_period_early_minutes', v_config.grace_period_early_minutes, 'half_day_hours', v_config.half_day_hours);
    end if;
  end if;

  if v_is_work_day then
    v_scheduled_clock_in := timezone(v_config.timezone, p_attendance_date::timestamp + v_start_time);
    if v_crosses_midnight then
      v_scheduled_clock_out := timezone(v_config.timezone, (p_attendance_date + 1)::timestamp + v_end_time);
    else
      v_scheduled_clock_out := timezone(v_config.timezone, p_attendance_date::timestamp + v_end_time);
    end if;
    v_work_minutes := greatest(0, floor(extract(epoch from (v_scheduled_clock_out - v_scheduled_clock_in)) / 60)::integer - coalesce(v_break_minutes, 0));
  else
    v_scheduled_clock_in := null;
    v_scheduled_clock_out := null;
    v_work_minutes := 0;
  end if;

  return jsonb_build_object('success', true, 'shift_id', v_schedule.shift_id, 'is_work_day', v_is_work_day, 'work_day_reason', case when v_is_work_day then 'SHIFT_SCHEDULED' else 'DAY_OFF' end, 'holiday_name', null, 'scheduled_clock_in', v_scheduled_clock_in, 'scheduled_clock_out', v_scheduled_clock_out, 'scheduled_work_minutes', v_work_minutes, 'timezone', v_config.timezone, 'ip_restrictions_enabled', v_config.ip_restrictions_enabled, 'allowed_ips', v_config.allowed_ips, 'geo_fencing_enabled', v_config.geo_fencing_enabled, 'allowed_geofences', v_config.allowed_geofences, 'late_mark_threshold_minutes', v_config.late_mark_threshold_minutes, 'early_leaving_threshold_minutes', v_config.early_leaving_threshold_minutes, 'grace_period_late_minutes', v_config.grace_period_late_minutes, 'grace_period_early_minutes', v_config.grace_period_early_minutes, 'half_day_hours', v_config.half_day_hours);
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_ams_shift_catalog_rows()
 RETURNS TABLE(tenant_id uuid, shift_id bigint, shift_code text, shift_name text, start_time time without time zone, end_time time without time zone, break_duration_minutes integer, paid_break_minutes integer, work_days jsonb, crosses_midnight boolean, shift_status text, shift_metadata jsonb, created_at timestamp with time zone, updated_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context_result jsonb;
  v_schema_name text;
  v_tenant_id uuid;
begin
  v_context_result := public.platform_ams_resolve_context('{}'::jsonb);
  if coalesce((v_context_result->>'success')::boolean, false) is not true then return; end if;
  v_schema_name := nullif(coalesce(v_context_result->'details'->>'tenant_schema', ''), '');
  v_tenant_id := public.platform_try_uuid(v_context_result->'details'->>'tenant_id');

  return query execute format(
    'select $1::uuid, shift_id, shift_code, shift_name, start_time, end_time, break_duration_minutes, paid_break_minutes, work_days, crosses_midnight, shift_status, shift_metadata, created_at, updated_at from %I.ams_shift order by shift_code asc, shift_id asc',
    v_schema_name
  ) using v_tenant_id;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_ams_team_day_summary_rows()
 RETURNS TABLE(tenant_id uuid, manager_actor_user_id uuid, manager_employee_id uuid, team_member_employee_id uuid, team_member_employee_code text, team_member_employee_name text, attendance_record_id uuid, attendance_date date, status_final text, clock_in_time timestamp with time zone, clock_out_time timestamp with time zone, late_minutes integer, early_leaving_minutes integer, overtime_minutes integer, on_leave_request_id uuid, holiday_name text, is_manually_edited boolean, mood_score smallint, updated_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_actor_user_id uuid := public.platform_current_actor_user_id();
begin
  return query
  select
    h.tenant_id,
    s.manager_actor_user_id,
    s.manager_employee_id,
    s.team_member_employee_id,
    s.team_member_employee_code,
    s.team_member_employee_name,
    h.attendance_record_id,
    h.attendance_date,
    h.status_final,
    h.clock_in_time,
    h.clock_out_time,
    h.late_minutes,
    h.early_leaving_minutes,
    h.overtime_minutes,
    h.on_leave_request_id,
    h.holiday_name,
    h.is_manually_edited,
    h.mood_score,
    h.updated_at
  from public.platform_rm_hierarchy_team_scope s
  join public.platform_rm_ams_attendance_history h
    on h.employee_id = s.team_member_employee_id
  where v_actor_user_id is null or s.manager_actor_user_id = v_actor_user_id
  order by h.attendance_date desc, h.attendance_record_id desc;
end;
$function$
;

