CREATE OR REPLACE FUNCTION public.platform_apply_agm_to_tenant(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_tenant_id uuid := public.platform_resolve_tenant_id(p_params);
  v_template_version text := public.platform_agm_module_template_version();
  v_dependency_result jsonb;
  v_apply_result jsonb;
  v_context_result jsonb;
  v_schema_name text;
  v_table_name text;
begin
  if not public.platform_is_internal_caller() then
    return public.platform_json_response(false,'INTERNAL_CALLER_REQUIRED','Internal caller is required.','{}'::jsonb);
  end if;
  if v_tenant_id is null then
    return public.platform_json_response(false,'TENANT_ID_REQUIRED','tenant_id or tenant_code is required.','{}'::jsonb);
  end if;

  v_dependency_result := public.platform_apply_ams_bio_to_tenant(jsonb_build_object('tenant_id', v_tenant_id,'source', 'platform_apply_agm_to_tenant'));
  if coalesce((v_dependency_result->>'success')::boolean, false) is not true then
    return v_dependency_result;
  end if;

  v_apply_result := public.platform_apply_template_version_to_tenant(jsonb_build_object('tenant_id', v_tenant_id,'template_version', v_template_version,'source', 'platform_apply_agm_to_tenant'));
  if coalesce((v_apply_result->>'success')::boolean, false) is not true then
    return v_apply_result;
  end if;

  v_context_result := public.platform_agm_resolve_context(jsonb_build_object('tenant_id', v_tenant_id,'source', 'platform_apply_agm_to_tenant'));
  if coalesce((v_context_result->>'success')::boolean, false) is not true then
    return v_context_result;
  end if;
  v_schema_name := nullif(coalesce(v_context_result->'details'->>'tenant_schema', ''), '');

  if not exists (
    select 1 from pg_constraint c join pg_class t on t.oid = c.conrelid join pg_namespace n on n.oid = t.relnamespace
    where n.nspname = v_schema_name and t.relname = 'agm_score_event' and c.conname = 'agm_score_event_employee_fk'
  ) then
    execute format('alter table %I.agm_score_event add constraint agm_score_event_employee_fk foreign key (employee_id) references %I.wcm_employee(employee_id) on delete cascade', v_schema_name, v_schema_name);
  end if;
  if not exists (
    select 1 from pg_constraint c join pg_class t on t.oid = c.conrelid join pg_namespace n on n.oid = t.relnamespace
    where n.nspname = v_schema_name and t.relname = 'agm_score_event' and c.conname = 'agm_score_event_attendance_fk'
  ) then
    execute format('alter table %I.agm_score_event add constraint agm_score_event_attendance_fk foreign key (attendance_record_id) references %I.ams_attendance_record(attendance_record_id) on delete set null', v_schema_name, v_schema_name);
  end if;
  if not exists (
    select 1 from pg_constraint c join pg_class t on t.oid = c.conrelid join pg_namespace n on n.oid = t.relnamespace
    where n.nspname = v_schema_name and t.relname = 'agm_score_event' and c.conname = 'agm_score_event_rule_set_fk'
  ) then
    execute format('alter table %I.agm_score_event add constraint agm_score_event_rule_set_fk foreign key (rule_set_id) references %I.agm_rule_set(rule_set_id) on delete set null', v_schema_name, v_schema_name);
  end if;
  if not exists (
    select 1 from pg_constraint c join pg_class t on t.oid = c.conrelid join pg_namespace n on n.oid = t.relnamespace
    where n.nspname = v_schema_name and t.relname = 'agm_score_event' and c.conname = 'agm_score_event_reversal_fk'
  ) then
    execute format('alter table %I.agm_score_event add constraint agm_score_event_reversal_fk foreign key (reversal_of) references %I.agm_score_event(score_event_id) on delete set null', v_schema_name, v_schema_name);
  end if;
  if not exists (
    select 1 from pg_constraint c join pg_class t on t.oid = c.conrelid join pg_namespace n on n.oid = t.relnamespace
    where n.nspname = v_schema_name and t.relname = 'agm_badge_award' and c.conname = 'agm_badge_award_employee_fk'
  ) then
    execute format('alter table %I.agm_badge_award add constraint agm_badge_award_employee_fk foreign key (employee_id) references %I.wcm_employee(employee_id) on delete cascade', v_schema_name, v_schema_name);
  end if;
  if not exists (
    select 1 from pg_constraint c join pg_class t on t.oid = c.conrelid join pg_namespace n on n.oid = t.relnamespace
    where n.nspname = v_schema_name and t.relname = 'agm_badge_award' and c.conname = 'agm_badge_award_badge_fk'
  ) then
    execute format('alter table %I.agm_badge_award add constraint agm_badge_award_badge_fk foreign key (badge_id) references %I.agm_badge_catalog(badge_id) on delete cascade', v_schema_name, v_schema_name);
  end if;
  if not exists (
    select 1 from pg_constraint c join pg_class t on t.oid = c.conrelid join pg_namespace n on n.oid = t.relnamespace
    where n.nspname = v_schema_name and t.relname = 'agm_badge_award' and c.conname = 'agm_badge_award_source_event_fk'
  ) then
    execute format('alter table %I.agm_badge_award add constraint agm_badge_award_source_event_fk foreign key (source_event_id) references %I.agm_score_event(score_event_id) on delete set null', v_schema_name, v_schema_name);
  end if;
  if not exists (
    select 1 from pg_constraint c join pg_class t on t.oid = c.conrelid join pg_namespace n on n.oid = t.relnamespace
    where n.nspname = v_schema_name and t.relname = 'agm_recognition_event' and c.conname = 'agm_recognition_event_sender_fk'
  ) then
    execute format('alter table %I.agm_recognition_event add constraint agm_recognition_event_sender_fk foreign key (sender_employee_id) references %I.wcm_employee(employee_id) on delete set null', v_schema_name, v_schema_name);
  end if;
  if not exists (
    select 1 from pg_constraint c join pg_class t on t.oid = c.conrelid join pg_namespace n on n.oid = t.relnamespace
    where n.nspname = v_schema_name and t.relname = 'agm_recognition_event' and c.conname = 'agm_recognition_event_recipient_fk'
  ) then
    execute format('alter table %I.agm_recognition_event add constraint agm_recognition_event_recipient_fk foreign key (recipient_employee_id) references %I.wcm_employee(employee_id) on delete cascade', v_schema_name, v_schema_name);
  end if;
  if not exists (
    select 1 from pg_constraint c join pg_class t on t.oid = c.conrelid join pg_namespace n on n.oid = t.relnamespace
    where n.nspname = v_schema_name and t.relname = 'agm_recognition_event' and c.conname = 'agm_recognition_event_source_event_fk'
  ) then
    execute format('alter table %I.agm_recognition_event add constraint agm_recognition_event_source_event_fk foreign key (source_event_id) references %I.agm_score_event(score_event_id) on delete set null', v_schema_name, v_schema_name);
  end if;
  if not exists (
    select 1 from pg_constraint c join pg_class t on t.oid = c.conrelid join pg_namespace n on n.oid = t.relnamespace
    where n.nspname = v_schema_name and t.relname = 'agm_user_preference' and c.conname = 'agm_user_preference_employee_fk'
  ) then
    execute format('alter table %I.agm_user_preference add constraint agm_user_preference_employee_fk foreign key (employee_id) references %I.wcm_employee(employee_id) on delete cascade', v_schema_name, v_schema_name);
  end if;
  if not exists (
    select 1 from pg_constraint c join pg_class t on t.oid = c.conrelid join pg_namespace n on n.oid = t.relnamespace
    where n.nspname = v_schema_name and t.relname = 'agm_user_score_summary' and c.conname = 'agm_user_score_summary_employee_fk'
  ) then
    execute format('alter table %I.agm_user_score_summary add constraint agm_user_score_summary_employee_fk foreign key (employee_id) references %I.wcm_employee(employee_id) on delete cascade', v_schema_name, v_schema_name);
  end if;

  execute format('create unique index if not exists agm_rule_set_code_lower_idx on %I.agm_rule_set (lower(rule_set_code))', v_schema_name);
  execute format('create unique index if not exists agm_rule_set_single_active_idx on %I.agm_rule_set ((1)) where status = ''active''', v_schema_name);
  execute format('create unique index if not exists agm_badge_catalog_code_lower_idx on %I.agm_badge_catalog (lower(badge_code))', v_schema_name);
  execute format('create unique index if not exists agm_score_event_source_key_idx on %I.agm_score_event (source_key)', v_schema_name);
  execute format('create index if not exists agm_score_event_employee_window_idx on %I.agm_score_event (employee_id, attendance_date desc)', v_schema_name);
  execute format('create index if not exists agm_score_event_attendance_idx on %I.agm_score_event (attendance_record_id)', v_schema_name);
  execute format('create index if not exists agm_score_event_rule_set_idx on %I.agm_score_event (rule_set_id)', v_schema_name);
  execute format('create index if not exists agm_score_event_reversal_idx on %I.agm_score_event (reversal_of)', v_schema_name);
  execute format('create unique index if not exists agm_badge_award_employee_badge_date_idx on %I.agm_badge_award (employee_id, badge_id, award_date)', v_schema_name);
  execute format('create index if not exists agm_badge_award_badge_idx on %I.agm_badge_award (badge_id)', v_schema_name);
  execute format('create index if not exists agm_badge_award_source_event_idx on %I.agm_badge_award (source_event_id)', v_schema_name);
  execute format('create index if not exists agm_recognition_event_recipient_history_idx on %I.agm_recognition_event (recipient_employee_id, created_at desc)', v_schema_name);
  execute format('create index if not exists agm_recognition_event_sender_history_idx on %I.agm_recognition_event (sender_employee_id, created_at desc)', v_schema_name);
  execute format('create index if not exists agm_recognition_event_source_event_idx on %I.agm_recognition_event (source_event_id)', v_schema_name);
  execute format('create unique index if not exists agm_user_preference_employee_idx on %I.agm_user_preference (employee_id)', v_schema_name);
  execute format('create unique index if not exists agm_user_score_summary_window_idx on %I.agm_user_score_summary (employee_id, window_code, window_start, window_end)', v_schema_name);
  execute format('create unique index if not exists agm_leaderboard_snapshot_scope_window_idx on %I.agm_leaderboard_snapshot (scope_code, scope_key, window_code, snapshot_date)', v_schema_name);
  execute format('create index if not exists agm_audit_log_created_at_idx on %I.agm_audit_log (created_at desc)', v_schema_name);

  foreach v_table_name in array array[
    'agm_rule_set',
    'agm_badge_catalog',
    'agm_badge_award',
    'agm_recognition_event',
    'agm_user_preference',
    'agm_user_score_summary'
  ]
  loop
    if not exists (
      select 1
      from pg_trigger tg
      join pg_class t on t.oid = tg.tgrelid
      join pg_namespace n on n.oid = t.relnamespace
      where n.nspname = v_schema_name
        and t.relname = v_table_name
        and tg.tgname = format('trg_%s_set_updated_at', v_table_name)
        and not tg.tgisinternal
    ) then
      execute format('create trigger %I before update on %I.%I for each row execute function public.platform_set_updated_at()', format('trg_%s_set_updated_at', v_table_name), v_schema_name, v_table_name);
    end if;
  end loop;

  if not exists (
    select 1
    from pg_trigger tg
    join pg_class t on t.oid = tg.tgrelid
    join pg_namespace n on n.oid = t.relnamespace
    where n.nspname = v_schema_name
      and t.relname = 'ams_attendance_record'
      and tg.tgname = 'trg_agm_queue_refresh_on_ams_change'
      and not tg.tgisinternal
  ) then
    execute format('create trigger trg_agm_queue_refresh_on_ams_change after insert or update or delete on %I.ams_attendance_record for each row execute function public.platform_enqueue_agm_refresh_for_attendance_change()', v_schema_name);
  end if;

  return public.platform_json_response(true,'OK','AGM applied to tenant schema.',jsonb_build_object('tenant_id', v_tenant_id,'tenant_schema', v_schema_name,'template_version', v_template_version));
exception when others then
  return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_apply_agm_to_tenant.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm, 'tenant_id', v_tenant_id));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_apply_ams_bio_to_tenant(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_tenant_id uuid := public.platform_resolve_tenant_id(p_params);
  v_template_version text := public.platform_ams_bio_module_template_version();
  v_dependency_result jsonb;
  v_apply_result jsonb;
