  v_apply_result := public.platform_apply_template_version_to_tenant(jsonb_build_object('tenant_id', v_tenant_id,'template_version', v_template_version,'source', 'platform_apply_ams_bio_to_tenant'));
  if coalesce((v_apply_result->>'success')::boolean, false) is not true then
