  v_context_result := public.platform_ams_bio_resolve_context(jsonb_build_object('tenant_id', v_tenant_id,'source', 'platform_apply_ams_bio_to_tenant'));
  if coalesce((v_context_result->>'success')::boolean, false) is not true then
    return v_context_result;
  end if;
  v_schema_name := nullif(coalesce(v_context_result->'details'->>'tenant_schema', ''), '');

  if not exists (select 1 from pg_constraint c join pg_class t on t.oid = c.conrelid join pg_namespace n on n.oid = t.relnamespace where n.nspname = v_schema_name and t.relname = 'ams_bio_employee_mapping' and c.conname = 'ams_bio_employee_mapping_employee_fk') then
    execute format('alter table %I.ams_bio_employee_mapping add constraint ams_bio_employee_mapping_employee_fk foreign key (employee_id) references %I.wcm_employee(employee_id) on delete set null', v_schema_name, v_schema_name);
  end if;
  if not exists (select 1 from pg_constraint c join pg_class t on t.oid = c.conrelid join pg_namespace n on n.oid = t.relnamespace where n.nspname = v_schema_name and t.relname = 'ams_bio_import_session' and c.conname = 'ams_bio_import_session_source_document_fk') then
    execute format('alter table %I.ams_bio_import_session add constraint ams_bio_import_session_source_document_fk foreign key (source_document_id) references public.platform_document_record(document_id) on delete set null', v_schema_name);
  end if;
  if not exists (select 1 from pg_constraint c join pg_class t on t.oid = c.conrelid join pg_namespace n on n.oid = t.relnamespace where n.nspname = v_schema_name and t.relname = 'ams_bio_normalized_punch' and c.conname = 'ams_bio_normalized_punch_employee_fk') then
    execute format('alter table %I.ams_bio_normalized_punch add constraint ams_bio_normalized_punch_employee_fk foreign key (employee_id) references %I.wcm_employee(employee_id) on delete set null', v_schema_name, v_schema_name);
  end if;
  if not exists (select 1 from pg_constraint c join pg_class t on t.oid = c.conrelid join pg_namespace n on n.oid = t.relnamespace where n.nspname = v_schema_name and t.relname = 'ams_bio_publish_log' and c.conname = 'ams_bio_publish_log_attendance_fk') then
    execute format('alter table %I.ams_bio_publish_log add constraint ams_bio_publish_log_attendance_fk foreign key (ams_attendance_record_id) references %I.ams_attendance_record(attendance_record_id) on delete set null', v_schema_name, v_schema_name);
  end if;
  if not exists (select 1 from pg_constraint c join pg_class t on t.oid = c.conrelid join pg_namespace n on n.oid = t.relnamespace where n.nspname = v_schema_name and t.relname = 'ams_bio_reconciliation_case' and c.conname = 'ams_bio_reconciliation_case_employee_fk') then
    execute format('alter table %I.ams_bio_reconciliation_case add constraint ams_bio_reconciliation_case_employee_fk foreign key (employee_id) references %I.wcm_employee(employee_id) on delete set null', v_schema_name, v_schema_name);
