  execute format('create index if not exists ams_bio_import_session_source_document_id_idx on %I.ams_bio_import_session (source_document_id) where source_document_id is not null', v_schema_name);
  execute format('create index if not exists ams_bio_publish_log_attendance_record_id_idx on %I.ams_bio_publish_log (ams_attendance_record_id) where ams_attendance_record_id is not null', v_schema_name);
  execute format('create index if not exists ams_bio_reconciliation_case_employee_id_idx on %I.ams_bio_reconciliation_case (employee_id) where employee_id is not null', v_schema_name);

  foreach v_table_name in array array[
    'ams_bio_source_profile','ams_bio_source_onboarding_state','ams_bio_connector','ams_bio_device','ams_bio_employee_mapping','ams_bio_field_mapping_profile','ams_bio_field_mapping_rule','ams_bio_import_session','ams_bio_import_run','ams_bio_import_staging_row','ams_bio_import_validation_summary','ams_bio_raw_punch_log','ams_bio_normalized_punch','ams_bio_publish_log','ams_bio_reconciliation_case'
