  return public.platform_json_response(true,'OK','AMS_BIO applied to tenant schema.',jsonb_build_object('tenant_id', v_tenant_id,'tenant_schema', v_schema_name,'template_version', v_template_version));
exception when others then
  return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_apply_ams_bio_to_tenant.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm, 'tenant_id', v_tenant_id));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_apply_ams_core_to_tenant(p_params jsonb)
