  v_schema_name text;
begin
  if not public.platform_is_internal_caller() then return public.platform_json_response(false,'INTERNAL_CALLER_REQUIRED','Internal caller is required.','{}'::jsonb); end if;
  if v_tenant_id is null then return public.platform_json_response(false,'TENANT_ID_REQUIRED','tenant_id or tenant_code is required.','{}'::jsonb); end if;

  v_dependency_result := public.platform_apply_lms_to_tenant(jsonb_build_object('tenant_id', v_tenant_id,'source', 'platform_apply_ams_core_to_tenant'));
  if coalesce((v_dependency_result->>'success')::boolean, false) is not true then return v_dependency_result; end if;

  v_apply_result := public.platform_apply_template_version_to_tenant(jsonb_build_object('tenant_id', v_tenant_id,'template_version', v_template_version,'source', 'platform_apply_ams_core_to_tenant'));
  if coalesce((v_apply_result->>'success')::boolean, false) is not true then return v_apply_result; end if;

  v_context_result := public.platform_ams_resolve_context(jsonb_build_object('tenant_id', v_tenant_id,'source', 'platform_apply_ams_core_to_tenant'));
  if coalesce((v_context_result->>'success')::boolean, false) is not true then return v_context_result; end if;
