  if not exists (select 1 from pg_constraint c join pg_class t on t.oid = c.conrelid join pg_namespace n on n.oid = t.relnamespace where n.nspname = v_schema_name and t.relname = 'ams_employee_schedule' and c.conname = 'ams_employee_schedule_employee_fk') then execute format('alter table %I.ams_employee_schedule add constraint ams_employee_schedule_employee_fk foreign key (employee_id) references %I.wcm_employee(employee_id) on delete cascade', v_schema_name, v_schema_name); end if;
