  if not exists (select 1 from pg_trigger tg join pg_class t on t.oid = tg.tgrelid join pg_namespace n on n.oid = t.relnamespace where n.nspname = v_schema_name and t.relname = 'ams_attendance_record' and tg.tgname = 'trg_ams_attendance_record_set_updated_at' and not tg.tgisinternal) then execute format('create trigger trg_ams_attendance_record_set_updated_at before update on %I.ams_attendance_record for each row execute function public.platform_set_updated_at()', v_schema_name); end if;
