CREATE OR REPLACE FUNCTION public.platform_hierarchy_occupancy_role_priority(p_occupancy_role text)
 RETURNS integer
 LANGUAGE sql
 IMMUTABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
