CREATE OR REPLACE FUNCTION public.platform_hierarchy_operational_occupancy_rows()
 RETURNS TABLE(tenant_id uuid, position_id bigint, position_code text, position_name text, reporting_position_id bigint, employee_id uuid, employee_code text, actor_user_id uuid, employee_name text, occupancy_id bigint, occupancy_role text, effective_start_date date, effective_end_date date, service_state text, employment_status text, active_occupancy_count integer, overlap_count integer, is_operational_occupant boolean)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_tenant_id uuid := public.platform_current_tenant_id();
  v_schema_name text := public.platform_current_tenant_schema();
begin
  if v_tenant_id is null or v_schema_name is null then
    return;
  end if;

  if not public.platform_table_exists(v_schema_name, 'hierarchy_position')
    or not public.platform_table_exists(v_schema_name, 'hierarchy_position_occupancy')
    or not public.platform_table_exists(v_schema_name, 'wcm_employee')
    or not public.platform_table_exists(v_schema_name, 'wcm_employee_service_state')
  then
    return;
  end if;

  return query execute format(
    'with active_rows as (
       select
         p.position_id,
         p.position_code,
         p.position_name,
         p.reporting_position_id,
         e.employee_id,
         e.employee_code,
         e.actor_user_id,
         concat_ws('' '', e.first_name, nullif(e.middle_name, ''''), e.last_name) as employee_name,
         o.occupancy_id,
         o.occupancy_role,
         o.effective_start_date,
         o.effective_end_date,
         s.service_state,
         s.employment_status
       from %1$I.hierarchy_position_occupancy o
       join %1$I.hierarchy_position p on p.position_id = o.position_id
       join %1$I.wcm_employee e on e.employee_id = o.employee_id
       join %1$I.wcm_employee_service_state s on s.employee_id = o.employee_id
       where o.occupancy_status = ''active''
         and o.effective_start_date <= current_date
         and coalesce(o.effective_end_date, date ''9999-12-31'') >= current_date
     ), ranked as (
       select
         a.*,
         count(*) over (partition by a.position_id)::integer as active_occupancy_count,
         row_number() over (
           partition by a.position_id
           order by
             public.platform_hierarchy_occupancy_role_priority(a.occupancy_role),
             public.platform_hierarchy_service_state_priority(a.service_state),
             a.effective_start_date desc,
             a.occupancy_id desc
         ) as operational_rank
       from active_rows a
     )
     select
       $1::uuid as tenant_id,
       r.position_id,
       r.position_code,
       r.position_name,
       r.reporting_position_id,
       r.employee_id,
       r.employee_code,
       r.actor_user_id,
       r.employee_name,
       r.occupancy_id,
       r.occupancy_role,
       r.effective_start_date,
       r.effective_end_date,
       r.service_state,
       r.employment_status,
       r.active_occupancy_count,
       greatest(r.active_occupancy_count - 1, 0) as overlap_count,
       (r.operational_rank = 1) as is_operational_occupant
     from ranked r
     order by r.position_id, r.operational_rank, r.occupancy_id',
    v_schema_name
  ) using v_tenant_id;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_hierarchy_position_assign_path()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_parent_path ltree;
begin
  if new.reporting_position_id is not null and new.reporting_position_id = new.position_id then
    raise exception 'Position cannot report to itself.' using errcode = '23514';
  end if;

  if new.position_id is null then
    raise exception 'Position id must be available before path assignment.' using errcode = '23514';
  end if;

  if new.reporting_position_id is null then
    new.hierarchy_path := text2ltree(new.position_id::text);
    return new;
  end if;

  execute format(
    'select hierarchy_path from %I.hierarchy_position where position_id = $1',
    tg_table_schema
  )
  into v_parent_path
  using new.reporting_position_id;

  if v_parent_path is null then
    raise exception 'Reporting position % not found in tenant hierarchy.', new.reporting_position_id using errcode = '23514';
  end if;

  if tg_op = 'UPDATE' and old.hierarchy_path is not null and v_parent_path <@ old.hierarchy_path then
    raise exception 'Hierarchy cycle detected for position %.', new.position_id using errcode = '23514';
  end if;

  new.hierarchy_path := v_parent_path || text2ltree(new.position_id::text);
  return new;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_hierarchy_position_catalog_rows()
 RETURNS TABLE(tenant_id uuid, position_id bigint, position_code text, position_name text, position_group_id bigint, position_group_code text, position_group_name text, reporting_position_id bigint, hierarchy_path text, hierarchy_level integer, position_status text, effective_start_date date, effective_end_date date, active_occupancy_count integer, direct_report_count integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_tenant_id uuid := public.platform_current_tenant_id();
  v_schema_name text := public.platform_current_tenant_schema();
begin
  if v_tenant_id is null or v_schema_name is null then
    return;
  end if;

  if not public.platform_table_exists(v_schema_name, 'hierarchy_position')
    or not public.platform_table_exists(v_schema_name, 'hierarchy_position_group')
    or not public.platform_table_exists(v_schema_name, 'hierarchy_position_occupancy')
  then
    return;
  end if;

  return query execute format(
    'select
       $1::uuid as tenant_id,
       p.position_id,
       p.position_code,
       p.position_name,
       p.position_group_id,
       g.position_group_code,
       g.position_group_name,
       p.reporting_position_id,
       ltree2text(p.hierarchy_path) as hierarchy_path,
       nlevel(p.hierarchy_path)::integer as hierarchy_level,
       p.position_status,
       p.effective_start_date,
       p.effective_end_date,
       coalesce(oa.active_occupancy_count, 0)::integer as active_occupancy_count,
       coalesce(dr.direct_report_count, 0)::integer as direct_report_count
     from %1$I.hierarchy_position p
     left join %1$I.hierarchy_position_group g on g.position_group_id = p.position_group_id
     left join (
       select position_id, count(*) as active_occupancy_count
       from %1$I.hierarchy_position_occupancy
       where occupancy_status = ''active''
         and effective_start_date <= current_date
         and coalesce(effective_end_date, date ''9999-12-31'') >= current_date
       group by position_id
     ) oa on oa.position_id = p.position_id
     left join (
       select reporting_position_id, count(*) as direct_report_count
       from %1$I.hierarchy_position
       where reporting_position_id is not null
       group by reporting_position_id
     ) dr on dr.reporting_position_id = p.position_id
     order by p.hierarchy_path nulls last, p.position_code',
    v_schema_name
  ) using v_tenant_id;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_hierarchy_position_group_catalog_rows()
 RETURNS TABLE(tenant_id uuid, position_group_id bigint, position_group_code text, position_group_name text, group_status text, description text, total_position_count integer, active_position_count integer, created_at timestamp with time zone, updated_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_tenant_id uuid := public.platform_current_tenant_id();
  v_schema_name text := public.platform_current_tenant_schema();
begin
  if v_tenant_id is null or v_schema_name is null then
    return;
  end if;

  if not public.platform_table_exists(v_schema_name, 'hierarchy_position_group')
    or not public.platform_table_exists(v_schema_name, 'hierarchy_position')
  then
