       g.created_at,
       g.updated_at
     from %1$I.hierarchy_position_group g
     left join %1$I.hierarchy_position p
       on p.position_group_id = g.position_group_id
     group by
       g.position_group_id,
       g.position_group_code,
       g.position_group_name,
       g.group_status,
       g.description,
       g.created_at,
       g.updated_at
     order by g.position_group_code',
    v_schema_name
  ) using v_tenant_id;
