$function$
;

CREATE OR REPLACE FUNCTION public.platform_hierarchy_position_refresh_descendants()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
begin
  if tg_op = 'UPDATE' and new.reporting_position_id is distinct from old.reporting_position_id then
    perform public.platform_hierarchy_refresh_subtree_paths(tg_table_schema, new.position_id);
  end if;

  return null;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_hierarchy_refresh_subtree_paths(p_schema_name text, p_root_position_id bigint)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
begin
  if nullif(btrim(coalesce(p_schema_name, '')), '') is null or p_root_position_id is null then
    return;
  end if;

  execute format(
    'with recursive tree as (
       select hp.position_id, hp.hierarchy_path as new_path
       from %1$I.hierarchy_position hp
       where hp.position_id = $1
       union all
       select child.position_id, tree.new_path || text2ltree(child.position_id::text) as new_path
       from %1$I.hierarchy_position child
       join tree on child.reporting_position_id = tree.position_id
     )
     update %1$I.hierarchy_position target
     set hierarchy_path = tree.new_path
     from tree
     where target.position_id = tree.position_id
       and target.position_id <> $1
       and target.hierarchy_path is distinct from tree.new_path',
    p_schema_name
  )
  using p_root_position_id;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_hierarchy_resolve_context(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_params jsonb := coalesce(p_params, '{}'::jsonb);
  v_requested_tenant_id uuid := public.platform_resolve_tenant_id(v_params);
  v_current_tenant_id uuid := public.platform_current_tenant_id();
  v_current_schema text := public.platform_current_tenant_schema();
  v_context_result jsonb;
  v_details jsonb;
begin
  if v_current_tenant_id is not null and v_current_schema is not null then
    if v_requested_tenant_id is not null and v_requested_tenant_id <> v_current_tenant_id then
      return public.platform_json_response(
        false,
        'CONTEXT_TENANT_MISMATCH',
        'The requested tenant does not match the current execution context.',
        jsonb_build_object(
          'requested_tenant_id', v_requested_tenant_id,
          'current_tenant_id', v_current_tenant_id
        )
      );
    end if;

    if not public.platform_table_exists(v_current_schema, 'wcm_employee')
      or not public.platform_table_exists(v_current_schema, 'wcm_employee_service_state')
      or not public.platform_table_exists(v_current_schema, 'hierarchy_position_group')
      or not public.platform_table_exists(v_current_schema, 'hierarchy_position')
      or not public.platform_table_exists(v_current_schema, 'hierarchy_position_occupancy')
      or not public.platform_table_exists(v_current_schema, 'hierarchy_position_occupancy_history')
    then
      return public.platform_json_response(
        false,
        'HIERARCHY_TEMPLATE_NOT_APPLIED',
        'HIERARCHY is not applied to the current tenant schema.',
        jsonb_build_object(
          'tenant_id', v_current_tenant_id,
          'tenant_schema', v_current_schema
        )
      );
    end if;

    return public.platform_json_response(
      true,
      'OK',
      'HIERARCHY execution context resolved.',
      jsonb_build_object(
        'tenant_id', v_current_tenant_id,
        'tenant_schema', v_current_schema,
        'actor_user_id', public.platform_current_actor_user_id()
      )
    );
  end if;

  if not public.platform_is_internal_caller() then
    return public.platform_json_response(
      false,
      'TENANT_CONTEXT_REQUIRED',
      'An applied tenant execution context is required.',
      '{}'::jsonb
    );
  end if;

  if v_requested_tenant_id is null then
    return public.platform_json_response(
      false,
      'TENANT_ID_REQUIRED',
      'tenant_id or tenant_code is required when no execution context is active.',
      '{}'::jsonb
    );
  end if;

  v_context_result := public.platform_apply_execution_context(jsonb_build_object(
    'execution_mode', 'internal_platform',
    'tenant_id', v_requested_tenant_id,
    'source', coalesce(nullif(btrim(v_params->>'source'), ''), 'platform_hierarchy_resolve_context')
  ));

  if coalesce((v_context_result->>'success')::boolean, false) is not true then
    return v_context_result;
  end if;

  v_details := coalesce(v_context_result->'details', '{}'::jsonb);

  if not public.platform_table_exists(v_details->>'tenant_schema', 'wcm_employee')
    or not public.platform_table_exists(v_details->>'tenant_schema', 'wcm_employee_service_state')
    or not public.platform_table_exists(v_details->>'tenant_schema', 'hierarchy_position_group')
    or not public.platform_table_exists(v_details->>'tenant_schema', 'hierarchy_position')
    or not public.platform_table_exists(v_details->>'tenant_schema', 'hierarchy_position_occupancy')
    or not public.platform_table_exists(v_details->>'tenant_schema', 'hierarchy_position_occupancy_history')
  then
    return public.platform_json_response(
      false,
      'HIERARCHY_TEMPLATE_NOT_APPLIED',
      'HIERARCHY is not applied to the requested tenant schema.',
      jsonb_build_object(
        'tenant_id', public.platform_try_uuid(v_details->>'tenant_id'),
        'tenant_schema', v_details->>'tenant_schema'
      )
    );
  end if;

  return public.platform_json_response(
    true,
    'OK',
    'HIERARCHY execution context resolved.',
    jsonb_build_object(
      'tenant_id', public.platform_try_uuid(v_details->>'tenant_id'),
      'tenant_schema', v_details->>'tenant_schema',
      'actor_user_id', public.platform_current_actor_user_id()
    )
  );
exception
  when others then
    return public.platform_json_response(
      false,
      'UNEXPECTED_ERROR',
      'Unexpected error in platform_hierarchy_resolve_context.',
      jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm)
    );
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_hierarchy_service_state_priority(p_service_state text)
 RETURNS integer
 LANGUAGE sql
 IMMUTABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
  select case lower(coalesce(p_service_state, ''))
    when 'active' then 1
    when 'pending_join' then 2
    when 'inactive' then 3
    when 'separated' then 4
    else 99
  end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_hierarchy_sync_wcm_position_state(p_schema_name text, p_employee_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_position_id bigint;
begin
  execute format(
    'select o.position_id
     from %I.hierarchy_position_occupancy o
     where o.employee_id = $1
       and o.occupancy_status = ''active''
       and o.effective_start_date <= current_date
       and coalesce(o.effective_end_date, date ''9999-12-31'') >= current_date
     order by o.effective_start_date desc, o.occupancy_id desc
     limit 1',
    p_schema_name
  )
  into v_position_id
  using p_employee_id;

  execute format(
    'update %I.wcm_employee_service_state
     set position_id = $1,
         updated_at = timezone(''utc'', now())
     where employee_id = $2',
    p_schema_name
  )
  using v_position_id, p_employee_id;
end;
$function$
;

