CREATE OR REPLACE FUNCTION public.platform_hierarchy_try_date(p_value text)
 RETURNS date
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
begin
  if nullif(btrim(coalesce(p_value, '')), '') is null then
    return null;
  end if;

  return p_value::date;
exception
  when others then
    return null;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_ingest_ams_bio_external_batch(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context jsonb := public.platform_ams_bio_resolve_context(p_params);
  v_schema_name text;
  v_items jsonb := coalesce(p_params->'items', '[]'::jsonb);
  v_item jsonb;
  v_inserted integer := 0;
  v_raw_id bigint;
begin
  if coalesce((v_context->>'success')::boolean, false) is not true then return v_context; end if;
  v_schema_name := v_context->'details'->>'tenant_schema';
  if jsonb_typeof(v_items) <> 'array' then return public.platform_json_response(false,'ITEMS_ARRAY_REQUIRED','items must be an array.','{}'::jsonb); end if;

  for v_item in select value from jsonb_array_elements(v_items)
  loop
    if nullif(btrim(coalesce(v_item->>'idempotency_key', '')), '') is not null then
      execute format('select raw_punch_log_id from %I.ams_bio_raw_punch_log where idempotency_key = $1', v_schema_name)
      into v_raw_id
      using v_item->>'idempotency_key';
      if v_raw_id is not null then
        continue;
      end if;
    end if;

    execute format(
      'insert into %I.ams_bio_raw_punch_log (connector_id, device_id, external_punch_id, external_employee_code, event_ts, punch_direction, raw_payload, ingest_status, idempotency_key)
       values ($1,$2,$3,$4,$5,$6,coalesce($7,''{}''::jsonb),''received'',$8)
       returning raw_punch_log_id',
      v_schema_name
    ) into v_raw_id using public.platform_try_uuid(v_item->>'connector_id'), public.platform_try_uuid(v_item->>'device_id'), nullif(btrim(coalesce(v_item->>'external_punch_id', '')), ''), nullif(btrim(coalesce(v_item->>'external_employee_code', '')), ''), public.platform_ams_bio_try_timestamptz(v_item->>'event_ts', coalesce(v_item->'parse_options', '{}'::jsonb)), v_item->>'punch_direction', coalesce(v_item->'raw_payload', v_item, '{}'::jsonb), nullif(btrim(coalesce(v_item->>'idempotency_key', '')), '');
    v_inserted := v_inserted + 1;
  end loop;

  return public.platform_json_response(true,'OK','BIO external batch ingested.',jsonb_build_object('inserted_count', v_inserted));
exception when others then
  return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_ingest_ams_bio_external_batch.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_init_ams_bio_import_session(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context jsonb := public.platform_ams_bio_resolve_context(p_params);
  v_schema_name text;
  v_session_id uuid := public.platform_try_uuid(p_params->>'import_session_id');
  v_source_profile_id uuid := public.platform_try_uuid(p_params->>'source_profile_id');
  v_mapping_profile_id uuid := public.platform_try_uuid(p_params->>'mapping_profile_id');
  v_actor_user_id uuid;
  v_result record;
begin
  if coalesce((v_context->>'success')::boolean, false) is not true then return v_context; end if;
  v_schema_name := v_context->'details'->>'tenant_schema';
  v_actor_user_id := public.platform_try_uuid(v_context->'details'->>'actor_user_id');
  if v_source_profile_id is null then return public.platform_json_response(false,'SOURCE_PROFILE_ID_REQUIRED','source_profile_id is required.','{}'::jsonb); end if;

  execute format(
    'insert into %I.ams_bio_import_session (import_session_id, source_profile_id, mapping_profile_id, session_code, import_mode, session_purpose, session_status, upload_filename, upload_content_type, source_document_id, import_window, source_request, session_scope, preview_snapshot, import_summary, created_by, updated_by)
     values (coalesce($1, gen_random_uuid()), $2, $3, $4, $5, coalesce($6,''sample''), ''initialized'', $7, $8, $9, coalesce($10,''{}''::jsonb), coalesce($11,''{}''::jsonb), coalesce($12,''{}''::jsonb), ''{}''::jsonb, ''{}''::jsonb, $13, $13)
     on conflict (import_session_id) do update
     set source_profile_id = excluded.source_profile_id,
         mapping_profile_id = excluded.mapping_profile_id,
         session_code = excluded.session_code,
         import_mode = excluded.import_mode,
         session_purpose = excluded.session_purpose,
         upload_filename = excluded.upload_filename,
         upload_content_type = excluded.upload_content_type,
         source_document_id = excluded.source_document_id,
         import_window = excluded.import_window,
         source_request = excluded.source_request,
         session_scope = excluded.session_scope,
         updated_by = excluded.updated_by,
         updated_at = timezone(''utc'', now())
     returning import_session_id, session_code, session_status',
    v_schema_name
  ) into v_result using v_session_id, v_source_profile_id, v_mapping_profile_id, nullif(btrim(coalesce(p_params->>'session_code', '')), ''), lower(nullif(btrim(coalesce(p_params->>'import_mode', '')), '')), lower(coalesce(nullif(btrim(p_params->>'session_purpose'), ''), 'sample')), nullif(btrim(coalesce(p_params->>'upload_filename', '')), ''), nullif(btrim(coalesce(p_params->>'upload_content_type', '')), ''), public.platform_try_uuid(p_params->>'source_document_id'), coalesce(p_params->'import_window', '{}'::jsonb), coalesce(p_params->'source_request', '{}'::jsonb), coalesce(p_params->'session_scope', '{}'::jsonb), v_actor_user_id;

  return public.platform_json_response(true,'OK','BIO import session initialized.',jsonb_build_object('import_session_id', v_result.import_session_id,'session_code', v_result.session_code,'session_status', v_result.session_status));
exception when others then
  return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_init_ams_bio_import_session.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_launch_eoap_workflow(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context_result jsonb;
  v_schema_name text;
  v_pending_hire_id uuid := public.platform_try_uuid(p_params->>'pending_hire_id');
  v_workflow_template_id uuid := public.platform_try_uuid(p_params->>'workflow_template_id');
  v_template_code text := nullif(lower(btrim(coalesce(p_params->>'workflow_template_code', ''))), '');
  v_workflow_id uuid := gen_random_uuid();
  v_employee_id uuid;
  v_conversion_case_id uuid;
  v_target_position_id bigint;
  v_current_step_code text;
  v_inserted_step_count integer := 0;
  v_audit_result jsonb;
begin
  v_context_result := public.platform_eoap_resolve_context(p_params);
  if coalesce((v_context_result->>'success')::boolean, false) is not true then return v_context_result; end if;
  v_schema_name := nullif(coalesce(v_context_result->'details'->>'tenant_schema', ''), '');
  if v_pending_hire_id is null then return public.platform_json_response(false,'PENDING_HIRE_ID_REQUIRED','pending_hire_id is required.','{}'::jsonb); end if;
  execute format('select employee_id, conversion_case_id, target_position_id from %I.eoap_pending_hire where pending_hire_id = $1', v_schema_name) into v_employee_id, v_conversion_case_id, v_target_position_id using v_pending_hire_id;
  if v_employee_id is null then return public.platform_json_response(false,'PENDING_HIRE_NOT_FOUND','Pending hire not found.','{}'::jsonb); end if;
  if v_workflow_template_id is null and v_template_code is not null then execute format('select workflow_template_id from %I.eoap_workflow_template where lower(workflow_template_code) = $1 and template_status = ''active'' limit 1', v_schema_name) into v_workflow_template_id using v_template_code; end if;
  if v_workflow_template_id is null then return public.platform_json_response(false,'WORKFLOW_TEMPLATE_ID_REQUIRED','workflow_template_id or workflow_template_code is required.','{}'::jsonb); end if;
  execute format('insert into %I.eoap_workflow (workflow_id, pending_hire_id, employee_id, workflow_template_id, conversion_case_id, target_position_id, workflow_status, workflow_metadata) values ($1,$2,$3,$4,$5,$6,''active'',coalesce($7,''{}''::jsonb))', v_schema_name) using v_workflow_id, v_pending_hire_id, v_employee_id, v_workflow_template_id, v_conversion_case_id, v_target_position_id, p_params->'workflow_metadata';
  execute format('insert into %I.eoap_workflow_step (workflow_id, workflow_template_step_id, step_code, step_name, step_type, step_sequence, is_required, review_required, dependency_step_codes, step_status, assigned_role_code, due_on, step_metadata) select $1, workflow_template_step_id, step_code, step_name, step_type, step_sequence, is_required, review_required, dependency_step_codes, case when coalesce(array_length(dependency_step_codes,1),0)=0 then ''ready'' else ''pending'' end, assigned_role_code, case when due_offset_days is null then null else current_date + due_offset_days end, step_metadata from %I.eoap_workflow_template_step where workflow_template_id = $2 order by step_sequence', v_schema_name, v_schema_name) using v_workflow_id, v_workflow_template_id;
  get diagnostics v_inserted_step_count = row_count;
  if v_inserted_step_count = 0 then return public.platform_json_response(false,'WORKFLOW_TEMPLATE_HAS_NO_STEPS','At least one workflow template step is required before launch.',jsonb_build_object('workflow_template_id', v_workflow_template_id)); end if;
  execute format('select step_code from %I.eoap_workflow_step where workflow_id=$1 and step_status in (''ready'',''in_progress'',''pending'',''on_hold'') order by case step_status when ''ready'' then 1 when ''in_progress'' then 2 when ''pending'' then 3 else 4 end, step_sequence limit 1', v_schema_name) into v_current_step_code using v_workflow_id;
  execute format('update %I.eoap_workflow set current_step_code = $1, updated_at = timezone(''utc'', now()) where workflow_id = $2', v_schema_name) using v_current_step_code, v_workflow_id;
  execute format('update %I.eoap_pending_hire set readiness_status = ''in_progress'', updated_at = timezone(''utc'', now()) where pending_hire_id = $1', v_schema_name) using v_pending_hire_id;
  v_audit_result := public.platform_log_eoap_audit_event(jsonb_build_object('tenant_id', public.platform_try_uuid(v_context_result->'details'->>'tenant_id'),'pending_hire_id', v_pending_hire_id,'workflow_id', v_workflow_id,'event_type', 'workflow_launched','event_details', jsonb_build_object('workflow_template_id', v_workflow_template_id,'current_step_code', v_current_step_code,'inserted_step_count', v_inserted_step_count)));
  if coalesce((v_audit_result->>'success')::boolean, false) is not true then return v_audit_result; end if;
  return public.platform_json_response(true,'OK','EOAP workflow launched.',jsonb_build_object('workflow_id', v_workflow_id,'pending_hire_id', v_pending_hire_id,'current_step_code', v_current_step_code,'inserted_step_count', v_inserted_step_count));
exception when others then return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_launch_eoap_workflow.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm)); end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_lms_append_balance_ledger_internal(p_schema_name text, p_employee_id uuid, p_leave_type_id uuid, p_leave_policy_id uuid, p_transaction_type text, p_quantity_delta numeric, p_effective_on date, p_expiry_on date, p_reference_request_id uuid, p_reference_code text, p_reference_metadata jsonb, p_actor_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_running_balance numeric;
  v_balance_ledger_id bigint;
begin
  if coalesce(p_quantity_delta, 0) = 0 then
    return public.platform_json_response(false,'LEDGER_QUANTITY_REQUIRED','quantity_delta must be non-zero.','{}'::jsonb);
  end if;

  v_running_balance := public.platform_lms_current_balance_internal(p_schema_name, p_employee_id, p_leave_type_id, p_effective_on) + p_quantity_delta;

  execute format(
    'insert into %I.lms_leave_balance_ledger (employee_id, leave_type_id, leave_policy_id, transaction_type, quantity_delta, effective_on, expiry_on, reference_request_id, reference_code, reference_metadata, running_balance, actor_user_id) values ($1,$2,$3,$4,$5,$6,$7,$8,$9,coalesce($10,''{}''::jsonb),$11,$12) returning balance_ledger_id',
    p_schema_name
  )
  into v_balance_ledger_id
  using p_employee_id, p_leave_type_id, p_leave_policy_id, upper(p_transaction_type), p_quantity_delta, coalesce(p_effective_on, current_date), p_expiry_on, p_reference_request_id, p_reference_code, p_reference_metadata, v_running_balance, p_actor_user_id;

  return public.platform_json_response(true,'OK','LMS balance ledger entry recorded.',jsonb_build_object('balance_ledger_id', v_balance_ledger_id,'running_balance', v_running_balance));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_lms_build_approval_chain_internal(p_tenant_id uuid, p_employee_id uuid, p_position_id bigint, p_policy_rules jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_levels integer := greatest(0, coalesce((p_policy_rules #>> '{approval_workflow,levels}')::integer, case when coalesce((p_policy_rules #>> '{approval_workflow,requires_approval}')::boolean, true) then 1 else 0 end));
  v_explicit_positions bigint[] := public.platform_lms_jsonb_bigint_array(p_policy_rules #> '{approval_workflow,approver_position_ids}');
  v_chain jsonb := '[]'::jsonb;
  v_index integer := 1;
  v_current_position_id bigint := p_position_id;
  v_position_id bigint;
  v_manager_result jsonb;
  v_details jsonb;
begin
  if v_levels <= 0 then
    return '[]'::jsonb;
  end if;

  if array_length(v_explicit_positions, 1) is not null then
    foreach v_position_id in array v_explicit_positions loop
      exit when v_index > v_levels;
      v_manager_result := public.platform_get_hierarchy_operational_occupant(jsonb_build_object('tenant_id', p_tenant_id,'position_id', v_position_id,'source', 'platform_lms_build_approval_chain_internal'));
      v_details := coalesce(v_manager_result->'details', '{}'::jsonb);
      v_chain := v_chain || jsonb_build_array(jsonb_build_object('approval_level', v_index,'approver_position_id', v_position_id,'approver_actor_user_id', public.platform_try_uuid(v_details->>'actor_user_id'),'approver_employee_id', public.platform_try_uuid(v_details->>'employee_id'),'delegation_position_id', null,'resolution_mode', 'explicit_position'));
      v_index := v_index + 1;
    end loop;

    return v_chain;
  end if;

  while v_index <= v_levels loop
    v_manager_result := public.platform_get_hierarchy_manager_resolution(jsonb_build_object('tenant_id', p_tenant_id,'position_id', v_current_position_id,'employee_id', p_employee_id,'source', 'platform_lms_build_approval_chain_internal'));
    if coalesce((v_manager_result->>'success')::boolean, false) is not true then exit; end if;
    v_details := coalesce(v_manager_result->'details', '{}'::jsonb);
    v_position_id := public.platform_hierarchy_try_bigint(v_details->>'manager_position_id');
    if v_position_id is null then exit; end if;
    v_chain := v_chain || jsonb_build_array(jsonb_build_object('approval_level', v_index,'approver_position_id', v_position_id,'approver_actor_user_id', public.platform_try_uuid(v_details->>'manager_actor_user_id'),'approver_employee_id', public.platform_try_uuid(v_details->>'manager_employee_id'),'delegation_position_id', null,'resolution_mode', 'hierarchy_manager'));
    v_current_position_id := v_position_id;
    v_index := v_index + 1;
  end loop;

  return v_chain;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_lms_calculate_duration_internal(p_schema_name text, p_start_date date, p_end_date date, p_request_session text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_configuration jsonb := public.platform_lms_get_effective_configuration(p_schema_name);
  v_weekend_days integer[] := coalesce(public.platform_lms_jsonb_bigint_array(v_configuration #> '{general,weekend_weekdays}')::integer[], public.platform_lms_jsonb_bigint_array(v_configuration #> '{general,weekend_days}')::integer[]);
  v_holiday_dates text[] := public.platform_lms_jsonb_text_array(v_configuration #> '{general,holiday_dates}');
  v_calendar_days numeric := 0;
  v_working_days numeric := 0;
  v_day date;
  v_session text := lower(coalesce(nullif(btrim(p_request_session), ''), 'full_day'));
  v_excluded_days integer := 0;
begin
  if p_start_date is null or p_end_date is null then
    return public.platform_json_response(false,'REQUEST_DATES_REQUIRED','request_start_date and request_end_date are required.','{}'::jsonb);
  end if;

  if p_end_date < p_start_date then
    return public.platform_json_response(false,'INVALID_DATE_RANGE','request_end_date must be on or after request_start_date.','{}'::jsonb);
  end if;

  if v_session not in ('full_day', 'first_half', 'second_half') then
    return public.platform_json_response(false,'INVALID_REQUEST_SESSION','request_session is invalid.','{}'::jsonb);
  end if;

  if array_length(v_weekend_days, 1) is null then
    v_weekend_days := array[0, 6];
  end if;

  if v_session in ('first_half', 'second_half') and p_start_date <> p_end_date then
    return public.platform_json_response(false,'HALF_DAY_SINGLE_DATE_REQUIRED','Half-day leave must use the same start and end date.','{}'::jsonb);
  end if;

  v_calendar_days := (p_end_date - p_start_date + 1)::numeric;

  for v_day in select generate_series(p_start_date, p_end_date, interval '1 day')::date
  loop
    if extract(dow from v_day)::integer = any(v_weekend_days)
       or v_day::text = any(v_holiday_dates)
    then
      v_excluded_days := v_excluded_days + 1;
    else
      v_working_days := v_working_days + 1;
    end if;
  end loop;

  if v_session in ('first_half', 'second_half') then
    if v_working_days > 0 then
      v_working_days := 0.5;
    else
      v_working_days := 0;
    end if;
  end if;

  return public.platform_json_response(true,'OK','LMS duration calculated.',jsonb_build_object('calendar_days', v_calendar_days,'working_days', v_working_days,'excluded_days', v_excluded_days,'request_session', v_session));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_lms_current_balance_internal(p_schema_name text, p_employee_id uuid, p_leave_type_id uuid, p_as_of date DEFAULT NULL::date)
 RETURNS numeric
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_balance numeric;
begin
  execute format(
    'select coalesce(sum(quantity_delta), 0)
     from %I.lms_leave_balance_ledger
     where employee_id = $1
       and leave_type_id = $2
       and effective_on <= coalesce($3, current_date)',
    p_schema_name
  )
  into v_balance
  using p_employee_id, p_leave_type_id, p_as_of;

  return coalesce(v_balance, 0);
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_lms_employee_balance_summary_rows()
 RETURNS TABLE(tenant_id uuid, employee_id uuid, employee_code text, employee_name text, position_id bigint, leave_type_id uuid, leave_type_code text, leave_type_name text, current_balance numeric, accrued_quantity numeric, debited_quantity numeric, reversed_quantity numeric, lapsed_quantity numeric, last_transaction_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_tenant_id uuid := public.platform_current_tenant_id();
  v_schema_name text := public.platform_current_tenant_schema();
begin
  if v_tenant_id is null or v_schema_name is null or not public.platform_table_exists(v_schema_name, 'lms_leave_balance_ledger') then return; end if;
  return query execute format(
    'select
       $1::uuid as tenant_id,
       e.employee_id,
       e.employee_code,
       concat_ws('' '', e.first_name, e.middle_name, e.last_name) as employee_name,
       s.position_id,
       t.leave_type_id,
       t.leave_type_code,
       t.leave_type_name,
       coalesce(sum(l.quantity_delta), 0)::numeric as current_balance,
       coalesce(sum(case when l.transaction_type in (''ACCRUAL'',''JOINING_CREDIT'',''PRORATE_ADJUSTMENT'',''BONUS_ALLOCATION'',''EMERGENCY_GRANT'') then l.quantity_delta else 0 end), 0)::numeric as accrued_quantity,
       coalesce(sum(case when l.transaction_type = ''DEBIT_REQUEST'' then abs(l.quantity_delta) else 0 end), 0)::numeric as debited_quantity,
       coalesce(sum(case when l.transaction_type = ''CREDIT_REVERSAL'' then l.quantity_delta else 0 end), 0)::numeric as reversed_quantity,
       coalesce(sum(case when l.transaction_type = ''LAPSE'' then abs(l.quantity_delta) else 0 end), 0)::numeric as lapsed_quantity,
       max(l.created_at) as last_transaction_at
     from %1$I.lms_leave_balance_ledger l
     join %1$I.wcm_employee e on e.employee_id = l.employee_id
     join %1$I.wcm_employee_service_state s on s.employee_id = e.employee_id
     join %1$I.lms_leave_type t on t.leave_type_id = l.leave_type_id
     group by e.employee_id, e.employee_code, e.first_name, e.middle_name, e.last_name, s.position_id, t.leave_type_id, t.leave_type_code, t.leave_type_name
     order by e.employee_code, t.leave_type_code',
    v_schema_name
  ) using v_tenant_id;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_lms_get_effective_configuration(p_schema_name text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_configuration jsonb;
begin
  execute format(
    'select configuration
     from %I.lms_tenant_configuration
     where configuration_status = ''active''
       and effective_from <= current_date
       and coalesce(effective_to, date ''9999-12-31'') >= current_date
     order by effective_from desc, created_at desc
     limit 1',
    p_schema_name
  )
  into v_configuration;

  return coalesce(v_configuration, '{}'::jsonb);
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_lms_jsonb_bigint_array(p_value jsonb)
 RETURNS bigint[]
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_result bigint[] := '{}'::bigint[];
  v_value text;
begin
  if p_value is null or p_value = 'null'::jsonb or jsonb_typeof(p_value) <> 'array' then
    return '{}'::bigint[];
  end if;

  for v_value in select value from jsonb_array_elements_text(p_value)
  loop
    begin
      if nullif(btrim(v_value), '') is not null then
        v_result := array_append(v_result, v_value::bigint);
      end if;
    exception
      when others then
        null;
    end;
  end loop;

  return coalesce(v_result, '{}'::bigint[]);
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_lms_jsonb_text_array(p_value jsonb)
 RETURNS text[]
 LANGUAGE sql
 IMMUTABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
  select
    case
      when p_value is null or p_value = 'null'::jsonb then '{}'::text[]
      when jsonb_typeof(p_value) <> 'array' then '{}'::text[]
      else coalesce((
        select array_agg(btrim(v)) filter (where nullif(btrim(v), '') is not null)
        from jsonb_array_elements_text(p_value) as t(v)
      ), '{}'::text[])
    end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_lms_leave_history_rows()
 RETURNS TABLE(tenant_id uuid, leave_request_id uuid, employee_id uuid, employee_code text, employee_name text, position_id bigint, leave_type_id uuid, leave_type_code text, leave_type_name text, leave_policy_id uuid, leave_policy_code text, request_status text, request_start_date date, request_end_date date, request_session text, request_days_working numeric, request_days_calendar numeric, current_approver_position_id bigint, current_approver_actor_user_id uuid, created_at timestamp with time zone, approved_at timestamp with time zone, cancelled_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_tenant_id uuid := public.platform_current_tenant_id();
  v_schema_name text := public.platform_current_tenant_schema();
begin
  if v_tenant_id is null or v_schema_name is null or not public.platform_table_exists(v_schema_name, 'lms_leave_request') then return; end if;
  return query execute format(
    'select
       $1::uuid as tenant_id,
       r.leave_request_id,
       e.employee_id,
       e.employee_code,
       concat_ws('' '', e.first_name, e.middle_name, e.last_name) as employee_name,
       s.position_id,
       t.leave_type_id,
       t.leave_type_code,
       t.leave_type_name,
       p.leave_policy_id,
       p.leave_policy_code,
       r.request_status,
       r.request_start_date,
       r.request_end_date,
       r.request_session,
       r.request_days_working,
       r.request_days_calendar,
       r.current_approver_position_id,
       r.current_approver_actor_user_id,
       r.created_at,
       r.approved_at,
       r.cancelled_at
     from %1$I.lms_leave_request r
     join %1$I.wcm_employee e on e.employee_id = r.employee_id
     join %1$I.wcm_employee_service_state s on s.employee_id = e.employee_id
     join %1$I.lms_leave_type t on t.leave_type_id = r.leave_type_id
     left join %1$I.lms_leave_policy p on p.leave_policy_id = r.leave_policy_id
     order by r.created_at desc, r.leave_request_id desc',
    v_schema_name
  ) using v_tenant_id;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_lms_leave_year_start(p_policy_rules jsonb, p_as_of date)
 RETURNS date
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_as_of date := coalesce(p_as_of, current_date);
  v_start_month integer := greatest(1, least(12, coalesce((p_policy_rules #>> '{year_end_processing,leave_year_start_month}')::integer, 1)));
  v_year integer;
begin
  if extract(month from v_as_of)::integer >= v_start_month then
    v_year := extract(year from v_as_of)::integer;
  else
    v_year := extract(year from v_as_of)::integer - 1;
  end if;

  return make_date(v_year, v_start_month, 1);
exception
  when others then
    return make_date(extract(year from coalesce(p_as_of, current_date))::integer, 1, 1);
end;
$function$
;

