CREATE OR REPLACE FUNCTION public.platform_lms_policy_catalog_rows()
 RETURNS TABLE(tenant_id uuid, leave_type_id uuid, leave_type_code text, leave_type_name text, leave_policy_id uuid, leave_policy_code text, leave_policy_name text, policy_status text, effective_from date, effective_to date, requires_approval boolean, assignment_count integer, created_at timestamp with time zone, updated_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_tenant_id uuid := public.platform_current_tenant_id();
  v_schema_name text := public.platform_current_tenant_schema();
begin
  if v_tenant_id is null or v_schema_name is null or not public.platform_table_exists(v_schema_name, 'lms_leave_policy') then return; end if;
  return query execute format(
    'select $1::uuid as tenant_id, t.leave_type_id, t.leave_type_code, t.leave_type_name, p.leave_policy_id, p.leave_policy_code, p.leave_policy_name, p.policy_status, p.effective_from, p.effective_to, t.requires_approval, coalesce(a.assignment_count, 0)::integer, p.created_at, p.updated_at
     from %1$I.lms_leave_policy p
     join %1$I.lms_leave_type t on t.leave_type_id = p.leave_type_id
