;

CREATE OR REPLACE FUNCTION public.platform_lms_resolve_context(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_params jsonb := coalesce(p_params, '{}'::jsonb);
  v_requested_tenant_id uuid := public.platform_resolve_tenant_id(v_params);
  v_current_tenant_id uuid := public.platform_current_tenant_id();
  v_current_schema text := public.platform_current_tenant_schema();
  v_context_result jsonb;
  v_details jsonb;
begin
  if v_current_tenant_id is not null and v_current_schema is not null then
    if v_requested_tenant_id is not null and v_requested_tenant_id <> v_current_tenant_id then
      return public.platform_json_response(false,'CONTEXT_TENANT_MISMATCH','The requested tenant does not match the current execution context.',jsonb_build_object('requested_tenant_id', v_requested_tenant_id,'current_tenant_id', v_current_tenant_id));
    end if;

    if not public.platform_table_exists(v_current_schema, 'wcm_employee')
      or not public.platform_table_exists(v_current_schema, 'wcm_employee_service_state')
      or not public.platform_table_exists(v_current_schema, 'hierarchy_position')
      or not public.platform_table_exists(v_current_schema, 'eoap_pending_hire')
      or not public.platform_table_exists(v_current_schema, 'lms_leave_type')
      or not public.platform_table_exists(v_current_schema, 'lms_leave_policy')
      or not public.platform_table_exists(v_current_schema, 'lms_policy_assignment')
      or not public.platform_table_exists(v_current_schema, 'lms_leave_request')
      or not public.platform_table_exists(v_current_schema, 'lms_leave_approval_history')
      or not public.platform_table_exists(v_current_schema, 'lms_leave_balance_ledger')
      or not public.platform_table_exists(v_current_schema, 'lms_ledger_consumption')
    then
      return public.platform_json_response(false,'LMS_TEMPLATE_NOT_APPLIED','LMS is not applied to the current tenant schema.',jsonb_build_object('tenant_id', v_current_tenant_id,'tenant_schema', v_current_schema));
    end if;

    return public.platform_json_response(true,'OK','LMS execution context resolved.',jsonb_build_object('tenant_id', v_current_tenant_id,'tenant_schema', v_current_schema,'actor_user_id', public.platform_current_actor_user_id()));
  end if;

  if not public.platform_is_internal_caller() then
    return public.platform_json_response(false,'TENANT_CONTEXT_REQUIRED','An applied tenant execution context is required.','{}'::jsonb);
  end if;

  if v_requested_tenant_id is null then
    return public.platform_json_response(false,'TENANT_ID_REQUIRED','tenant_id or tenant_code is required when no execution context is active.','{}'::jsonb);
  end if;

  v_context_result := public.platform_apply_execution_context(jsonb_build_object(
    'execution_mode', 'internal_platform',
    'tenant_id', v_requested_tenant_id,
    'source', coalesce(nullif(btrim(v_params->>'source'), ''), 'platform_lms_resolve_context')
  ));

  if coalesce((v_context_result->>'success')::boolean, false) is not true then
    return v_context_result;
  end if;

  v_details := coalesce(v_context_result->'details', '{}'::jsonb);

  return public.platform_json_response(true,'OK','LMS execution context resolved.',jsonb_build_object('tenant_id', public.platform_try_uuid(v_details->>'tenant_id'),'tenant_schema', v_details->>'tenant_schema','actor_user_id', public.platform_current_actor_user_id()));
exception
  when others then
    return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_lms_resolve_context.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_lms_resolve_policy_assignment_internal(p_schema_name text, p_employee_id uuid, p_position_id bigint, p_employment_status text, p_service_state text, p_leave_type_id uuid, p_as_of date)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_row record;
  v_policy_count integer := 0;
begin
  execute format(
    'select
       a.policy_assignment_id,
       a.leave_policy_id,
       a.assignment_scope,
       a.assignment_priority,
       p.leave_policy_code,
       p.leave_policy_name,
       p.policy_rules,
       p.automation_rules,
       p.compliance_rules
     from %1$I.lms_policy_assignment a
     join %1$I.lms_leave_policy p
       on p.leave_policy_id = a.leave_policy_id
     where p.leave_type_id = $1
       and p.policy_status = ''active''
       and a.assignment_status = ''active''
       and coalesce(a.effective_from, date ''1900-01-01'') <= coalesce($6, current_date)
       and coalesce(a.effective_to, date ''9999-12-31'') >= coalesce($6, current_date)
       and (
         (a.assignment_scope = ''employee'' and a.employee_id = $2)
         or (a.assignment_scope = ''position'' and a.position_id = $3)
         or (a.assignment_scope = ''employment_status'' and lower(coalesce(a.employment_status, '''')) = lower(coalesce($4, '''')))
         or (a.assignment_scope = ''service_state'' and lower(coalesce(a.service_state, '''')) = lower(coalesce($5, '''')))
         or a.assignment_scope = ''all_employee''
       )
     order by
       case a.assignment_scope
         when ''employee'' then 1
         when ''position'' then 2
         when ''employment_status'' then 3
         when ''service_state'' then 4
         when ''criteria'' then 5
         else 6
       end,
       a.assignment_priority asc,
       coalesce(a.effective_from, date ''1900-01-01'') desc,
       a.created_at desc
     limit 1',
    p_schema_name
  )
  into v_row
  using p_leave_type_id, p_employee_id, p_position_id, p_employment_status, p_service_state, p_as_of;

  if v_row.leave_policy_id is null then
    execute format(
      'select count(*)
       from %I.lms_leave_policy
       where leave_type_id = $1
         and policy_status = ''active''
         and effective_from <= coalesce($2, current_date)
         and coalesce(effective_to, date ''9999-12-31'') >= coalesce($2, current_date)',
      p_schema_name
    )
    into v_policy_count
    using p_leave_type_id, p_as_of;

    if v_policy_count = 1 then
      execute format(
        'select
           null::uuid as policy_assignment_id,
           p.leave_policy_id,
           ''all_employee''::text as assignment_scope,
           9999::integer as assignment_priority,
           p.leave_policy_code,
           p.leave_policy_name,
           p.policy_rules,
           p.automation_rules,
           p.compliance_rules
         from %I.lms_leave_policy p
         where p.leave_type_id = $1
           and p.policy_status = ''active''
           and p.effective_from <= coalesce($2, current_date)
           and coalesce(p.effective_to, date ''9999-12-31'') >= coalesce($2, current_date)
         limit 1',
        p_schema_name
      )
      into v_row
      using p_leave_type_id, p_as_of;
    end if;
  end if;

  if v_row.leave_policy_id is null then
    return public.platform_json_response(false,'LEAVE_POLICY_NOT_RESOLVED','No effective leave policy assignment was resolved for the employee and leave type.',jsonb_build_object('employee_id', p_employee_id,'leave_type_id', p_leave_type_id));
  end if;

  return public.platform_json_response(true,'OK','LMS policy assignment resolved.',jsonb_build_object(
    'policy_assignment_id', v_row.policy_assignment_id,
    'leave_policy_id', v_row.leave_policy_id,
    'leave_policy_code', v_row.leave_policy_code,
    'leave_policy_name', v_row.leave_policy_name,
    'assignment_scope', v_row.assignment_scope,
    'assignment_priority', v_row.assignment_priority,
    'policy_rules', coalesce(v_row.policy_rules, '{}'::jsonb),
    'automation_rules', coalesce(v_row.automation_rules, '{}'::jsonb),
    'compliance_rules', coalesce(v_row.compliance_rules, '{}'::jsonb)
  ));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_lms_resolve_subject_context_internal(p_schema_name text, p_employee_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_row record;
begin
  execute format(
    'select
       e.employee_id,
       e.employee_code,
       e.first_name,
       e.middle_name,
       e.last_name,
       e.actor_user_id,
       s.service_state,
       s.employment_status,
       s.joining_date,
       s.position_id,
       s.last_billable
     from %I.wcm_employee e
     join %I.wcm_employee_service_state s
       on s.employee_id = e.employee_id
     where e.employee_id = $1',
    p_schema_name,
    p_schema_name
  )
  into v_row
  using p_employee_id;

  if v_row.employee_id is null then
    return public.platform_json_response(false,'EMPLOYEE_NOT_FOUND','Employee not found in WCM_CORE.','{}'::jsonb);
  end if;

  return public.platform_json_response(true,'OK','LMS subject context resolved.',jsonb_build_object(
    'employee_id', v_row.employee_id,
    'employee_code', v_row.employee_code,
    'employee_name', concat_ws(' ', v_row.first_name, v_row.middle_name, v_row.last_name),
    'actor_user_id', v_row.actor_user_id,
    'service_state', v_row.service_state,
    'employment_status', v_row.employment_status,
    'joining_date', v_row.joining_date,
    'position_id', v_row.position_id,
    'last_billable', v_row.last_billable
  ));
end;
$function$
;

