  v_source_name text := nullif(btrim(coalesce(p_params->>'source_name', '')), '');
  v_source_mode text := lower(nullif(btrim(coalesce(p_params->>'source_mode', '')), ''));
  v_vendor_name text := nullif(btrim(coalesce(p_params->>'vendor_name', '')), '');
  v_source_status text := lower(coalesce(nullif(btrim(p_params->>'source_status'), ''), 'draft'));
  v_guardrail text := lower(coalesce(nullif(btrim(p_params->>'onboarding_guardrail_mode'), ''), 'guided'));
