  execute format(
    'insert into %I.ams_bio_source_profile (source_profile_id, source_code, source_name, source_mode, vendor_name, source_status, onboarding_guardrail_mode, connection_profile, import_profile, source_metadata, created_by, updated_by)
     values (coalesce($1, gen_random_uuid()), $2, $3, $4, $5, $6, $7, coalesce($8,''{}''::jsonb), coalesce($9,''{}''::jsonb), coalesce($10,''{}''::jsonb), $11, $11)
