  ) into v_result using v_source_profile_id, v_source_code, v_source_name, v_source_mode, v_vendor_name, v_source_status, v_guardrail, coalesce(p_params->'connection_profile', '{}'::jsonb), coalesce(p_params->'import_profile', '{}'::jsonb), coalesce(p_params->'source_metadata', '{}'::jsonb), v_actor_user_id;

  execute format(
    'insert into %I.ams_bio_source_onboarding_state (source_profile_id, onboarding_status, current_step_code, completion_flags, step_state, recommendation_snapshot, validation_snapshot, created_by, updated_by)
     values ($1, ''draft'', null, ''{}''::jsonb, ''{}''::jsonb, ''{}''::jsonb, ''{}''::jsonb, $2, $2)
     on conflict (source_profile_id) do nothing',
    v_schema_name
  ) using v_result.source_profile_id, v_actor_user_id;

  return public.platform_json_response(true,'OK','BIO source profile saved.',jsonb_build_object('source_profile_id', v_result.source_profile_id,'source_code', v_result.source_code,'source_status', v_result.source_status));
exception when others then
  return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_register_ams_bio_source_profile.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_register_ams_configuration(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context_result jsonb;
  v_schema_name text;
  v_configuration_id uuid := public.platform_try_uuid(p_params->>'ams_configuration_id');
begin
  v_context_result := public.platform_ams_resolve_context(p_params);
  if coalesce((v_context_result->>'success')::boolean, false) is not true then return v_context_result; end if;
