  v_context_result := public.platform_eoap_resolve_context(p_params); if coalesce((v_context_result->>'success')::boolean, false) is not true then return v_context_result; end if; v_schema_name := nullif(coalesce(v_context_result->'details'->>'tenant_schema', ''), '');
  if v_template_code is null or v_template_name is null then return public.platform_json_response(false,'WORKFLOW_TEMPLATE_INPUTS_REQUIRED','workflow_template_code and workflow_template_name are required.','{}'::jsonb); end if;
  if v_workflow_template_id is null then execute format('insert into %I.eoap_workflow_template (workflow_template_code, workflow_template_name, entry_mode, template_status, default_position_id, template_metadata) values ($1,$2,coalesce($3,''recruitment_conversion''),coalesce($4,''active''),$5,coalesce($6,''{}''::jsonb)) returning workflow_template_id', v_schema_name) into v_workflow_template_id using v_template_code, v_template_name, p_params->>'entry_mode', p_params->>'template_status', public.platform_hierarchy_try_bigint(p_params->>'default_position_id'), p_params->'template_metadata'; else execute format('update %I.eoap_workflow_template set workflow_template_code=$1, workflow_template_name=$2, entry_mode=coalesce($3, entry_mode), template_status=coalesce($4, template_status), default_position_id=coalesce($5, default_position_id), template_metadata=coalesce($6, template_metadata), updated_at=timezone(''utc'', now()) where workflow_template_id=$7', v_schema_name) using v_template_code, v_template_name, p_params->>'entry_mode', p_params->>'template_status', public.platform_hierarchy_try_bigint(p_params->>'default_position_id'), p_params->'template_metadata', v_workflow_template_id; end if;
  return public.platform_json_response(true,'OK','EOAP workflow template registered.',jsonb_build_object('workflow_template_id', v_workflow_template_id,'workflow_template_code', v_template_code));
exception when others then return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_register_eoap_workflow_template.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm)); end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_register_eoap_workflow_template_step(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context_result jsonb; v_schema_name text; v_workflow_template_id uuid := public.platform_try_uuid(p_params->>'workflow_template_id'); v_template_code text := nullif(lower(btrim(coalesce(p_params->>'workflow_template_code', ''))), ''); v_dep text[] := '{}'::text[];
begin
  v_context_result := public.platform_eoap_resolve_context(p_params); if coalesce((v_context_result->>'success')::boolean, false) is not true then return v_context_result; end if; v_schema_name := nullif(coalesce(v_context_result->'details'->>'tenant_schema', ''), '');
  if v_workflow_template_id is null and v_template_code is not null then execute format('select workflow_template_id from %I.eoap_workflow_template where lower(workflow_template_code) = $1 limit 1', v_schema_name) into v_workflow_template_id using v_template_code; end if;
  if v_workflow_template_id is null or nullif(lower(btrim(coalesce(p_params->>'step_code', ''))), '') is null or nullif(btrim(coalesce(p_params->>'step_name', '')), '') is null or not (p_params ? 'step_sequence') then return public.platform_json_response(false,'WORKFLOW_TEMPLATE_STEP_INPUTS_REQUIRED','workflow_template_id or workflow_template_code with step_code, step_name, and step_sequence are required.','{}'::jsonb); end if;
  if p_params ? 'dependency_step_codes' then select coalesce(array_agg(value order by ord), '{}'::text[]) into v_dep from jsonb_array_elements_text(coalesce(p_params->'dependency_step_codes', '[]'::jsonb)) with ordinality as d(value, ord); end if;
  execute format('insert into %I.eoap_workflow_template_step (workflow_template_id, step_code, step_name, step_type, step_sequence, is_required, review_required, assigned_role_code, due_offset_days, dependency_step_codes, step_metadata) values ($1,$2,$3,coalesce($4,''task''),$5,coalesce($6,true),coalesce($7,false),$8,$9,$10,coalesce($11,''{}''::jsonb)) returning workflow_template_step_id', v_schema_name)
  using v_workflow_template_id, lower(btrim(p_params->>'step_code')), btrim(p_params->>'step_name'), p_params->>'step_type', (p_params->>'step_sequence')::integer, (p_params->>'is_required')::boolean, (p_params->>'review_required')::boolean, nullif(lower(btrim(coalesce(p_params->>'assigned_role_code', ''))), ''), case when p_params ? 'due_offset_days' then (p_params->>'due_offset_days')::integer else null end, v_dep, p_params->'step_metadata';
  return public.platform_json_response(true,'OK','EOAP workflow template step registered.',jsonb_build_object('workflow_template_id', v_workflow_template_id,'step_code', lower(btrim(p_params->>'step_code'))));
exception when others then return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_register_eoap_workflow_template_step.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm)); end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_register_hierarchy_position(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context_result jsonb;
  v_context_details jsonb;
  v_schema_name text;
  v_position_id bigint := public.platform_hierarchy_try_bigint(p_params->>'position_id');
  v_input_position_code text := nullif(lower(btrim(coalesce(p_params->>'position_code', ''))), '');
  v_input_position_name text := nullif(btrim(coalesce(p_params->>'position_name', '')), '');
  v_input_position_group_id bigint := public.platform_hierarchy_try_bigint(p_params->>'position_group_id');
  v_input_reporting_position_id bigint := public.platform_hierarchy_try_bigint(p_params->>'reporting_position_id');
  v_input_position_status text := lower(coalesce(nullif(btrim(p_params->>'position_status'), ''), 'active'));
  v_input_effective_start_date date := public.platform_hierarchy_try_date(p_params->>'effective_start_date');
  v_input_effective_end_date date := public.platform_hierarchy_try_date(p_params->>'effective_end_date');
  v_existing_position_code text;
  v_existing_position_name text;
  v_existing_position_group_id bigint;
  v_existing_reporting_position_id bigint;
  v_existing_position_status text;
  v_existing_effective_start_date date;
  v_existing_effective_end_date date;
  v_duplicate_position_id bigint;
  v_path_text text;
  v_operation_kind text;
begin
  v_context_result := public.platform_hierarchy_resolve_context(p_params);
  if coalesce((v_context_result->>'success')::boolean, false) is not true then
    return v_context_result;
  end if;

  if v_input_position_status not in ('active', 'inactive', 'temporary') then
    return public.platform_json_response(false, 'INVALID_POSITION_STATUS', 'position_status must be active, inactive, or temporary.', '{}'::jsonb);
  end if;

  if v_input_effective_end_date is not null and v_input_effective_start_date is not null and v_input_effective_end_date < v_input_effective_start_date then
    return public.platform_json_response(false, 'INVALID_EFFECTIVE_DATE_RANGE', 'effective_end_date cannot be earlier than effective_start_date.', '{}'::jsonb);
  end if;

  v_context_details := coalesce(v_context_result->'details', '{}'::jsonb);
  v_schema_name := nullif(v_context_details->>'tenant_schema', '');

  if v_position_id is not null then
    execute format(
      'select position_code, position_name, position_group_id, reporting_position_id, position_status, effective_start_date, effective_end_date
       from %I.hierarchy_position
       where position_id = $1',
      v_schema_name
    )
    into v_existing_position_code, v_existing_position_name, v_existing_position_group_id, v_existing_reporting_position_id, v_existing_position_status, v_existing_effective_start_date, v_existing_effective_end_date
    using v_position_id;

    if v_existing_position_code is null then
      return public.platform_json_response(false, 'POSITION_NOT_FOUND', 'Position not found.', jsonb_build_object('position_id', v_position_id));
    end if;

    v_operation_kind := 'updated';
  else
    v_operation_kind := 'created';
  end if;

  v_input_position_code := coalesce(v_input_position_code, v_existing_position_code);
  v_input_position_name := coalesce(v_input_position_name, v_existing_position_name);
  v_input_position_group_id := coalesce(v_input_position_group_id, v_existing_position_group_id);
  v_input_reporting_position_id := coalesce(v_input_reporting_position_id, v_existing_reporting_position_id);
  v_input_position_status := coalesce(v_input_position_status, v_existing_position_status, 'active');
  v_input_effective_start_date := coalesce(v_input_effective_start_date, v_existing_effective_start_date);
  v_input_effective_end_date := coalesce(v_input_effective_end_date, v_existing_effective_end_date);

  if v_input_position_code is null then
    return public.platform_json_response(false, 'POSITION_CODE_REQUIRED', 'position_code is required.', '{}'::jsonb);
  end if;

  if v_input_position_name is null then
    return public.platform_json_response(false, 'POSITION_NAME_REQUIRED', 'position_name is required.', '{}'::jsonb);
  end if;

  if v_input_reporting_position_id is not null and v_position_id is not null and v_input_reporting_position_id = v_position_id then
    return public.platform_json_response(false, 'SELF_REPORTING_NOT_ALLOWED', 'A position cannot report to itself.', jsonb_build_object('position_id', v_position_id));
  end if;

  if v_input_position_group_id is not null then
    execute format(
      'select position_group_id from %I.hierarchy_position_group where position_group_id = $1',
      v_schema_name
    )
    into v_duplicate_position_id
    using v_input_position_group_id;

    if v_duplicate_position_id is null then
      return public.platform_json_response(false, 'POSITION_GROUP_NOT_FOUND', 'position_group_id was not found in the tenant.', jsonb_build_object('position_group_id', v_input_position_group_id));
    end if;
  end if;

  if v_input_reporting_position_id is not null then
    execute format(
      'select position_id from %I.hierarchy_position where position_id = $1',
      v_schema_name
    )
    into v_duplicate_position_id
    using v_input_reporting_position_id;

    if v_duplicate_position_id is null then
      return public.platform_json_response(false, 'REPORTING_POSITION_NOT_FOUND', 'reporting_position_id was not found in the tenant.', jsonb_build_object('reporting_position_id', v_input_reporting_position_id));
    end if;
  end if;

  execute format(
    'select position_id from %I.hierarchy_position where lower(position_code) = $1 limit 1',
    v_schema_name
  )
  into v_duplicate_position_id
  using lower(v_input_position_code);

  if v_duplicate_position_id is not null and (v_position_id is null or v_duplicate_position_id <> v_position_id) then
    return public.platform_json_response(false, 'POSITION_CODE_EXISTS', 'position_code already exists in the tenant.', jsonb_build_object('position_code', v_input_position_code));
  end if;

  if v_operation_kind = 'created' then
    execute format(
      'insert into %I.hierarchy_position (
         position_code,
         position_name,
         position_group_id,
         reporting_position_id,
         position_status,
         effective_start_date,
         effective_end_date
       ) values ($1, $2, $3, $4, $5, $6, $7)
       returning position_id, ltree2text(hierarchy_path)',
      v_schema_name
    )
    into v_position_id, v_path_text
    using v_input_position_code, v_input_position_name, v_input_position_group_id, v_input_reporting_position_id, v_input_position_status, v_input_effective_start_date, v_input_effective_end_date;
  else
    execute format(
      'update %I.hierarchy_position
       set position_code = $1,
           position_name = $2,
           position_group_id = $3,
           reporting_position_id = $4,
           position_status = $5,
           effective_start_date = $6,
           effective_end_date = $7,
           updated_at = timezone(''utc'', now())
       where position_id = $8
       returning ltree2text(hierarchy_path)',
      v_schema_name
    )
    into v_path_text
    using v_input_position_code, v_input_position_name, v_input_position_group_id, v_input_reporting_position_id, v_input_position_status, v_input_effective_start_date, v_input_effective_end_date, v_position_id;
  end if;

  return public.platform_json_response(
    true,
    'OK',
    'Hierarchy position registered.',
    jsonb_build_object(
      'tenant_id', public.platform_try_uuid(v_context_details->>'tenant_id'),
      'position_id', v_position_id,
      'operation_kind', v_operation_kind,
      'position_code', v_input_position_code,
      'position_name', v_input_position_name,
      'position_group_id', v_input_position_group_id,
      'reporting_position_id', v_input_reporting_position_id,
      'position_status', v_input_position_status,
      'hierarchy_path', v_path_text
    )
  );
exception
  when others then
    return public.platform_json_response(
      false,
      'UNEXPECTED_ERROR',
      'Unexpected error in platform_register_hierarchy_position.',
      jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm)
    );
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_register_hierarchy_position_group(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
