  v_input_group_name text := nullif(btrim(coalesce(p_params->>'position_group_name', '')), '');
  v_input_group_status text := lower(coalesce(nullif(btrim(p_params->>'group_status'), ''), 'active'));
  v_input_description text := nullif(btrim(coalesce(p_params->>'description', '')), '');
  v_existing_group_code text;
