CREATE OR REPLACE FUNCTION public.platform_register_lms_leave_policy(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context_result jsonb;
  v_schema_name text;
  v_leave_policy_id uuid := public.platform_try_uuid(p_params->>'leave_policy_id');
  v_leave_policy_code text := nullif(lower(btrim(coalesce(p_params->>'leave_policy_code', ''))), '');
  v_leave_policy_name text := nullif(btrim(coalesce(p_params->>'leave_policy_name', '')), '');
  v_leave_type_id uuid := public.platform_try_uuid(p_params->>'leave_type_id');
  v_leave_type_code text := nullif(lower(btrim(coalesce(p_params->>'leave_type_code', ''))), '');
begin
  v_context_result := public.platform_lms_resolve_context(p_params);
  if coalesce((v_context_result->>'success')::boolean, false) is not true then return v_context_result; end if;
  v_schema_name := nullif(coalesce(v_context_result->'details'->>'tenant_schema', ''), '');

  if v_leave_policy_code is null or v_leave_policy_name is null then
    return public.platform_json_response(false,'LEAVE_POLICY_INPUTS_REQUIRED','leave_policy_code and leave_policy_name are required.','{}'::jsonb);
  end if;

  if v_leave_type_id is null and v_leave_type_code is not null then
    execute format('select leave_type_id from %I.lms_leave_type where lower(leave_type_code) = $1 limit 1', v_schema_name)
    into v_leave_type_id
    using v_leave_type_code;
  end if;

  if v_leave_type_id is null then
    return public.platform_json_response(false,'LEAVE_TYPE_REQUIRED','leave_type_id or leave_type_code is required.','{}'::jsonb);
  end if;

  if v_leave_policy_id is null then
    execute format('select leave_policy_id from %I.lms_leave_policy where lower(leave_policy_code) = $1 limit 1', v_schema_name)
    into v_leave_policy_id
    using v_leave_policy_code;
  end if;

  if v_leave_policy_id is null then
    execute format('insert into %I.lms_leave_policy (leave_policy_code, leave_policy_name, leave_type_id, effective_from, effective_to, policy_status, policy_rules, automation_rules, compliance_rules, policy_metadata) values ($1,$2,$3,coalesce($4,current_date),$5,coalesce($6,''active''),coalesce($7,''{}''::jsonb),coalesce($8,''{}''::jsonb),coalesce($9,''{}''::jsonb),coalesce($10,''{}''::jsonb)) returning leave_policy_id', v_schema_name)
    into v_leave_policy_id
    using v_leave_policy_code, v_leave_policy_name, v_leave_type_id, public.platform_lms_try_date(p_params->>'effective_from'), public.platform_lms_try_date(p_params->>'effective_to'), p_params->>'policy_status', p_params->'policy_rules', p_params->'automation_rules', p_params->'compliance_rules', p_params->'policy_metadata';
  else
    execute format('update %I.lms_leave_policy set leave_policy_code = $1, leave_policy_name = $2, leave_type_id = $3, effective_from = coalesce($4, effective_from), effective_to = $5, policy_status = coalesce($6, policy_status), policy_rules = coalesce($7, policy_rules), automation_rules = coalesce($8, automation_rules), compliance_rules = coalesce($9, compliance_rules), policy_metadata = coalesce($10, policy_metadata), updated_at = timezone(''utc'', now()) where leave_policy_id = $11', v_schema_name)
    using v_leave_policy_code, v_leave_policy_name, v_leave_type_id, public.platform_lms_try_date(p_params->>'effective_from'), public.platform_lms_try_date(p_params->>'effective_to'), p_params->>'policy_status', p_params->'policy_rules', p_params->'automation_rules', p_params->'compliance_rules', p_params->'policy_metadata', v_leave_policy_id;
  end if;

  return public.platform_json_response(true,'OK','LMS leave policy recorded.',jsonb_build_object('leave_policy_id', v_leave_policy_id,'leave_policy_code', v_leave_policy_code,'leave_type_id', v_leave_type_id));
exception
  when others then
    return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_register_lms_leave_policy.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_register_lms_leave_type(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context_result jsonb;
  v_schema_name text;
  v_leave_type_id uuid := public.platform_try_uuid(p_params->>'leave_type_id');
