  v_leave_type_name text := nullif(btrim(coalesce(p_params->>'leave_type_name', '')), '');
begin
  v_context_result := public.platform_lms_resolve_context(p_params);
  if coalesce((v_context_result->>'success')::boolean, false) is not true then return v_context_result; end if;
  v_schema_name := nullif(coalesce(v_context_result->'details'->>'tenant_schema', ''), '');

  if v_leave_type_code is null or v_leave_type_name is null then
    return public.platform_json_response(false,'LEAVE_TYPE_INPUTS_REQUIRED','leave_type_code and leave_type_name are required.','{}'::jsonb);
  end if;

  if v_leave_type_id is null then
    execute format('select leave_type_id from %I.lms_leave_type where lower(leave_type_code) = $1 limit 1', v_schema_name)
    into v_leave_type_id
    using v_leave_type_code;
  end if;

  if v_leave_type_id is null then
    execute format('insert into %I.lms_leave_type (leave_type_code, leave_type_name, leave_unit, session_mode, requires_approval, allow_negative_balance, allow_supporting_document, medical_certificate_after_days, carry_forward_allowed, encashment_allowed, leave_type_status, type_metadata) values ($1,$2,coalesce($3,''day''),coalesce($4,''full_or_half_day''),coalesce($5,true),coalesce($6,false),coalesce($7,false),$8,coalesce($9,false),coalesce($10,false),coalesce($11,''active''),coalesce($12,''{}''::jsonb)) returning leave_type_id', v_schema_name)
    into v_leave_type_id
    using v_leave_type_code, v_leave_type_name, p_params->>'leave_unit', p_params->>'session_mode', (p_params->>'requires_approval')::boolean, (p_params->>'allow_negative_balance')::boolean, (p_params->>'allow_supporting_document')::boolean, public.platform_lms_try_numeric(p_params->>'medical_certificate_after_days'), (p_params->>'carry_forward_allowed')::boolean, (p_params->>'encashment_allowed')::boolean, p_params->>'leave_type_status', p_params->'type_metadata';
  else
    execute format('update %I.lms_leave_type set leave_type_code = $1, leave_type_name = $2, leave_unit = coalesce($3, leave_unit), session_mode = coalesce($4, session_mode), requires_approval = coalesce($5, requires_approval), allow_negative_balance = coalesce($6, allow_negative_balance), allow_supporting_document = coalesce($7, allow_supporting_document), medical_certificate_after_days = coalesce($8, medical_certificate_after_days), carry_forward_allowed = coalesce($9, carry_forward_allowed), encashment_allowed = coalesce($10, encashment_allowed), leave_type_status = coalesce($11, leave_type_status), type_metadata = coalesce($12, type_metadata), updated_at = timezone(''utc'', now()) where leave_type_id = $13', v_schema_name)
    using v_leave_type_code, v_leave_type_name, p_params->>'leave_unit', p_params->>'session_mode', (p_params->>'requires_approval')::boolean, (p_params->>'allow_negative_balance')::boolean, (p_params->>'allow_supporting_document')::boolean, public.platform_lms_try_numeric(p_params->>'medical_certificate_after_days'), (p_params->>'carry_forward_allowed')::boolean, (p_params->>'encashment_allowed')::boolean, p_params->>'leave_type_status', p_params->'type_metadata', v_leave_type_id;
  end if;

  return public.platform_json_response(true,'OK','LMS leave type recorded.',jsonb_build_object('leave_type_id', v_leave_type_id,'leave_type_code', v_leave_type_code));
exception
  when others then
    return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_register_lms_leave_type.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_register_lms_tenant_configuration(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context_result jsonb;
  v_schema_name text;
  v_configuration_id uuid := public.platform_try_uuid(p_params->>'lms_configuration_id');
  v_configuration jsonb := coalesce(p_params->'configuration', '{}'::jsonb);
  v_status text := lower(coalesce(nullif(btrim(p_params->>'configuration_status'), ''), 'active'));
begin
  v_context_result := public.platform_lms_resolve_context(p_params);
  if coalesce((v_context_result->>'success')::boolean, false) is not true then return v_context_result; end if;
  v_schema_name := nullif(coalesce(v_context_result->'details'->>'tenant_schema', ''), '');

  if jsonb_typeof(v_configuration) <> 'object' then
    return public.platform_json_response(false,'INVALID_CONFIGURATION','configuration must be a JSON object.','{}'::jsonb);
  end if;

  if v_configuration_id is null then
    execute format('insert into %I.lms_tenant_configuration (configuration_status, effective_from, effective_to, configuration) values ($1, coalesce($2, current_date), $3, $4) returning lms_configuration_id', v_schema_name)
    into v_configuration_id
    using v_status, public.platform_lms_try_date(p_params->>'effective_from'), public.platform_lms_try_date(p_params->>'effective_to'), v_configuration;
  else
    execute format('update %I.lms_tenant_configuration set configuration_status = $1, effective_from = coalesce($2, effective_from), effective_to = $3, configuration = $4, updated_at = timezone(''utc'', now()) where lms_configuration_id = $5', v_schema_name)
    using v_status, public.platform_lms_try_date(p_params->>'effective_from'), public.platform_lms_try_date(p_params->>'effective_to'), v_configuration, v_configuration_id;
  end if;

  return public.platform_json_response(true,'OK','LMS tenant configuration recorded.',jsonb_build_object('lms_configuration_id', v_configuration_id,'configuration_status', upper(v_status)));
exception
  when others then
    return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_register_lms_tenant_configuration.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_reprocess_tps_stale_summaries(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context jsonb;
  v_schema_name text;
  v_batch record;
  v_payroll_period date := date_trunc('month', public.platform_tps_try_date(p_params->>'payroll_period')::timestamp)::date;
  v_batch_id bigint := nullif(btrim(coalesce(p_params->>'batch_id', '')), '')::bigint;
  v_reprocessed_count integer := 0;
  v_row record;
  v_result jsonb;
begin
  v_context := public.platform_tps_resolve_context(p_params);
  if coalesce((v_context->>'success')::boolean, false) is not true then return v_context; end if;
  v_schema_name := v_context->'details'->>'tenant_schema';

  if v_batch_id is not null then
    execute format('select batch_id, payroll_period, batch_status from %I.tps_processing_batch where batch_id = $1', v_schema_name)
    into v_batch
    using v_batch_id;
  elsif v_payroll_period is not null then
    execute format('select batch_id, payroll_period, batch_status from %I.tps_processing_batch where payroll_period = $1', v_schema_name)
    into v_batch
    using v_payroll_period;
  else
    return public.platform_json_response(false,'BATCH_OR_PERIOD_REQUIRED','batch_id or payroll_period is required.','{}'::jsonb);
  end if;

  if v_batch.batch_id is null then return public.platform_json_response(false,'TPS_BATCH_NOT_FOUND','TPS batch not found.','{}'::jsonb); end if;
  if v_batch.batch_status = 'FINALIZED' then return public.platform_json_response(false,'TPS_BATCH_FINALIZED','Finalized TPS batches cannot be reprocessed.',jsonb_build_object('batch_id', v_batch.batch_id)); end if;

  for v_row in execute format('select employee_id from %I.tps_employee_period_summary where batch_id = $1 and is_stale = true order by employee_id', v_schema_name) using v_batch.batch_id
  loop
    v_result := public.platform_reconcile_tps_employee_period(jsonb_build_object('tenant_id', public.platform_try_uuid(v_context->'details'->>'tenant_id'),'batch_id', v_batch.batch_id,'employee_id', v_row.employee_id,'payroll_period', v_batch.payroll_period,'source', 'platform_reprocess_tps_stale_summaries'));
    if coalesce((v_result->>'success')::boolean, false) is not true then return v_result; end if;
    v_reprocessed_count := v_reprocessed_count + 1;
  end loop;

  return public.platform_json_response(true,'OK','TPS stale summaries reprocessed.',jsonb_build_object('batch_id', v_batch.batch_id,'reprocessed_count', v_reprocessed_count));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_request_ams_bio_import_run(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context jsonb := public.platform_ams_bio_resolve_context(p_params);
  v_schema_name text;
  v_result record;
begin
  if coalesce((v_context->>'success')::boolean, false) is not true then return v_context; end if;
  v_schema_name := v_context->'details'->>'tenant_schema';

  execute format(
    'insert into %I.ams_bio_import_run (import_run_id, source_profile_id, import_session_id, run_code, run_kind, source_mode, run_status, request_payload, source_window, requested_by)
     values (coalesce($1, gen_random_uuid()), $2, $3, $4, $5, $6, ''queued'', coalesce($7,''{}''::jsonb), coalesce($8,''{}''::jsonb), $9)
     returning import_run_id, run_code, run_status',
    v_schema_name
  ) into v_result using public.platform_try_uuid(p_params->>'import_run_id'), public.platform_try_uuid(p_params->>'source_profile_id'), public.platform_try_uuid(p_params->>'import_session_id'), nullif(btrim(coalesce(p_params->>'run_code', '')), ''), lower(nullif(btrim(coalesce(p_params->>'run_kind', '')), '')), lower(nullif(btrim(coalesce(p_params->>'source_mode', '')), '')), coalesce(p_params->'request_payload', '{}'::jsonb), coalesce(p_params->'source_window', '{}'::jsonb), public.platform_try_uuid(v_context->'details'->>'actor_user_id');

  return public.platform_json_response(true,'OK','BIO import run requested.',jsonb_build_object('import_run_id', v_result.import_run_id,'run_code', v_result.run_code,'run_status', v_result.run_status));
exception when others then
  return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_request_ams_bio_import_run.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_request_tps_batch_processing(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context jsonb;
  v_schema_name text;
  v_tenant_id uuid;
  v_batch_id bigint := nullif(btrim(coalesce(p_params->>'batch_id', '')), '')::bigint;
  v_batch record;
  v_actor_user_id uuid := coalesce(public.platform_try_uuid(p_params->>'actor_user_id'), public.platform_current_actor_user_id());
  v_enqueue_result jsonb;
begin
  v_context := public.platform_tps_resolve_context(p_params);
  if coalesce((v_context->>'success')::boolean, false) is not true then return v_context; end if;
  v_schema_name := v_context->'details'->>'tenant_schema';
  v_tenant_id := public.platform_try_uuid(v_context->'details'->>'tenant_id');

  if v_batch_id is null then return public.platform_json_response(false,'BATCH_ID_REQUIRED','batch_id is required.','{}'::jsonb); end if;

  execute format('select batch_id, payroll_period, batch_status from %I.tps_processing_batch where batch_id = $1', v_schema_name)
  into v_batch
  using v_batch_id;

  if v_batch.batch_id is null then return public.platform_json_response(false,'TPS_BATCH_NOT_FOUND','TPS batch not found.',jsonb_build_object('batch_id', v_batch_id)); end if;
  if v_batch.batch_status not in ('FROZEN', 'FAILED') then return public.platform_json_response(false,'TPS_BATCH_NOT_QUEUEABLE','Only FROZEN or FAILED TPS batches can be queued for processing.',jsonb_build_object('batch_id', v_batch_id,'batch_status', v_batch.batch_status)); end if;

  v_enqueue_result := public.platform_async_enqueue_job(jsonb_build_object(
    'tenant_id', v_tenant_id,
    'worker_code', 'tps_period_processing_worker',
    'job_type', 'process_period_batch',
    'priority', 70,
    'payload', jsonb_build_object('tenant_id', v_tenant_id, 'batch_id', v_batch.batch_id, 'payroll_period', v_batch.payroll_period, 'actor_user_id', v_actor_user_id),
    'deduplication_key', format('tps:%s:%s', v_tenant_id::text, v_batch.batch_id::text),
    'origin_source', coalesce(nullif(btrim(p_params->>'source'), ''), 'platform_request_tps_batch_processing'),
    'metadata', jsonb_build_object('slice', 'TPS', 'reason', 'batch_processing')
  ));

  if coalesce((v_enqueue_result->>'success')::boolean, false) is not true then return v_enqueue_result; end if;

  execute format(
    'update %I.tps_processing_batch
        set batch_status = ''PROCESSING'',
            processed_by_actor_user_id = coalesce($2, processed_by_actor_user_id),
            last_error = null,
            updated_at = timezone(''utc'', now())
      where batch_id = $1',
    v_schema_name
  )
  using v_batch.batch_id, v_actor_user_id;

  return public.platform_json_response(true,'OK','TPS batch queued for processing.',jsonb_build_object(
    'tenant_id', v_tenant_id,
    'batch_id', v_batch.batch_id,
    'payroll_period', v_batch.payroll_period,
    'batch_status', 'PROCESSING',
    'enqueued_job_id', v_enqueue_result->'details'->>'job_id'
  ));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_resolve_ams_bio_reconciliation_case(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context jsonb := public.platform_ams_bio_resolve_context(p_params);
  v_schema_name text;
  v_case_id uuid := public.platform_try_uuid(p_params->>'reconciliation_case_id');
  v_employee_id uuid := public.platform_try_uuid(p_params->>'employee_id');
  v_case record;
begin
  if coalesce((v_context->>'success')::boolean, false) is not true then return v_context; end if;
  v_schema_name := v_context->'details'->>'tenant_schema';
  if v_case_id is null then return public.platform_json_response(false,'RECONCILIATION_CASE_ID_REQUIRED','reconciliation_case_id is required.','{}'::jsonb); end if;

  execute format('select reconciliation_case_id, normalized_punch_id, case_status, details_json from %I.ams_bio_reconciliation_case where reconciliation_case_id = $1', v_schema_name)
  into v_case using v_case_id;
  if v_case.reconciliation_case_id is null then return public.platform_json_response(false,'RECONCILIATION_CASE_NOT_FOUND','Reconciliation case not found.',jsonb_build_object('reconciliation_case_id', v_case_id)); end if;

  if v_employee_id is not null then
    execute format('update %I.ams_bio_normalized_punch set employee_id = $2, normalization_status = ''ready_to_publish'', updated_at = timezone(''utc'', now()) where normalized_punch_id = $1', v_schema_name)
    using v_case.normalized_punch_id, v_employee_id;
    execute format('insert into %I.ams_bio_publish_log (normalized_punch_id, publish_status, payload_snapshot, error_details) values ($1,''pending'',''{}''::jsonb,''{}''::jsonb) on conflict (normalized_punch_id) do update set publish_status = ''pending'', updated_at = timezone(''utc'', now())', v_schema_name)
    using v_case.normalized_punch_id;
  end if;

  execute format('update %I.ams_bio_reconciliation_case set employee_id = coalesce($2, employee_id), case_status = ''resolved'', details_json = coalesce(details_json,''{}''::jsonb) || coalesce($3,''{}''::jsonb), resolved_at = timezone(''utc'', now()), resolved_by = $4, updated_at = timezone(''utc'', now()) where reconciliation_case_id = $1', v_schema_name)
  using v_case_id, v_employee_id, coalesce(p_params->'details_json', '{}'::jsonb), public.platform_try_uuid(v_context->'details'->>'actor_user_id');

  return public.platform_json_response(true,'OK','BIO reconciliation case resolved.',jsonb_build_object('reconciliation_case_id', v_case_id,'normalized_punch_id', v_case.normalized_punch_id));
exception when others then
  return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_resolve_ams_bio_reconciliation_case.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm));
end;
$function$
;

