CREATE OR REPLACE FUNCTION public.platform_stage_ams_bio_import_rows(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context jsonb := public.platform_ams_bio_resolve_context(p_params);
  v_schema_name text;
  v_import_session_id uuid := public.platform_try_uuid(p_params->>'import_session_id');
  v_rows jsonb := coalesce(p_params->'rows', '[]'::jsonb);
  v_row jsonb;
  v_index integer := 0;
  v_count integer := 0;
begin
  if coalesce((v_context->>'success')::boolean, false) is not true then return v_context; end if;
  v_schema_name := v_context->'details'->>'tenant_schema';
  if v_import_session_id is null then return public.platform_json_response(false,'IMPORT_SESSION_ID_REQUIRED','import_session_id is required.','{}'::jsonb); end if;
  if jsonb_typeof(v_rows) <> 'array' then return public.platform_json_response(false,'ROWS_ARRAY_REQUIRED','rows must be an array.','{}'::jsonb); end if;

  for v_row in select value from jsonb_array_elements(v_rows)
  loop
    v_index := v_index + 1;
    execute format(
      'insert into %I.ams_bio_import_staging_row (import_session_id, row_num, source_row_hash, raw_row, canonical_row, row_status, validation_detail)
       values ($1, $2, md5(coalesce($3::text, '''')), coalesce($3,''{}''::jsonb), ''{}''::jsonb, ''staged'', ''{}''::jsonb)
       on conflict (import_session_id, row_num) do update
       set source_row_hash = excluded.source_row_hash,
           raw_row = excluded.raw_row,
           canonical_row = excluded.canonical_row,
           row_status = excluded.row_status,
           validation_detail = excluded.validation_detail,
           updated_at = timezone(''utc'', now())',
      v_schema_name
    ) using v_import_session_id, v_index, v_row;
    v_count := v_count + 1;
  end loop;

  execute format(
    'update %I.ams_bio_import_session
     set session_status = case when $2 > 0 then ''parsed'' else session_status end,
         import_summary = jsonb_set(coalesce(import_summary,''{}''::jsonb), ''{staged_rows}'', to_jsonb($2), true),
         updated_at = timezone(''utc'', now())
     where import_session_id = $1',
    v_schema_name
  ) using v_import_session_id, v_count;

  return public.platform_json_response(true,'OK','BIO import rows staged.',jsonb_build_object('import_session_id', v_import_session_id,'staged_rows', v_count));
exception when others then
  return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_stage_ams_bio_import_rows.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_submit_ams_regularization_request(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context_result jsonb;
  v_schema_name text;
  v_tenant_id uuid;
  v_regularization_request_id uuid;
  v_attendance_record record;
  v_attendance_record_id uuid := public.platform_try_uuid(p_params->>'attendance_record_id');
  v_employee_id uuid := public.platform_try_uuid(p_params->>'employee_id');
  v_document_id uuid := public.platform_try_uuid(p_params->>'supporting_document_id');
  v_document record;
  v_existing_pending_request_id uuid;
begin
  v_context_result := public.platform_ams_resolve_context(p_params);
  if coalesce((v_context_result->>'success')::boolean, false) is not true then return v_context_result; end if;
  v_schema_name := nullif(coalesce(v_context_result->'details'->>'tenant_schema',''), '');
  v_tenant_id := public.platform_try_uuid(v_context_result->'details'->>'tenant_id');

  if v_employee_id is null or v_attendance_record_id is null then return public.platform_json_response(false,'REGULARIZATION_INPUTS_REQUIRED','employee_id and attendance_record_id are required.','{}'::jsonb); end if;

  execute format('select attendance_record_id, employee_id from %I.ams_attendance_record where attendance_record_id = $1', v_schema_name)
  into v_attendance_record
  using v_attendance_record_id;

  if v_attendance_record.attendance_record_id is null then
    return public.platform_json_response(false,'ATTENDANCE_RECORD_NOT_FOUND','Attendance record not found.',jsonb_build_object('attendance_record_id', v_attendance_record_id));
  end if;

  if v_attendance_record.employee_id is distinct from v_employee_id then
    return public.platform_json_response(false,'ATTENDANCE_EMPLOYEE_MISMATCH','attendance_record_id does not belong to the supplied employee_id.',jsonb_build_object('attendance_record_id', v_attendance_record_id,'employee_id', v_employee_id));
  end if;

  if v_document_id is not null then
    select document_id, tenant_id, document_status
    into v_document
    from public.platform_document_record
    where document_id = v_document_id;

    if v_document.document_id is null then
      return public.platform_json_response(false,'SUPPORTING_DOCUMENT_NOT_FOUND','supporting_document_id was not found in the governed document registry.',jsonb_build_object('supporting_document_id', v_document_id));
    end if;

    if v_document.tenant_id is distinct from v_tenant_id then
      return public.platform_json_response(false,'SUPPORTING_DOCUMENT_TENANT_MISMATCH','supporting_document_id does not belong to the supplied tenant.',jsonb_build_object('supporting_document_id', v_document_id,'tenant_id', v_tenant_id));
    end if;

    if v_document.document_status <> 'active' then
      return public.platform_json_response(false,'SUPPORTING_DOCUMENT_NOT_ACTIVE','supporting_document_id must be active before it can support a regularization request.',jsonb_build_object('supporting_document_id', v_document_id,'document_status', v_document.document_status));
    end if;
  end if;

  execute format('select regularization_request_id from %I.ams_regularization_request where attendance_record_id = $1 and request_status = ''PENDING'' order by created_at desc limit 1', v_schema_name)
  into v_existing_pending_request_id
  using v_attendance_record_id;

  if v_existing_pending_request_id is not null then
    return public.platform_json_response(false,'REGULARIZATION_ALREADY_PENDING','A pending regularization request already exists for this attendance record.',jsonb_build_object('attendance_record_id', v_attendance_record_id,'regularization_request_id', v_existing_pending_request_id));
  end if;

  execute format('insert into %I.ams_regularization_request (attendance_record_id,employee_id,request_type,requested_clock_in,requested_clock_out,employee_remarks,supporting_document_id,request_status,request_metadata) values ($1,$2,coalesce($3,''FULL_DAY_CORRECTION''),$4,$5,$6,$7,''PENDING'',coalesce($8,''{}''::jsonb)) returning regularization_request_id', v_schema_name)
  into v_regularization_request_id
  using v_attendance_record_id, v_employee_id, p_params->>'request_type', public.platform_ams_try_timestamptz(p_params->>'requested_clock_in'), public.platform_ams_try_timestamptz(p_params->>'requested_clock_out'), p_params->>'employee_remarks', v_document_id, p_params->'request_metadata';

  execute format('update %I.ams_attendance_record set regularization_request_id = $2, updated_at = timezone(''utc'', now()) where attendance_record_id = $1', v_schema_name)
  using v_attendance_record_id, v_regularization_request_id;

  perform public.platform_ams_log_audit_event(v_schema_name,'REGULARIZATION_SUBMITTED','AMS_CORE',jsonb_build_object('request_type', p_params->>'request_type','supporting_document_id', v_document_id),v_employee_id,v_attendance_record_id,v_regularization_request_id,coalesce(public.platform_try_uuid(p_params->>'actor_user_id'), public.platform_current_actor_user_id()));

  return public.platform_json_response(true,'OK','AMS regularization request submitted.',jsonb_build_object('regularization_request_id', v_regularization_request_id));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_tps_batch_catalog_rows()
 RETURNS TABLE(tenant_id uuid, batch_id bigint, payroll_period date, batch_status text, frozen_at timestamp with time zone, processed_at timestamp with time zone, finalized_at timestamp with time zone, total_employees bigint, stale_summary_count bigint, aggregate_payable_days numeric, aggregate_lop_days numeric, aggregate_paid_leave_days numeric, aggregate_overtime_hours numeric, last_error text, updated_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context jsonb := public.platform_tps_resolve_context('{}'::jsonb);
  v_schema_name text;
  v_tenant_id uuid;
begin
  if coalesce((v_context->>'success')::boolean, false) is not true then return; end if;
  v_schema_name := v_context->'details'->>'tenant_schema';
  v_tenant_id := public.platform_try_uuid(v_context->'details'->>'tenant_id');

  return query execute format(
    'select $1::uuid as tenant_id,
            b.batch_id,
            b.payroll_period,
            b.batch_status,
            b.frozen_at,
            b.processed_at,
            b.finalized_at,
            count(s.employee_period_summary_id)::bigint as total_employees,
            count(*) filter (where s.is_stale = true)::bigint as stale_summary_count,
            coalesce(sum(s.payable_days), 0) as aggregate_payable_days,
            coalesce(sum(s.lop_days), 0) as aggregate_lop_days,
            coalesce(sum(s.paid_leave_days), 0) as aggregate_paid_leave_days,
            coalesce(sum(s.total_overtime_hours), 0) as aggregate_overtime_hours,
            b.last_error,
            b.updated_at
       from %I.tps_processing_batch b
       left join %I.tps_employee_period_summary s on s.batch_id = b.batch_id
      group by b.batch_id, b.payroll_period, b.batch_status, b.frozen_at, b.processed_at, b.finalized_at, b.last_error, b.updated_at
      order by b.payroll_period desc, b.batch_id desc',
    v_schema_name,
    v_schema_name
  ) using v_tenant_id;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_tps_calculate_attendance_hash_internal(p_schema_name text, p_employee_id uuid, p_scope_start date, p_scope_end date)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_hash text;
begin
  execute format(
    'select md5(coalesce(string_agg(
       concat_ws(''|'',
         attendance_date::text,
         coalesce(status_final, ''''),
         coalesce(overtime_minutes, 0)::text,
         coalesce(on_leave_request_id::text, ''''),
         coalesce(leave_session_scope, ''''),
         coalesce(leave_fraction, 0)::text,
         coalesce(is_holiday, false)::text,
         coalesce(regularization_request_id::text, ''''),
         coalesce(updated_at::text, '''')
       ), ''||'' order by attendance_date, attendance_record_id
     ), ''''))
     from %I.ams_attendance_record
     where employee_id = $1
       and attendance_date between $2 and $3',
    p_schema_name
  )
  into v_hash
  using p_employee_id, p_scope_start, p_scope_end;

  return coalesce(v_hash, md5(''));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_tps_employee_period_summary_rows()
 RETURNS TABLE(tenant_id uuid, batch_id bigint, payroll_period date, employee_id uuid, employee_code text, batch_status text, payable_days numeric, lop_days numeric, paid_leave_days numeric, total_overtime_hours numeric, is_stale boolean, source_data_hash text, last_source_change timestamp with time zone, processed_at timestamp with time zone, updated_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context jsonb := public.platform_tps_resolve_context('{}'::jsonb);
  v_schema_name text;
  v_tenant_id uuid;
begin
  if coalesce((v_context->>'success')::boolean, false) is not true then return; end if;
  v_schema_name := v_context->'details'->>'tenant_schema';
  v_tenant_id := public.platform_try_uuid(v_context->'details'->>'tenant_id');

  return query execute format(
    'select $1::uuid as tenant_id,
            s.batch_id,
            s.payroll_period,
            s.employee_id,
            e.employee_code,
            b.batch_status,
            s.payable_days,
            s.lop_days,
            s.paid_leave_days,
            s.total_overtime_hours,
            s.is_stale,
            s.source_data_hash,
            s.last_source_change,
            s.processed_at,
            s.updated_at
       from %I.tps_employee_period_summary s
       join %I.tps_processing_batch b on b.batch_id = s.batch_id
       join %I.wcm_employee e on e.employee_id = s.employee_id
      order by s.payroll_period desc, e.employee_code',
    v_schema_name,
    v_schema_name,
    v_schema_name
  ) using v_tenant_id;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_tps_is_paid_leave_request(p_schema_name text, p_leave_request_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_is_paid boolean := false;
begin
  if p_leave_request_id is null then return false; end if;

  execute format(
    'select exists (
       select 1
       from %I.lms_leave_request r
       join %I.lms_ledger_consumption c
         on c.leave_request_id = r.leave_request_id
        and c.consumption_status = ''active''
       where r.leave_request_id = $1
         and r.request_status in (''APPROVED'', ''AUTO_APPROVED'')
     )',
    p_schema_name,
    p_schema_name
  )
  into v_is_paid
  using p_leave_request_id;

  return coalesce(v_is_paid, false);
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_tps_jsonb_increment(p_payload jsonb, p_key text, p_increment numeric)
 RETURNS jsonb
 LANGUAGE sql
 IMMUTABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
  select coalesce(p_payload, '{}'::jsonb)
         || jsonb_build_object(
              p_key,
              coalesce((coalesce(p_payload, '{}'::jsonb)->>p_key)::numeric, 0) + coalesce(p_increment, 0)
            );
$function$
;

CREATE OR REPLACE FUNCTION public.platform_tps_mark_summary_stale_on_attendance_change()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_schema_name text := tg_table_schema;
  v_employee_id uuid := coalesce(new.employee_id, old.employee_id);
  v_attendance_date date := coalesce(new.attendance_date, old.attendance_date);
  v_payroll_period date;
begin
  if v_employee_id is null or v_attendance_date is null then
    return coalesce(new, old);
  end if;

  v_payroll_period := date_trunc('month', v_attendance_date::timestamp)::date;

  execute format(
    'update %I.tps_employee_period_summary s
        set is_stale = true,
            last_source_change = timezone(''utc'', now()),
            updated_at = timezone(''utc'', now())
       from %I.tps_processing_batch b
      where b.batch_id = s.batch_id
        and s.employee_id = $1
        and s.payroll_period = $2
        and b.batch_status <> ''FINALIZED''',
    v_schema_name,
    v_schema_name
  )
  using v_employee_id, v_payroll_period;

  return coalesce(new, old);
end;
$function$
;

