CREATE OR REPLACE FUNCTION public.platform_tps_queue_health_current_rows()
 RETURNS TABLE(tenant_id uuid, checked_at timestamp with time zone, queued_count bigint, running_count bigint, retry_wait_count bigint, dead_letter_count bigint, stale_lease_count bigint, stale_summary_count bigint, processing_batches_over_30m bigint, severity text, details jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_tenant_id uuid := public.platform_current_tenant_id();
begin
  if v_tenant_id is null then return; end if;

  return query
  select q.tenant_id,
         q.checked_at,
         q.queued_count,
         q.running_count,
         q.retry_wait_count,
         q.dead_letter_count,
