  from public.tps_queue_health_log q
  where q.tenant_id = v_tenant_id
  order by q.checked_at desc, q.queue_health_log_id desc
  limit 1;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_tps_resolve_context(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_params jsonb := coalesce(p_params, '{}'::jsonb);
  v_requested_tenant_id uuid := public.platform_resolve_tenant_id(v_params);
  v_current_tenant_id uuid := public.platform_current_tenant_id();
  v_current_schema text := public.platform_current_tenant_schema();
  v_context_result jsonb;
  v_details jsonb;
begin
  if v_current_tenant_id is not null and v_current_schema is not null then
    if v_requested_tenant_id is not null and v_requested_tenant_id <> v_current_tenant_id then
      return public.platform_json_response(false,'CONTEXT_TENANT_MISMATCH','The requested tenant does not match the current execution context.',jsonb_build_object('requested_tenant_id', v_requested_tenant_id,'current_tenant_id', v_current_tenant_id));
    end if;

    if not public.platform_table_exists(v_current_schema, 'wcm_employee')
      or not public.platform_table_exists(v_current_schema, 'wcm_employee_service_state')
      or not public.platform_table_exists(v_current_schema, 'lms_leave_request')
      or not public.platform_table_exists(v_current_schema, 'lms_ledger_consumption')
      or not public.platform_table_exists(v_current_schema, 'ams_attendance_record')
      or not public.platform_table_exists(v_current_schema, 'tps_processing_batch')
      or not public.platform_table_exists(v_current_schema, 'tps_employee_period_summary')
    then
      return public.platform_json_response(false,'TPS_TEMPLATE_NOT_APPLIED','TPS is not applied to the current tenant schema.',jsonb_build_object('tenant_id', v_current_tenant_id,'tenant_schema', v_current_schema));
    end if;

    return public.platform_json_response(true,'OK','TPS execution context resolved.',jsonb_build_object('tenant_id', v_current_tenant_id,'tenant_schema', v_current_schema,'actor_user_id', public.platform_current_actor_user_id()));
  end if;

  if not public.platform_is_internal_caller() then
    return public.platform_json_response(false,'TENANT_CONTEXT_REQUIRED','An applied tenant execution context is required.','{}'::jsonb);
  end if;

  if v_requested_tenant_id is null then
    return public.platform_json_response(false,'TENANT_ID_REQUIRED','tenant_id or tenant_code is required when no execution context is active.','{}'::jsonb);
  end if;

  v_context_result := public.platform_apply_execution_context(jsonb_build_object(
    'execution_mode', 'internal_platform',
    'tenant_id', v_requested_tenant_id,
    'source', coalesce(nullif(btrim(v_params->>'source'), ''), 'platform_tps_resolve_context')
  ));
  if coalesce((v_context_result->>'success')::boolean, false) is not true then return v_context_result; end if;

  v_details := coalesce(v_context_result->'details', '{}'::jsonb);
  if not public.platform_table_exists(v_details->>'tenant_schema', 'tps_processing_batch') then
    return public.platform_json_response(false,'TPS_TEMPLATE_NOT_APPLIED','TPS is not applied to the requested tenant schema.',jsonb_build_object('tenant_id', public.platform_try_uuid(v_details->>'tenant_id'),'tenant_schema', v_details->>'tenant_schema'));
  end if;

  return public.platform_json_response(true,'OK','TPS execution context resolved.',jsonb_build_object('tenant_id', public.platform_try_uuid(v_details->>'tenant_id'),'tenant_schema', v_details->>'tenant_schema','actor_user_id', public.platform_current_actor_user_id()));
exception when others then
  return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_tps_resolve_context.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_tps_try_date(p_value text)
 RETURNS date
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
begin
  if p_value is null or btrim(p_value) = '' then return null; end if;
  return p_value::date;
exception when others then
  return null;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_update_eoap_workflow_step(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context_result jsonb;
  v_schema_name text;
  v_workflow_step_id uuid := public.platform_try_uuid(p_params->>'workflow_step_id');
  v_workflow_id uuid := public.platform_try_uuid(p_params->>'workflow_id');
  v_step_code text := nullif(lower(btrim(coalesce(p_params->>'step_code', ''))), '');
  v_step_status text := lower(coalesce(nullif(btrim(p_params->>'step_status'), ''), ''));
  v_assigned_actor_user_id uuid := public.platform_try_uuid(p_params->>'assigned_actor_user_id');
  v_due_on date := case when p_params ? 'due_on' then (p_params->>'due_on')::date else null end;
  v_completion_notes text := nullif(btrim(coalesce(p_params->>'completion_notes', '')), '');
  v_existing_workflow_id uuid;
  v_existing_step_status text;
  v_pending_hire_id uuid;
  v_promoted_step_count integer := 0;
  v_demoted_step_count integer := 0;
  v_audit_result jsonb;
begin
  v_context_result := public.platform_eoap_resolve_context(p_params);
  if coalesce((v_context_result->>'success')::boolean, false) is not true then return v_context_result; end if;
  v_schema_name := nullif(coalesce(v_context_result->'details'->>'tenant_schema', ''), '');
  if v_step_status not in ('pending','ready','in_progress','completed','rejected','skipped','on_hold') then
    return public.platform_json_response(false,'INVALID_STEP_STATUS','step_status is invalid.','{}'::jsonb);
  end if;
  if v_workflow_step_id is null then
    if v_workflow_id is null or v_step_code is null then
      return public.platform_json_response(false,'STEP_TARGET_REQUIRED','workflow_step_id or workflow_id with step_code is required.','{}'::jsonb);
    end if;
    execute format('select workflow_step_id from %I.eoap_workflow_step where workflow_id = $1 and step_code = $2', v_schema_name) into v_workflow_step_id using v_workflow_id, v_step_code;
  end if;
  if v_workflow_step_id is null then
    return public.platform_json_response(false,'WORKFLOW_STEP_NOT_FOUND','Workflow step not found.','{}'::jsonb);
  end if;
  execute format('select s.workflow_id, s.step_status, w.pending_hire_id from %I.eoap_workflow_step s join %I.eoap_workflow w on w.workflow_id = s.workflow_id where s.workflow_step_id = $1', v_schema_name, v_schema_name) into v_existing_workflow_id, v_existing_step_status, v_pending_hire_id using v_workflow_step_id;
  if v_existing_workflow_id is null then
    return public.platform_json_response(false,'WORKFLOW_STEP_NOT_FOUND','Workflow step not found.','{}'::jsonb);
  end if;
  execute format('update %I.eoap_workflow_step set step_status = $1, assigned_actor_user_id = coalesce($2, assigned_actor_user_id), due_on = coalesce($3, due_on), completion_notes = coalesce($4, completion_notes), completed_at = case when $1 in (''completed'',''rejected'',''skipped'') then coalesce(completed_at, timezone(''utc'', now())) when $1 in (''pending'',''ready'',''in_progress'',''on_hold'') then null else completed_at end, updated_at = timezone(''utc'', now()) where workflow_step_id = $5', v_schema_name) using v_step_status, v_assigned_actor_user_id, v_due_on, v_completion_notes, v_workflow_step_id;
  if v_step_status in ('completed','skipped') then
    execute format('update %I.eoap_workflow_step s set step_status = ''ready'', updated_at = timezone(''utc'', now()) where s.workflow_id = $1 and s.step_status = ''pending'' and coalesce(array_length(s.dependency_step_codes, 1), 0) > 0 and not exists (select 1 from unnest(s.dependency_step_codes) dep(step_code) left join %I.eoap_workflow_step d on d.workflow_id = s.workflow_id and d.step_code = dep.step_code where d.workflow_step_id is null or d.step_status not in (''completed'',''skipped''))', v_schema_name, v_schema_name) using v_existing_workflow_id;
    get diagnostics v_promoted_step_count = row_count;
  elsif v_existing_step_status in ('completed','skipped') and v_step_status not in ('completed','skipped') then
    execute format('update %I.eoap_workflow_step s set step_status = ''pending'', updated_at = timezone(''utc'', now()) where s.workflow_id = $1 and s.step_status = ''ready'' and exists (select 1 from unnest(s.dependency_step_codes) dep(step_code) join %I.eoap_workflow_step d on d.workflow_id = s.workflow_id and d.step_code = dep.step_code where d.step_status not in (''completed'',''skipped''))', v_schema_name, v_schema_name) using v_existing_workflow_id;
    get diagnostics v_demoted_step_count = row_count;
  end if;
  execute format('update %I.eoap_workflow set current_step_code = (select step_code from %I.eoap_workflow_step where workflow_id = $1 and step_status in (''ready'',''in_progress'',''pending'',''on_hold'') order by case step_status when ''ready'' then 1 when ''in_progress'' then 2 when ''pending'' then 3 else 4 end, step_sequence limit 1), updated_at = timezone(''utc'', now()) where workflow_id = $1', v_schema_name, v_schema_name) using v_existing_workflow_id;
  v_audit_result := public.platform_log_eoap_audit_event(jsonb_build_object('tenant_id', public.platform_try_uuid(v_context_result->'details'->>'tenant_id'),'pending_hire_id', v_pending_hire_id,'workflow_id', v_existing_workflow_id,'workflow_step_id', v_workflow_step_id,'event_type', 'workflow_step_updated','event_details', jsonb_build_object('prior_step_status', v_existing_step_status,'new_step_status', v_step_status,'promoted_step_count', v_promoted_step_count,'demoted_step_count', v_demoted_step_count)));
  if coalesce((v_audit_result->>'success')::boolean, false) is not true then return v_audit_result; end if;
  return public.platform_json_response(true,'OK','EOAP workflow step updated.',jsonb_build_object('workflow_id', v_existing_workflow_id,'workflow_step_id', v_workflow_step_id,'prior_step_status', v_existing_step_status,'new_step_status', v_step_status,'promoted_step_count', v_promoted_step_count,'demoted_step_count', v_demoted_step_count));
exception when others then
  return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_update_eoap_workflow_step.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_upsert_ams_bio_employee_mapping(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context jsonb := public.platform_ams_bio_resolve_context(p_params);
  v_schema_name text;
  v_mapping_id uuid := public.platform_try_uuid(p_params->>'employee_mapping_id');
  v_employee_id uuid := public.platform_try_uuid(p_params->>'employee_id');
  v_external_employee_code text := nullif(btrim(coalesce(p_params->>'external_employee_code', '')), '');
  v_mapping_status text := lower(coalesce(nullif(btrim(p_params->>'mapping_status'), ''), case when v_employee_id is null then 'unmapped' else 'mapped' end));
  v_result record;
begin
  if coalesce((v_context->>'success')::boolean, false) is not true then return v_context; end if;
  v_schema_name := v_context->'details'->>'tenant_schema';

  if v_external_employee_code is null then
    return public.platform_json_response(false,'EXTERNAL_EMPLOYEE_CODE_REQUIRED','external_employee_code is required.','{}'::jsonb);
  end if;
  if v_employee_id is not null and public.platform_ams_bio_active_employee_anchor_exists(v_schema_name, v_employee_id, current_date) is not true then
    return public.platform_json_response(false,'EMPLOYEE_NOT_ACTIVE','employee_id is not an active BIO publish anchor.',jsonb_build_object('employee_id', v_employee_id));
  end if;

  execute format(
    'insert into %I.ams_bio_employee_mapping (employee_mapping_id, external_employee_code, employee_id, mapping_status, confidence_score, mapping_source, mapping_metadata)
     values (coalesce($1, gen_random_uuid()), $2, $3, $4, $5, $6, coalesce($7,''{}''::jsonb))
     on conflict (external_employee_code) do update
     set employee_id = excluded.employee_id,
         mapping_status = excluded.mapping_status,
         confidence_score = excluded.confidence_score,
         mapping_source = excluded.mapping_source,
         mapping_metadata = excluded.mapping_metadata,
         updated_at = timezone(''utc'', now())
     returning employee_mapping_id, external_employee_code, employee_id, mapping_status',
    v_schema_name
  ) into v_result using v_mapping_id, v_external_employee_code, v_employee_id, v_mapping_status, nullif(btrim(coalesce(p_params->>'confidence_score', '')), '')::numeric, nullif(btrim(coalesce(p_params->>'mapping_source', '')), ''), coalesce(p_params->'mapping_metadata', '{}'::jsonb);

  return public.platform_json_response(true,'OK','BIO employee mapping saved.',jsonb_build_object('employee_mapping_id', v_result.employee_mapping_id,'external_employee_code', v_result.external_employee_code,'employee_id', v_result.employee_id,'mapping_status', v_result.mapping_status));
exception when others then
  return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_upsert_ams_bio_employee_mapping.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_upsert_ams_employee_schedule(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare v_context_result jsonb; v_schema_name text; v_employee_schedule_id uuid := public.platform_try_uuid(p_params->>'employee_schedule_id'); begin
  v_context_result := public.platform_ams_resolve_context(p_params); if coalesce((v_context_result->>'success')::boolean, false) is not true then return v_context_result; end if; v_schema_name := nullif(coalesce(v_context_result->'details'->>'tenant_schema',''), '');
  if public.platform_try_uuid(p_params->>'employee_id') is null then return public.platform_json_response(false,'EMPLOYEE_ID_REQUIRED','employee_id is required.','{}'::jsonb); end if;
  if v_employee_schedule_id is null then
    execute format('insert into %I.ams_employee_schedule (employee_id,shift_id,effective_start_date,effective_end_date,schedule_status,custom_work_days,custom_start_time,custom_end_time,custom_break_duration_minutes,schedule_metadata) values ($1,$2,coalesce($3,current_date),$4,coalesce($5,''active''),$6,$7,$8,$9,coalesce($10,''{}''::jsonb)) returning employee_schedule_id', v_schema_name)
    into v_employee_schedule_id
    using public.platform_try_uuid(p_params->>'employee_id'), public.platform_ams_try_bigint(p_params->>'shift_id'), public.platform_ams_try_date(p_params->>'effective_start_date'), public.platform_ams_try_date(p_params->>'effective_end_date'), p_params->>'schedule_status', p_params->'custom_work_days', public.platform_ams_try_time(p_params->>'custom_start_time'), public.platform_ams_try_time(p_params->>'custom_end_time'), public.platform_ams_try_bigint(p_params->>'custom_break_duration_minutes'), p_params->'schedule_metadata';
  else
    execute format('update %I.ams_employee_schedule set shift_id = coalesce($1,shift_id), effective_start_date = coalesce($2,effective_start_date), effective_end_date = $3, schedule_status = coalesce($4,schedule_status), custom_work_days = coalesce($5,custom_work_days), custom_start_time = coalesce($6,custom_start_time), custom_end_time = coalesce($7,custom_end_time), custom_break_duration_minutes = coalesce($8,custom_break_duration_minutes), schedule_metadata = coalesce($9,schedule_metadata), updated_at = timezone(''utc'', now()) where employee_schedule_id = $10', v_schema_name)
    using public.platform_ams_try_bigint(p_params->>'shift_id'), public.platform_ams_try_date(p_params->>'effective_start_date'), public.platform_ams_try_date(p_params->>'effective_end_date'), p_params->>'schedule_status', p_params->'custom_work_days', public.platform_ams_try_time(p_params->>'custom_start_time'), public.platform_ams_try_time(p_params->>'custom_end_time'), public.platform_ams_try_bigint(p_params->>'custom_break_duration_minutes'), p_params->'schedule_metadata', v_employee_schedule_id;
  end if;
  perform public.platform_ams_log_audit_event(v_schema_name,'AMS_SCHEDULE_RECORDED','AMS_CORE',jsonb_build_object('employee_schedule_id', v_employee_schedule_id),public.platform_try_uuid(p_params->>'employee_id'),null,null,coalesce(public.platform_try_uuid(p_params->>'actor_user_id'), public.platform_current_actor_user_id()));
  return public.platform_json_response(true,'OK','AMS employee schedule recorded.',jsonb_build_object('employee_schedule_id', v_employee_schedule_id));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_upsert_hierarchy_position_occupancy(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context_result jsonb;
  v_context_details jsonb;
  v_schema_name text;
  v_occupancy_id bigint := public.platform_hierarchy_try_bigint(p_params->>'occupancy_id');
  v_employee_id uuid := public.platform_try_uuid(p_params->>'employee_id');
  v_position_id bigint := public.platform_hierarchy_try_bigint(p_params->>'position_id');
  v_occupancy_role text := lower(coalesce(nullif(btrim(p_params->>'occupancy_role'), ''), 'primary'));
  v_effective_start_date date := coalesce(public.platform_hierarchy_try_date(p_params->>'effective_start_date'), current_date);
  v_effective_end_date date := public.platform_hierarchy_try_date(p_params->>'effective_end_date');
  v_occupancy_status text := lower(coalesce(nullif(btrim(p_params->>'occupancy_status'), ''), 'active'));
  v_occupancy_reason text := nullif(btrim(coalesce(p_params->>'occupancy_reason', '')), '');
  v_event_details jsonb := coalesce(p_params->'event_details', '{}'::jsonb);
  v_actor_user_id uuid := coalesce(public.platform_try_uuid(p_params->>'actor_user_id'), public.platform_current_actor_user_id());
  v_employee_exists boolean := false;
  v_position_exists boolean := false;
  v_existing record;
  v_close_record record;
  v_event_type text;
begin
  v_context_result := public.platform_hierarchy_resolve_context(p_params);
  if coalesce((v_context_result->>'success')::boolean, false) is not true then
    return v_context_result;
  end if;

  if v_employee_id is null then
    return public.platform_json_response(false, 'EMPLOYEE_ID_REQUIRED', 'employee_id is required.', '{}'::jsonb);
  end if;

  if v_position_id is null then
    return public.platform_json_response(false, 'POSITION_ID_REQUIRED', 'position_id is required.', '{}'::jsonb);
  end if;

  if v_occupancy_role not in ('primary', 'handover_successor', 'handover_legacy') then
    return public.platform_json_response(false, 'INVALID_OCCUPANCY_ROLE', 'occupancy_role must be primary, handover_successor, or handover_legacy.', '{}'::jsonb);
  end if;

  if v_occupancy_status not in ('active', 'ended', 'cancelled') then
    return public.platform_json_response(false, 'INVALID_OCCUPANCY_STATUS', 'occupancy_status must be active, ended, or cancelled.', '{}'::jsonb);
  end if;

  if jsonb_typeof(v_event_details) is distinct from 'object' then
    return public.platform_json_response(false, 'INVALID_EVENT_DETAILS', 'event_details must be a JSON object.', '{}'::jsonb);
  end if;

  if v_effective_end_date is not null and v_effective_end_date < v_effective_start_date then
    return public.platform_json_response(false, 'INVALID_EFFECTIVE_DATE_RANGE', 'effective_end_date cannot be earlier than effective_start_date.', '{}'::jsonb);
  end if;

  if v_occupancy_status in ('ended', 'cancelled') and v_effective_end_date is null then
    v_effective_end_date := current_date;
  end if;

  v_context_details := coalesce(v_context_result->'details', '{}'::jsonb);
  v_schema_name := nullif(v_context_details->>'tenant_schema', '');

  execute format(
    'select exists (
       select 1
       from %I.wcm_employee e
       join %I.wcm_employee_service_state s on s.employee_id = e.employee_id
       where e.employee_id = $1
     )',
    v_schema_name,
    v_schema_name
  )
  into v_employee_exists
  using v_employee_id;

  if not v_employee_exists then
    return public.platform_json_response(false, 'EMPLOYEE_NOT_FOUND', 'Employee must exist in WCM_CORE before occupancy can be assigned.', jsonb_build_object('employee_id', v_employee_id));
  end if;

  execute format(
    'select exists (select 1 from %I.hierarchy_position where position_id = $1)',
    v_schema_name
  )
  into v_position_exists
  using v_position_id;

  if not v_position_exists then
    return public.platform_json_response(false, 'POSITION_NOT_FOUND', 'Position not found in tenant hierarchy.', jsonb_build_object('position_id', v_position_id));
  end if;

  if v_occupancy_id is not null then
    execute format(
      'select occupancy_id, employee_id, position_id, occupancy_role, effective_start_date, effective_end_date, occupancy_status, occupancy_reason
       from %I.hierarchy_position_occupancy
       where occupancy_id = $1',
      v_schema_name
    )
    into v_existing
    using v_occupancy_id;

    if v_existing.occupancy_id is null then
      return public.platform_json_response(false, 'OCCUPANCY_NOT_FOUND', 'Occupancy row not found.', jsonb_build_object('occupancy_id', v_occupancy_id));
    end if;
  else
    execute format(
      'select occupancy_id, employee_id, position_id, occupancy_role, effective_start_date, effective_end_date, occupancy_status, occupancy_reason
       from %I.hierarchy_position_occupancy
       where employee_id = $1
         and position_id = $2
         and occupancy_status = ''active''
         and effective_end_date is null
       order by occupancy_id desc
       limit 1',
      v_schema_name
    )
    into v_existing
    using v_employee_id, v_position_id;
  end if;

  if v_existing.occupancy_id is null and v_occupancy_status = 'active' then
    for v_close_record in execute format(
      'select occupancy_id, employee_id, position_id, occupancy_role, effective_start_date
       from %I.hierarchy_position_occupancy
       where employee_id = $1
         and occupancy_status = ''active''
         and effective_end_date is null
         and position_id <> $2
       for update',
      v_schema_name
    ) using v_employee_id, v_position_id loop
      execute format(
        'update %I.hierarchy_position_occupancy
         set effective_end_date = $1,
             occupancy_status = ''ended'',
             updated_at = timezone(''utc'', now())
         where occupancy_id = $2',
        v_schema_name
      )
      using greatest(v_close_record.effective_start_date, v_effective_start_date), v_close_record.occupancy_id;

      perform public.platform_hierarchy_log_occupancy_history_internal(
        v_schema_name,
        v_close_record.occupancy_id,
        v_close_record.employee_id,
        v_close_record.position_id,
        v_close_record.occupancy_role,
        'auto_closed',
        v_close_record.effective_start_date,
        greatest(v_close_record.effective_start_date, v_effective_start_date),
        'employee_reassigned_to_new_position',
        jsonb_build_object('new_position_id', v_position_id),
        v_actor_user_id
      );
    end loop;
  end if;

  if v_existing.occupancy_id is null then
    execute format(
      'insert into %I.hierarchy_position_occupancy (
         employee_id,
         position_id,
         occupancy_role,
         effective_start_date,
         effective_end_date,
         occupancy_status,
         occupancy_reason
       ) values ($1, $2, $3, $4, $5, $6, $7)
       returning occupancy_id',
      v_schema_name
    )
    into v_occupancy_id
    using v_employee_id, v_position_id, v_occupancy_role, v_effective_start_date, v_effective_end_date, v_occupancy_status, v_occupancy_reason;

    v_event_type := 'assigned';
  else
    execute format(
      'update %I.hierarchy_position_occupancy
       set employee_id = $1,
           position_id = $2,
           occupancy_role = $3,
           effective_start_date = $4,
           effective_end_date = $5,
           occupancy_status = $6,
           occupancy_reason = $7,
           updated_at = timezone(''utc'', now())
       where occupancy_id = $8',
      v_schema_name
    )
    using v_employee_id, v_position_id, v_occupancy_role, v_effective_start_date, v_effective_end_date, v_occupancy_status, v_occupancy_reason, v_existing.occupancy_id;

    v_occupancy_id := v_existing.occupancy_id;
    v_event_type := case when v_occupancy_status = 'active' then 'updated' else 'ended' end;
  end if;

  perform public.platform_hierarchy_log_occupancy_history_internal(
    v_schema_name,
    v_occupancy_id,
    v_employee_id,
    v_position_id,
    v_occupancy_role,
    v_event_type,
    v_effective_start_date,
    v_effective_end_date,
    v_occupancy_reason,
    v_event_details,
    v_actor_user_id
  );

  perform public.platform_hierarchy_sync_wcm_position_state(v_schema_name, v_employee_id);

  return public.platform_json_response(
    true,
    'OK',
    'Hierarchy occupancy upserted.',
    jsonb_build_object(
      'tenant_id', public.platform_try_uuid(v_context_details->>'tenant_id'),
      'occupancy_id', v_occupancy_id,
      'employee_id', v_employee_id,
      'position_id', v_position_id,
      'occupancy_role', v_occupancy_role,
      'occupancy_status', v_occupancy_status,
      'effective_start_date', v_effective_start_date,
      'effective_end_date', v_effective_end_date,
      'event_type', v_event_type
    )
  );
exception
  when unique_violation then
    return public.platform_json_response(
      false,
      'EMPLOYEE_ACTIVE_OCCUPANCY_EXISTS',
      'Employee already has an active open occupancy assignment.',
      jsonb_build_object('employee_id', v_employee_id)
    );
  when others then
    return public.platform_json_response(
      false,
      'UNEXPECTED_ERROR',
      'Unexpected error in platform_upsert_hierarchy_position_occupancy.',
      jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm)
    );
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_upsert_lms_policy_assignment(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context_result jsonb;
  v_schema_name text;
  v_policy_assignment_id uuid := public.platform_try_uuid(p_params->>'policy_assignment_id');
  v_leave_policy_id uuid := public.platform_try_uuid(p_params->>'leave_policy_id');
  v_leave_policy_code text := nullif(lower(btrim(coalesce(p_params->>'leave_policy_code', ''))), '');
  v_assignment_scope text := lower(coalesce(nullif(btrim(p_params->>'assignment_scope'), ''), 'all_employee'));
begin
  v_context_result := public.platform_lms_resolve_context(p_params);
  if coalesce((v_context_result->>'success')::boolean, false) is not true then return v_context_result; end if;
  v_schema_name := nullif(coalesce(v_context_result->'details'->>'tenant_schema', ''), '');

  if v_leave_policy_id is null and v_leave_policy_code is not null then
    execute format('select leave_policy_id from %I.lms_leave_policy where lower(leave_policy_code) = $1 limit 1', v_schema_name)
    into v_leave_policy_id
    using v_leave_policy_code;
  end if;

  if v_leave_policy_id is null then
    return public.platform_json_response(false,'LEAVE_POLICY_REQUIRED','leave_policy_id or leave_policy_code is required.','{}'::jsonb);
  end if;

  if v_assignment_scope = 'employee' and public.platform_try_uuid(p_params->>'employee_id') is null then
    return public.platform_json_response(false,'EMPLOYEE_ID_REQUIRED','employee_id is required for employee-scoped policy assignment.','{}'::jsonb);
  end if;

  if v_assignment_scope = 'position' and public.platform_hierarchy_try_bigint(p_params->>'position_id') is null then
    return public.platform_json_response(false,'POSITION_ID_REQUIRED','position_id is required for position-scoped policy assignment.','{}'::jsonb);
  end if;

  if v_policy_assignment_id is null then
    execute format('insert into %I.lms_policy_assignment (leave_policy_id, assignment_scope, employee_id, position_id, employment_status, service_state, assignment_priority, effective_from, effective_to, assignment_status, criteria) values ($1,$2,$3,$4,$5,$6,coalesce($7,100),$8,$9,coalesce($10,''active''),coalesce($11,''{}''::jsonb)) returning policy_assignment_id', v_schema_name)
    into v_policy_assignment_id
    using v_leave_policy_id, v_assignment_scope, public.platform_try_uuid(p_params->>'employee_id'), public.platform_hierarchy_try_bigint(p_params->>'position_id'), nullif(lower(btrim(coalesce(p_params->>'employment_status', ''))), ''), nullif(lower(btrim(coalesce(p_params->>'service_state', ''))), ''), case when p_params ? 'assignment_priority' then (p_params->>'assignment_priority')::integer else null end, public.platform_lms_try_date(p_params->>'effective_from'), public.platform_lms_try_date(p_params->>'effective_to'), p_params->>'assignment_status', p_params->'criteria';
  else
    execute format('update %I.lms_policy_assignment set leave_policy_id = $1, assignment_scope = $2, employee_id = $3, position_id = $4, employment_status = $5, service_state = $6, assignment_priority = coalesce($7, assignment_priority), effective_from = $8, effective_to = $9, assignment_status = coalesce($10, assignment_status), criteria = coalesce($11, criteria), updated_at = timezone(''utc'', now()) where policy_assignment_id = $12', v_schema_name)
    using v_leave_policy_id, v_assignment_scope, public.platform_try_uuid(p_params->>'employee_id'), public.platform_hierarchy_try_bigint(p_params->>'position_id'), nullif(lower(btrim(coalesce(p_params->>'employment_status', ''))), ''), nullif(lower(btrim(coalesce(p_params->>'service_state', ''))), ''), case when p_params ? 'assignment_priority' then (p_params->>'assignment_priority')::integer else null end, public.platform_lms_try_date(p_params->>'effective_from'), public.platform_lms_try_date(p_params->>'effective_to'), p_params->>'assignment_status', p_params->'criteria', v_policy_assignment_id;
  end if;

  return public.platform_json_response(true,'OK','LMS policy assignment recorded.',jsonb_build_object('policy_assignment_id', v_policy_assignment_id,'leave_policy_id', v_leave_policy_id,'assignment_scope', v_assignment_scope));
exception
  when others then
    return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_upsert_lms_policy_assignment.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_validate_ams_bio_publish_readiness(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context jsonb := public.platform_ams_bio_resolve_context(p_params);
  v_schema_name text;
  v_normalized_punch_id uuid := public.platform_try_uuid(p_params->>'normalized_punch_id');
  v_row record;
begin
  if coalesce((v_context->>'success')::boolean, false) is not true then return v_context; end if;
  v_schema_name := v_context->'details'->>'tenant_schema';
  if v_normalized_punch_id is null then return public.platform_json_response(false,'NORMALIZED_PUNCH_ID_REQUIRED','normalized_punch_id is required.','{}'::jsonb); end if;

  execute format('select normalized_punch_id, employee_id, attendance_date, normalization_status from %I.ams_bio_normalized_punch where normalized_punch_id = $1', v_schema_name)
  into v_row using v_normalized_punch_id;

  if v_row.normalized_punch_id is null then return public.platform_json_response(false,'NORMALIZED_PUNCH_NOT_FOUND','Normalized punch not found.',jsonb_build_object('normalized_punch_id', v_normalized_punch_id)); end if;
  if v_row.normalization_status not in ('ready_to_publish','published') then return public.platform_json_response(false,'PUBLISH_NOT_READY','Normalized punch is not ready to publish.',jsonb_build_object('normalization_status', v_row.normalization_status)); end if;
  if public.platform_ams_bio_active_employee_anchor_exists(v_schema_name, v_row.employee_id, v_row.attendance_date) is not true then return public.platform_json_response(false,'EMPLOYEE_NOT_ACTIVE','Employee anchor is not active for publish.',jsonb_build_object('employee_id', v_row.employee_id,'attendance_date', v_row.attendance_date)); end if;

  return public.platform_json_response(true,'OK','BIO normalized punch is ready for publish.',jsonb_build_object('normalized_punch_id', v_row.normalized_punch_id,'employee_id', v_row.employee_id,'attendance_date', v_row.attendance_date));
exception when others then
  return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_validate_ams_bio_publish_readiness.',jsonb_build_object('sqlstate', sqlstate, 'sqlerrm', sqlerrm));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_assign_employee_fbp_policy(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context jsonb := public.platform_fbp_resolve_context(p_params);
  v_schema_name text;
  v_actor_user_id uuid;
  v_employee_id uuid := public.platform_try_uuid(p_params->>'employee_id');
  v_policy_id uuid := public.platform_try_uuid(p_params->>'policy_id');
  v_policy_code text := nullif(lower(btrim(coalesce(p_params->>'policy_code', ''))), '');
  v_financial_year text := coalesce(nullif(btrim(p_params->>'financial_year'), ''), public.platform_fbp_financial_year(public.platform_fbp_try_date(p_params->>'effective_start_date')));
  v_elected_tax_regime text := upper(coalesce(nullif(btrim(p_params->>'elected_tax_regime'), ''), 'OLD'));
  v_effective_start_date date := coalesce(public.platform_fbp_try_date(p_params->>'effective_start_date'), current_date);
  v_effective_end_date date := public.platform_fbp_try_date(p_params->>'effective_end_date');
  v_total_allocated_amount numeric := public.platform_fbp_try_numeric(p_params->>'total_allocated_amount');
  v_assignment_metadata jsonb := coalesce(p_params->'assignment_metadata', '{}'::jsonb);
  v_existing_assignment_id uuid;
  v_assignment_id uuid;
begin
  if coalesce((v_context->>'success')::boolean, false) is not true then return v_context; end if;
  v_schema_name := v_context->'details'->>'tenant_schema';
  v_actor_user_id := coalesce(public.platform_try_uuid(p_params->>'actor_user_id'), public.platform_try_uuid(v_context->'details'->>'actor_user_id'));
  if jsonb_typeof(v_assignment_metadata) <> 'object' then return public.platform_json_response(false,'ASSIGNMENT_METADATA_INVALID','assignment_metadata must be a JSON object.', '{}'::jsonb); end if;
  if v_employee_id is null then return public.platform_json_response(false,'EMPLOYEE_ID_REQUIRED','employee_id is required.', '{}'::jsonb); end if;
  if v_policy_id is null and v_policy_code is not null then execute format('select policy_id, total_annual_limit from %I.wcm_fbp_policy where lower(policy_code) = $1 and policy_status in (''DRAFT'',''ACTIVE'')', v_schema_name) into v_policy_id, v_total_allocated_amount using v_policy_code; end if;
  if v_policy_id is null then return public.platform_json_response(false,'POLICY_ID_REQUIRED','policy_id or policy_code is required.', '{}'::jsonb); end if;
  if v_total_allocated_amount is null then execute format('select total_annual_limit from %I.wcm_fbp_policy where policy_id = $1', v_schema_name) into v_total_allocated_amount using v_policy_id; end if;

  execute format('select employee_assignment_id from %I.wcm_fbp_employee_assignment where employee_id = $1 and financial_year = $2 and effective_start_date = $3 order by created_at desc, employee_assignment_id desc limit 1', v_schema_name)
    into v_existing_assignment_id using v_employee_id, v_financial_year, v_effective_start_date;

  if v_existing_assignment_id is not null then
    execute format('update %I.wcm_fbp_employee_assignment set policy_id = $2, elected_tax_regime = $3, total_allocated_amount = $4, effective_end_date = $5, assignment_status = ''ACTIVE'', assignment_metadata = $6, created_by_actor_user_id = coalesce($7, created_by_actor_user_id), updated_at = timezone(''utc'', now()) where employee_assignment_id = $1 returning employee_assignment_id', v_schema_name)
      into v_assignment_id using v_existing_assignment_id, v_policy_id, v_elected_tax_regime, coalesce(v_total_allocated_amount, 0), v_effective_end_date, v_assignment_metadata, v_actor_user_id;
  else
    execute format('update %I.wcm_fbp_employee_assignment set assignment_status = ''SUPERSEDED'', effective_end_date = case when effective_start_date >= $2 then effective_start_date else least(coalesce(effective_end_date, $2 - 1), $2 - 1) end, updated_at = timezone(''utc'', now()) where employee_id = $1 and financial_year = $3 and assignment_status = ''ACTIVE''', v_schema_name)
      using v_employee_id, v_effective_start_date, v_financial_year;

    execute format('insert into %I.wcm_fbp_employee_assignment (employee_id, policy_id, financial_year, elected_tax_regime, total_allocated_amount, effective_start_date, effective_end_date, assignment_status, assignment_metadata, created_by_actor_user_id) values ($1,$2,$3,$4,$5,$6,$7,''ACTIVE'',$8,$9) returning employee_assignment_id', v_schema_name)
      into v_assignment_id using v_employee_id, v_policy_id, v_financial_year, v_elected_tax_regime, coalesce(v_total_allocated_amount, 0), v_effective_start_date, v_effective_end_date, v_assignment_metadata, v_actor_user_id;
  end if;

  perform public.platform_fbp_append_audit(v_schema_name,'FBP_EMPLOYEE_ASSIGNMENT_UPSERTED','FBP',jsonb_build_object('employee_assignment_id', v_assignment_id,'employee_id', v_employee_id,'financial_year', v_financial_year),null,v_policy_id,v_assignment_id,null,null,null,v_actor_user_id);
  return public.platform_json_response(true,'OK','Employee FBP policy assigned.',jsonb_build_object('employee_assignment_id', v_assignment_id,'employee_id', v_employee_id,'policy_id', v_policy_id,'financial_year', v_financial_year));
exception when others then
  return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_assign_employee_fbp_policy.',jsonb_build_object('sqlstate', sqlstate,'sqlerrm', sqlerrm));
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_fbp_employee_dashboard_rows()
 RETURNS TABLE(tenant_id uuid, employee_id uuid, employee_code text, employee_name text, financial_year text, employee_assignment_id uuid, policy_code text, elected_tax_regime text, total_allocated_amount numeric, total_declared_amount numeric, total_utilized_amount numeric, total_pending_reimbursement_amount numeric, total_balance_amount numeric, latest_declaration_status text, updated_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context jsonb := public.platform_fbp_resolve_context('{}'::jsonb);
  v_schema_name text;
  v_tenant_id uuid;
begin
  if coalesce((v_context->>'success')::boolean, false) is not true then return; end if;
  v_schema_name := v_context->'details'->>'tenant_schema';
  v_tenant_id := public.platform_try_uuid(v_context->'details'->>'tenant_id');
  return query execute format(
    'select $1::uuid,
            ea.employee_id,
            e.employee_code,
            trim(concat(coalesce(e.first_name, ''''), '' '', coalesce(e.last_name, ''''))),
            ea.financial_year,
            ea.employee_assignment_id,
            p.policy_code,
            ea.elected_tax_regime,
            ea.total_allocated_amount,
            coalesce(d.total_declared_amount, 0),
            coalesce(sum(di.utilized_amount), 0),
            coalesce(sum(di.pending_reimbursement_amount), 0),
            coalesce(sum(di.balance_amount), 0),
            d.declaration_status,
            greatest(ea.updated_at, coalesce(d.updated_at, ea.updated_at))
       from %I.wcm_fbp_employee_assignment ea
       join %I.wcm_employee e on e.employee_id = ea.employee_id
       join %I.wcm_fbp_policy p on p.policy_id = ea.policy_id
       left join lateral (
         select d1.declaration_id, d1.total_declared_amount, d1.declaration_status, d1.updated_at
           from %I.wcm_fbp_declaration d1
          where d1.employee_assignment_id = ea.employee_assignment_id
          order by d1.created_at desc, d1.declaration_id desc
          limit 1
       ) d on true
       left join %I.wcm_fbp_declaration_item di on di.declaration_id = d.declaration_id
      group by ea.employee_assignment_id, e.employee_code, e.first_name, e.last_name, p.policy_code, d.declaration_id, d.total_declared_amount, d.declaration_status, d.updated_at
      order by ea.financial_year desc, e.employee_code',
    v_schema_name, v_schema_name, v_schema_name, v_schema_name, v_schema_name
  ) using v_tenant_id;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_fbp_sync_to_payroll_internal(p_schema_name text, p_declaration_id uuid, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_employee_id uuid;
  v_assignment_id uuid;
  v_synced_count integer := 0;
  v_override_value jsonb;
  r_item record;
begin
  execute format(
    'select employee_id from %I.wcm_fbp_declaration where declaration_id = $1 and declaration_status = ''APPROVED''',
    p_schema_name
  ) into v_employee_id using p_declaration_id;

  if v_employee_id is null then
    raise exception 'Approved declaration % not found for FBP payroll sync.', p_declaration_id;
  end if;

  execute format(
    'select employee_pay_structure_assignment_id from %I.wcm_employee_pay_structure_assignment where employee_id = $1 and assignment_status = ''ACTIVE'' and effective_from <= current_date and (effective_to is null or effective_to >= current_date) order by effective_from desc, created_at desc limit 1',
    p_schema_name
  ) into v_assignment_id using v_employee_id;

  if v_assignment_id is null then
    raise exception 'No active payroll assignment found for employee %.', v_employee_id;
  end if;

  for r_item in execute format(
    'select di.declaration_item_id, di.declared_monthly_amount, b.benefit_code from %I.wcm_fbp_declaration_item di join %I.wcm_fbp_benefit b on b.benefit_id = di.benefit_id where di.declaration_id = $1 and di.item_status = ''ACTIVE'' and di.linked_component_id is not null',
    p_schema_name, p_schema_name
  ) using p_declaration_id loop
    v_override_value := jsonb_build_object(
      'calculation', jsonb_build_object('method', 'FLAT_AMOUNT', 'value', r_item.declared_monthly_amount),
      'declaration_item_id', r_item.declaration_item_id,
      'synced_at', timezone('utc', now())
    );

    execute format(
      'update %I.wcm_employee_pay_structure_assignment
          set override_inputs = jsonb_set(
                coalesce(override_inputs,''{}''::jsonb),
                array[''fbp''],
                jsonb_set(
                  coalesce(coalesce(override_inputs,''{}''::jsonb)->''fbp'',''{}''::jsonb),
                  array[$2],
                  $3,
                  true
                ),
                true
              ),
              updated_at = timezone(''utc'', now())
        where employee_pay_structure_assignment_id = $1',
      p_schema_name
    ) using v_assignment_id, lower(r_item.benefit_code), v_override_value;

    v_synced_count := v_synced_count + 1;
  end loop;

  perform public.platform_fbp_append_audit(p_schema_name,'FBP_SYNCED_TO_PAYROLL','FBP',jsonb_build_object('declaration_id', p_declaration_id,'employee_id', v_employee_id,'synced_components', v_synced_count),null,null,null,p_declaration_id,null,null,p_actor_user_id);
  return v_synced_count;
end;
$function$
;

CREATE OR REPLACE FUNCTION public.platform_process_lwf_batch_job(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_context jsonb := public.platform_lwf_resolve_context(p_params);
  v_schema_name text;
  v_tenant_id uuid;
  v_actor_user_id uuid := coalesce(public.platform_try_uuid(p_params->>'actor_user_id'), public.platform_current_actor_user_id());
  v_batch_id bigint := nullif(p_params->>'batch_id', '')::bigint;
  v_batch record;
  v_employee_id uuid;
  v_requested_count integer := 0;
  v_processed_count integer := 0;
  v_synced_count integer := 0;
  v_error_count integer := 0;
  v_calc_result jsonb;
  v_details jsonb;
  v_ledger_id uuid;
  v_sync_result jsonb;
  v_final_employee numeric;
  v_final_employer numeric;
begin
  if coalesce((v_context->>'success')::boolean, false) is not true then return v_context; end if;
  if v_batch_id is null then return public.platform_json_response(false,'BATCH_ID_REQUIRED','batch_id is required.','{}'::jsonb); end if;
  v_schema_name := v_context->'details'->>'tenant_schema';
  v_tenant_id := public.platform_try_uuid(v_context->'details'->>'tenant_id');

  execute format('select * from %I.wcm_lwf_processing_batch where batch_id = $1', v_schema_name) into v_batch using v_batch_id;
  if v_batch.batch_id is null then
    return public.platform_json_response(false,'BATCH_NOT_FOUND','LWF batch was not found.',jsonb_build_object('batch_id', v_batch_id));
  end if;
  if v_batch.batch_status not in ('REQUESTED','FAILED') then
    return public.platform_json_response(false,'BATCH_NOT_PROCESSABLE','Only REQUESTED or FAILED batches can be processed.',jsonb_build_object('batch_id', v_batch_id, 'batch_status', v_batch.batch_status));
  end if;

  execute format('update %I.wcm_lwf_processing_batch set batch_status = ''PROCESSING'', process_started_at = timezone(''utc'', now()), process_completed_at = null, error_payload = ''{}''::jsonb, updated_at = timezone(''utc'', now()) where batch_id = $1', v_schema_name)
    using v_batch_id;

  if jsonb_array_length(coalesce(v_batch.requested_employee_ids, '[]'::jsonb)) > 0 then
    for v_employee_id in
      select public.platform_try_uuid(value)
      from jsonb_array_elements_text(v_batch.requested_employee_ids)
    loop
      continue when v_employee_id is null;
      v_requested_count := v_requested_count + 1;
      v_calc_result := public.platform_lwf_calculate_contribution_internal(v_schema_name, v_employee_id, v_batch.payroll_period, v_batch.batch_source = 'FNF', v_batch.source_batch_id);
      if coalesce((v_calc_result->>'success')::boolean, false) is not true then
        v_error_count := v_error_count + 1;
        execute format(
          'insert into %I.wcm_lwf_dead_letter_entry (batch_id, employee_id, error_code, error_message, payload)
           values ($1,$2,$3,$4,$5)',
          v_schema_name
        ) using v_batch_id, v_employee_id, coalesce(v_calc_result->>'code', 'CALCULATION_FAILED'), coalesce(v_calc_result->>'message', 'LWF calculation failed.'), coalesce(v_calc_result->'details', '{}'::jsonb);
        continue;
      end if;

      v_details := coalesce(v_calc_result->'details', '{}'::jsonb);
      if coalesce(v_details->>'state_code', '') <> v_batch.state_code then
        v_error_count := v_error_count + 1;
        execute format(
          'insert into %I.wcm_lwf_dead_letter_entry (batch_id, employee_id, error_code, error_message, payload)
           values ($1,$2,''STATE_MISMATCH'',''Resolved state did not match the requested batch state.'',$3)',
          v_schema_name
        ) using v_batch_id, v_employee_id, v_details;
        continue;
      end if;

      execute format(
        'insert into %I.wcm_lwf_period_ledger (
           batch_id, employee_id, payroll_period, state_code, eligible_wages,
           system_employee_contribution, system_employer_contribution,
           final_employee_contribution, final_employer_contribution,
           override_status, sync_status, calculation_payload, sync_payload, ledger_metadata
         ) values (
           $1,$2,$3,$4,$5,$6,$7,$6,$7,''NONE'',''PENDING'',$8,''{}''::jsonb,jsonb_build_object(''batch_source'', $9))
         on conflict (employee_id, payroll_period, batch_id) do update
           set state_code = excluded.state_code,
               eligible_wages = excluded.eligible_wages,
               system_employee_contribution = excluded.system_employee_contribution,
               system_employer_contribution = excluded.system_employer_contribution,
               final_employee_contribution = case when %I.wcm_lwf_period_ledger.override_status = ''MANUAL'' then %I.wcm_lwf_period_ledger.final_employee_contribution else excluded.final_employee_contribution end,
               final_employer_contribution = case when %I.wcm_lwf_period_ledger.override_status = ''MANUAL'' then %I.wcm_lwf_period_ledger.final_employer_contribution else excluded.final_employer_contribution end,
               calculation_payload = excluded.calculation_payload,
               ledger_metadata = excluded.ledger_metadata,
               updated_at = timezone(''utc'', now())
         returning contribution_ledger_id, final_employee_contribution, final_employer_contribution',
        v_schema_name, v_schema_name, v_schema_name, v_schema_name, v_schema_name
      ) into v_ledger_id, v_final_employee, v_final_employer using
        v_batch_id,
        v_employee_id,
        v_batch.payroll_period,
        v_batch.state_code,
        round(coalesce(public.platform_lwf_try_numeric(v_details->>'eligible_wages'), 0), 2),
        round(coalesce(public.platform_lwf_try_numeric(v_details->>'employee_contribution'), 0), 2),
        round(coalesce(public.platform_lwf_try_numeric(v_details->>'employer_contribution'), 0), 2),
        v_details,
        v_batch.batch_source;

      v_sync_result := public.platform_lwf_sync_to_payroll_internal(v_schema_name, v_tenant_id, v_employee_id, v_batch.payroll_period, v_batch_id, v_ledger_id::text, v_final_employee, v_final_employer);
      if coalesce((v_sync_result->>'success')::boolean, false) is not true then
        v_error_count := v_error_count + 1;
        execute format(
          'update %I.wcm_lwf_period_ledger
              set sync_status = ''ERROR'',
                  sync_payload = $2,
                  updated_at = timezone(''utc'', now())
            where contribution_ledger_id = $1',
          v_schema_name
        ) using v_ledger_id, coalesce(v_sync_result->'details', '{}'::jsonb);
        execute format(
          'insert into %I.wcm_lwf_dead_letter_entry (batch_id, employee_id, error_code, error_message, payload)
           values ($1,$2,''PAYROLL_SYNC_FAILED'',''LWF payroll sync failed.'',$3)',
          v_schema_name
        ) using v_batch_id, v_employee_id, coalesce(v_sync_result->'details', '{}'::jsonb);
        continue;
      end if;

      execute format(
        'update %I.wcm_lwf_period_ledger
            set sync_status = ''SYNCED'',
                sync_payload = $2,
                updated_at = timezone(''utc'', now())
          where contribution_ledger_id = $1',
        v_schema_name
      ) using v_ledger_id, coalesce(v_sync_result->'details', '{}'::jsonb);

      v_processed_count := v_processed_count + 1;
      v_synced_count := v_synced_count + 1;
    end loop;
  end if;

  execute format(
    'update %I.wcm_lwf_processing_batch
        set batch_status = $2,
            process_completed_at = timezone(''utc'', now()),
            summary_payload = jsonb_build_object(''requested_count'', $3, ''processed_count'', $4, ''synced_count'', $5, ''error_count'', $6),
            error_payload = case when $6 > 0 then jsonb_build_object(''error_count'', $6) else ''{}''::jsonb end,
            updated_at = timezone(''utc'', now())
      where batch_id = $1',
    v_schema_name
  ) using v_batch_id, case when v_error_count > 0 then 'FAILED' else 'SYNCED' end, v_requested_count, v_processed_count, v_synced_count, v_error_count;

  perform public.platform_refresh_lwf_compliance_summary_internal(v_schema_name, v_batch.payroll_period, v_batch.state_code);
  perform public.platform_lwf_append_audit(v_schema_name, 'BATCH_PROCESSED', case when v_error_count > 0 then 'PARTIAL_FAILURE' else 'SUCCESS' end, 'wcm_lwf_processing_batch', v_batch_id::text, jsonb_build_object('requested_count', v_requested_count, 'processed_count', v_processed_count, 'synced_count', v_synced_count, 'error_count', v_error_count), v_actor_user_id, null, v_batch_id);

  return public.platform_json_response(true,'OK','LWF batch processed.',jsonb_build_object('batch_id', v_batch_id, 'processed_count', v_processed_count, 'synced_count', v_synced_count, 'error_count', v_error_count, 'batch_status', case when v_error_count > 0 then 'FAILED' else 'SYNCED' end));
exception when others then
  return public.platform_json_response(false,'UNEXPECTED_ERROR','Unexpected error in platform_process_lwf_batch_job.',jsonb_build_object('sqlstate', sqlstate,'sqlerrm', sqlerrm,'batch_id', v_batch_id));
end;
$function$
;

create or replace view "public"."platform_rm_hierarchy_org_chart" as  SELECT p.tenant_id,
    p.position_id,
    p.position_code,
    p.position_name,
    p.position_group_id,
    p.position_group_code,
    p.position_group_name,
    p.reporting_position_id,
    p.hierarchy_path,
    p.hierarchy_level,
    p.position_status,
    p.active_occupancy_count,
    p.direct_report_count,
    o.employee_id AS operational_employee_id,
    o.employee_code AS operational_employee_code,
    o.actor_user_id AS operational_actor_user_id,
    o.employee_name AS operational_employee_name,
    o.occupancy_role AS operational_occupancy_role,
    o.overlap_count
   FROM (public.platform_rm_hierarchy_position_catalog p
     LEFT JOIN public.platform_rm_hierarchy_operational_occupancy o ON (((o.position_id = p.position_id) AND o.is_operational_occupant)));


